public fun selectWebGpuBlendPlan(mode: SkBlendMode): BlendPlan = when (mode) {
    in FIXED_FUNCTION_BLEND_MODES -> BlendPlan(
        mode = mode,
        kind = BlendPlan.Kind.FixedFunction,
        reason = "fixed-function WebGPU blend allowlist accepts $mode",
    )

    in DRAW_SHADER_LAYER_COMPOSITE_BLEND_MODES -> BlendPlan(
        mode = mode,
        kind = BlendPlan.Kind.ShaderLayerComposite,
        reason = "blend mode $mode requires shader/layer composite BlendPlan; " +
            "fixed-function WebGPU path refuses it",
    )

    else -> BlendPlan(
        mode = mode,
        kind = BlendPlan.Kind.RefuseDiagnostic,
        reason = "blend mode $mode is not in the M7 WebGPU BlendPlan allowlist. " +
            "Fixed-function modes: $fixedFunctionBlendModeNames. " +
            "Shader layer-composite modes: $drawShaderLayerCompositeBlendModeNames. " +
            "Other modes need additional shader work and are deferred.",
    )
}

public fun selectLayerCompositeBlendPlan(mode: SkBlendMode): BlendPlan = when {
    mode in LAYER_SHADER_COMPOSITE_BLEND_MODES -> BlendPlan(
        mode = mode,
        kind = BlendPlan.Kind.ShaderLayerComposite,
        reason = "blend mode $mode requires shader/layer composite BlendPlan for saveLayer composition",
    )

    mode in FIXED_FUNCTION_BLEND_MODES -> BlendPlan(
        mode = mode,
        kind = BlendPlan.Kind.FixedFunction,
        reason = "fixed-function layer composite blend allowlist accepts $mode",
    )

    else -> BlendPlan(
        mode = mode,
        kind = BlendPlan.Kind.RefuseDiagnostic,
        reason = "blend mode $mode is not in the M7 layer composite BlendPlan allowlist. " +
            "Fixed-function modes: $layerFixedFunctionBlendModeNames. " +
            "Shader layer-composite modes: $layerShaderCompositeBlendModeNames. " +
            "Other modes need additional shader work and are deferred.",
    )
}

/**
 * G1.2 — first GPU-backed [SkDevice] implementation, built on wgpu4k.
 *
 * **Scope.** Only `drawRect` with axis-aligned, fill-style, opaque-color,
 * non-AA paint is supported. The other three [SkDevice] methods stub out
 * with `TODO("G2+")`. This is enough to ratchet the SkDevice abstraction
 * through SkCanvas onto a non-raster backend and to feed the first
 * rect-fill cross-test (`RectFillCrossTest`).
 *
 * **How it works.**
 *  - The constructor allocates a [HeadlessTarget] (color texture +
 *    staging buffer) sized to `width`/`height`, compiles
 *    `shaders/solid_color.wgsl`, and builds a single `RGBA8Unorm` +
 *    SrcOver render pipeline that reads its fragment color from a
 *    `uniform Uniforms { color: vec4f }` binding.
 *  - Each [drawRect] applies SkBitmapDevice's non-AA pixel-edge rounding
 *    (`floor(coord + 0.5)`) to derive an integer scissor rect, intersects
 *    it with the user's clip and the viewport, and buffers the draw in
 *    [pending]. Nothing is sent to the GPU until [flush].
 *  - [flush] replays the buffered draws: one render pass per draw, each
 *    with its own uniform buffer + bind group. The first pass clears to
 *    [background], later passes use `GPULoadOp.Load`. After all draws,
 *    `copyTextureToBuffer` stages the texture and `mapAsync` reads the
 *    pixels back to the JVM heap as a tightly-packed RGBA byte array.
 *
 * **Why one render pass per draw, not one accumulating pass?** WebGPU
 * does not let us call `queue.writeBuffer` between draws of a single
 * render pass (the writes must happen outside the encoder). Per-draw
 * render passes are the simplest correct workaround; per-draw bind
 * groups + dynamic-offset are an optimisation for G2+.
 *
 * **GLFW main-thread caveat.** [WebGpuContext.createOrNull] still
 * bootstraps a hidden GLFW window for the [io.ygdrasil.webgpu.NativeSurface];
 * tests run under `-XstartOnFirstThread` (configured in
 * `gpu-raster/build.gradle.kts`). The device itself never touches GLFW
 * after the context is built.
 */
public class SkWebGpuDevice(
    private val context: WebGpuContext,
    override val width: Int,
    override val height: Int,
    /**
     * G6.1 — when `true`, the final present pass applies the
     * sRGB → linear → Rec.2020 → encoded transform so readback bytes
     * are in `DM_REFERENCE_COLOR_SPACE` (cross-test convention).
     * When `false`, the present pass is an identity copy — readback
     * bytes stay in raw sRGB primaries (what unit tests expect).
     * `WebGpuSink` (cross-tests) flips this to `true` ; everything
     * else stays on the raw sRGB default.
     */
    private val applyColorspaceTransform: Boolean = false,
    /**
     * FOR-232 bounded target-colorspace blend pilot. When enabled, the
     * supported solid-colour coverage shaders convert unpremul sRGB source
     * colours to the DM Rec.2020 encoded target before premultiplication and
     * fixed-function blending. The final present pass is then an identity
     * copy because the intermediate is already in the comparison colour
     * space.
     *
     * This is intentionally narrow. Until every draw family used by a scene
     * has an audited target-space path, unsupported draw kinds refuse with a
     * stable diagnostic instead of silently mixing colour conventions.
     */
    private val targetColorSpaceBlend: Boolean = false,
    /**
     * FOR-237 diagnostic-only runtime-effect path. This lets focused evidence
     * tests render known, parser-validated WGSL candidates without exposing
     * them as supported WebGPU runtime effects.
     */
    internal val allowUnpromotedRuntimeEffectsForDiagnostics: Boolean = false,
    /**
     * G6.2 — backing format of the intermediate render target. All draw
     * pipelines target this format. Default `RGBA16Float` (F16) buys
     * sub-byte precision on intermediate blends, gradient stop lerps,
     * and future image filters. Callers on drivers that don't support
     * F16 blending (or memory-constrained backends) can pass
     * `RGBA8Unorm` to fall back to the G6.1 behaviour. The final
     * readback target stays `RGBA8Unorm` regardless ; this only
     * affects the intermediate.
     */
    private val intermediateFormat: GPUTextureFormat = GPUTextureFormat.RGBA16Float,
) : SkDevice, AutoCloseable {
    public enum class PipelineKeyAxisClass {
        Layout,
        Code,
        PipelineState,
        UniformOnly,
    }

    public data class PipelineKeyClassification(
        val axis: String,
        val axisClass: PipelineKeyAxisClass,
        val value: String,
    )

    public data class GpuCacheTelemetrySnapshot(
        val shaderModuleCacheHits: Int,
        val shaderModuleCacheMisses: Int,
        val pipelineCacheHits: Int,
        val pipelineCacheMisses: Int,
        val resourceCacheHits: Int,
        val resourceCacheMisses: Int,
        val pipelineCreations: Int,
        val shaderModuleCount: Int,
        val pipelineCacheEntryCount: Int,
        val resourceCacheEntryCount: Int,
    )

    public data class RawColorSentinelSnapshot(
        val propertyName: String,
        val enabled: Boolean,
        val rectUniformColorWrites: List<RawRectUniformColorWrite>,
        val rgba8TextureUploads: List<RawRgba8TextureUpload>,
    )

    public data class OutputReadbackBoundarySnapshot(
        val propertyName: String,
        val enabled: Boolean,
        val width: Int,
        val height: Int,
        val samples: List<OutputReadbackSample>,
    )

    public data class OutputReadbackSample(
        val x: Int,
        val y: Int,
        val rgba: IntArray,
    )

    public data class For258ShaderSideProbeSnapshot(
        val propertyName: String,
        val enabled: Boolean,
        val diagnosticShader: String,
        val pipelineLayout: String,
        val samples: List<For258ShaderSideProbeSample>,
    )

    public data class For258ShaderSideProbeSample(
        val name: String,
        val x: Int,
        val y: Int,
        val observedRgbaFloat: FloatArray,
        val observedRgba8: IntArray,
        val valid: Boolean,
    )

    public data class M60F16FragmentLaneDiagnosticSnapshot(
        val propertyName: String,
