    private suspend fun recordM60F16AaStencilCoverPredrawDstReadbacks() {
        if (!m60F16AaStencilCoverPredrawDstReadbackDiagnosticsEnabled) return
        val readbacks = m60F16AaStencilCoverPredrawDstPendingReadbacks.toList()
        m60F16AaStencilCoverPredrawDstPendingReadbacks.clear()
        readbacks.forEach { readback ->
            val metadata = readback.metadata
            try {
                readback.staging.mapAsync(
                    GPUMapMode.Read,
                    0uL,
                    readback.bufferSize,
                ).getOrThrow()
                val bytes = readback.staging
                    .getMappedRange(0uL, readback.bufferSize)
                    .toByteArray()
                readback.staging.unmap()
                val buffer = ByteBuffer.wrap(bytes).order(ByteOrder.LITTLE_ENDIAN)
                val samples = M60_F16_DIRECT_PASS_WRITE_HOOK_POINTS.mapIndexed { index, (x, y) ->
                    val targetWithinScissor = m60F16PointWithinScissor(x, y, metadata.scissor)
                    val base = index * M60_F16_AA_STENCIL_COVER_POST_PASS_READBACK_SAMPLE_STRIDE_BYTES
                    val observed = FloatArray(4) { channel ->
                        buffer.getFloat(base + channel * Float.SIZE_BYTES)
                    }
                    val valid = targetWithinScissor && observed.all { value -> value >= 0f }
                    M60F16AaStencilCoverPredrawDstReadbackSample(
                        x = x,
                        y = y,
                        targetWithinScissor = targetWithinScissor,
                        readbackAttempted = true,
                        readbackAvailable = valid,
                        dstBeforeRgbaFloat = if (valid) observed else null,
                        dstBeforeRgba8 = if (valid) {
                            IntArray(4) { channel ->
                                ((observed[channel] * 255f) + 0.5f).toInt().coerceIn(0, 255)
                            }
                        } else {
                            null
                        },
                        classification = if (valid) {
                            "predraw-dst-observed"
                        } else if (targetWithinScissor) {
                            "predraw-dst-unavailable"
                        } else {
                            "predraw-dst-not-targeted-by-draw"
                        },
                        reason = if (valid) {
                            "FOR-410 compute diagnostic sampled the intermediate texture immediately before this StencilCoverAaPolygonDraw render pass."
                        } else if (targetWithinScissor) {
                            "The predraw compute diagnostic ran, but this coordinate did not produce an in-bounds destination sample for this draw."
                        } else {
                            "The coordinate is outside this StencilCoverAaPolygonDraw scissor, so this draw cannot provide the predraw destination for it."
                        },
                    )
                }
                m60F16AaStencilCoverPredrawDstReadbackEvents +=
                    m60F16PredrawDstReadbackEvent(
                        metadata = metadata,
                        copyAttempted = true,
                        copySucceeded = true,
                        copyFailureReason = null,
                        samples = samples,
                    )
            } catch (t: Throwable) {
                val samples = M60_F16_DIRECT_PASS_WRITE_HOOK_POINTS.map { (x, y) ->
                    val targetWithinScissor = m60F16PointWithinScissor(x, y, metadata.scissor)
                    M60F16AaStencilCoverPredrawDstReadbackSample(
                        x = x,
                        y = y,
                        targetWithinScissor = targetWithinScissor,
                        readbackAttempted = true,
                        readbackAvailable = false,
                        dstBeforeRgbaFloat = null,
                        dstBeforeRgba8 = null,
                        classification = if (targetWithinScissor) {
                            "predraw-dst-unavailable"
                        } else {
                            "predraw-dst-not-targeted-by-draw"
                        },
                        reason = "FOR-410 predraw compute/copy readback failed: ${t::class.simpleName}: ${t.message}",
                    )
                }
                m60F16AaStencilCoverPredrawDstReadbackEvents +=
                    m60F16PredrawDstReadbackEvent(
                        metadata = metadata,
                        copyAttempted = true,
                        copySucceeded = false,
                        copyFailureReason = "${t::class.simpleName}: ${t.message}",
                        samples = samples,
                    )
            }
        }
    }

