            },
            diagnostic = true,
            boundedRuntimeCorrection = false,
            contributionIsolationDiagnostic = true,
            runtimeIntegerLaneMaskProbeFor445Diagnostic =
                m60F16RuntimeIntegerLaneMaskProbeFor445DiagnosticsEnabled,
            widthQuantizedRenderFixFor431 = true,
        )

    // ─── Rect pipeline (G1.2 / G2.3a) — full-screen tri + scissor + coverage ───

    private val handwrittenRectShader: GPUShaderModule = loadShader("shaders/solid_color.wgsl")
    private val generatedSolidRectShaderKey: PipelineKey = pipelineKeyIdentity(
        listOf(
            PipelineKeyClassification("shaderFamily", classifyPipelineAxis("shaderFamily"), "solidRect"),
            PipelineKeyClassification("generatedPath", classifyPipelineAxis("generatedPath"), "true"),
        ),
    )
    private val generatedSolidRectShaderResult: Pair<GPUShaderModule?, String?> = run {
        val enabled = System.getProperty(GeneratedSolidRectWgsl.FEATURE_FLAG, "true").toBoolean()
        if (!enabled) {
            null to "generated solid rect disabled via -D${GeneratedSolidRectWgsl.FEATURE_FLAG}=false"
        } else {
            val source = GeneratedSolidRectWgsl.generateDeterministic()
            val validation = GeneratedSolidRectWgsl.validate(source)
            if (!validation.isSuccess) {
                null to "generated solid rect parse failure: ${validation.diagnostics.joinToString("; ")}"
            } else {
                generatedShaderModuleCache.getOrPut(generatedSolidRectShaderKey) {
                    context.device.createShaderModule(ShaderModuleDescriptor(code = source))
                } to null
            }
        }
    }
    private val generatedSolidRectShader: GPUShaderModule? = generatedSolidRectShaderResult.first
    private val generatedSolidRectInitFallbackReason: String? = generatedSolidRectShaderResult.second
    private var lastGeneratedSolidRectFallbackReason: String? = generatedSolidRectInitFallbackReason
    private var lastSolidRectPathForDiagnostics: String? = null
    private var lastCoverageSelectionForDiagnostics: WebGpuCoverageSelection? = null
    private var lastImageFilterRouteForDiagnostics: ImageFilterRouteDiagnostics? = null

    private val rectBindGroupLayout: GPUBindGroupLayout = context.device.createBindGroupLayout(
        BindGroupLayoutDescriptor(
            entries = listOf(
                BindGroupLayoutEntry(
                    binding = 0u,
                    visibility = GPUShaderStage.Fragment,
                    buffer = BufferBindingLayout(type = GPUBufferBindingType.Uniform),
                ),
            ),
        ),
    )

    private val rectPipelineLayout = context.device.createPipelineLayout(
        PipelineLayoutDescriptor(bindGroupLayouts = listOf(rectBindGroupLayout)),
    )

    /**
     * Lazily-populated rect-pipeline cache, one entry per [SkBlendMode]
     * the caller exercises. All entries share the same vertex / fragment
     * shader, same layout, same target format — only the [BlendState]
     * differs.
     */
    private val rectPipelineCache: MutableMap<SkBlendMode, GPURenderPipeline> = mutableMapOf()
    private val generatedRectPipelineCache: PipelineKeyedCache<GPURenderPipeline> =
        PipelineKeyedCache("generated solid rect pipelines")

    private fun rectPipelineFor(mode: SkBlendMode, useGenerated: Boolean): GPURenderPipeline {
        val pipelineKey = pipelineKeyIdentity(
            listOf(
                PipelineKeyClassification("blendMode", classifyPipelineAxis("blendMode"), mode.name),
                PipelineKeyClassification("generatedPath", classifyPipelineAxis("generatedPath"), useGenerated.toString()),
            ),
        )
        val shader = if (useGenerated) generatedSolidRectShader else handwrittenRectShader
        if (useGenerated && shader == null) {
            lastGeneratedSolidRectFallbackReason = generatedSolidRectInitFallbackReason ?: "generated solid rect unavailable"
            lastSolidRectPathForDiagnostics = "handwritten"
            val cached = rectPipelineCache[mode]
            if (cached != null) {
                cacheCounters.pipelineHits += 1
                return cached
            }
            cacheCounters.pipelineMisses += 1
            cacheCounters.pipelineCreations += 1
            return createRectPipeline(handwrittenRectShader, mode).also { rectPipelineCache[mode] = it }
        }
        if (useGenerated) {
            lastGeneratedSolidRectFallbackReason = null
            lastSolidRectPathForDiagnostics = "generated"
            val before = generatedRectPipelineCache.size
            return generatedRectPipelineCache.getOrPut(pipelineKey) {
                cacheCounters.pipelineMisses += 1
                cacheCounters.pipelineCreations += 1
                createRectPipeline(shader!!, mode)
            }.also {
                if (generatedRectPipelineCache.size == before) {
                    cacheCounters.pipelineHits += 1
                }
            }
        }
        lastSolidRectPathForDiagnostics = "handwritten"
        val cached = rectPipelineCache[mode]
        if (cached != null) {
            cacheCounters.pipelineHits += 1
            return cached
        }
        cacheCounters.pipelineMisses += 1
        cacheCounters.pipelineCreations += 1
        return createRectPipeline(handwrittenRectShader, mode).also { rectPipelineCache[mode] = it }
    }

    private fun createRectPipeline(shader: GPUShaderModule, mode: SkBlendMode): GPURenderPipeline =
        context.device.createRenderPipeline(
            RenderPipelineDescriptor(
                layout = rectPipelineLayout,
                vertex = VertexState(module = shader, entryPoint = "vs_main"),
                fragment = FragmentState(
                    module = shader,
                    entryPoint = "fs_main",
                    targets = listOf(
                        ColorTargetState(
                            format = intermediateFormat,
                            blend = blendStateFor(mode),
                        ),
                    ),
                ),
            ),
        )

    private val runtimeLinearGradientShader: GPUShaderModule = loadShader("shaders/runtime_linear_gradient_rt.wgsl")
    private val runtimeSimpleShader: GPUShaderModule = loadShader("shaders/runtime_simple_rt.wgsl")
    private val runtimeSpiralShader: GPUShaderModule = loadShader("shaders/runtime_spiral_rt.wgsl")
    private val runtimeEffectPipelineCache: MutableMap<Pair<String, SkBlendMode>, GPURenderPipeline> = mutableMapOf()
    private var lastRuntimeEffectFallbackReason: String? = null

    private fun runtimeEffectPipelineFor(wgslImplementationId: String, mode: SkBlendMode): GPURenderPipeline =
        runtimeEffectPipelineCache.getOrPut(wgslImplementationId to mode) {
            val shader = runtimeEffectShaderFor(wgslImplementationId)
            context.device.createRenderPipeline(
                RenderPipelineDescriptor(
                    layout = rectPipelineLayout,
                    vertex = VertexState(module = shader, entryPoint = "vs_main"),
                    fragment = FragmentState(
                        module = shader,
                        entryPoint = "fs_main",
                        targets = listOf(
                            ColorTargetState(
                                format = intermediateFormat,
                                blend = blendStateFor(mode),
                            ),
                        ),
                    ),
                ),
            )
        }

    private fun runtimeEffectShaderFor(wgslImplementationId: String): GPUShaderModule =
        when (wgslImplementationId) {
            "wgsl/runtime_linear_gradient_rt" -> runtimeLinearGradientShader
            "wgsl/runtime_simple_rt" -> runtimeSimpleShader
            "wgsl/runtime_spiral_rt" -> runtimeSpiralShader
            else -> error("Unsupported runtime-effect WGSL implementation: $wgslImplementationId")
        }

    internal fun runtimeEffectFallbackReasonForDiagnostics(): String? = lastRuntimeEffectFallbackReason

    private fun shouldUseGeneratedSolidRectPath(d: RectDraw): Boolean {
        val blendPlan = blendPlanFor(d.mode)
        if (d.mode != SkBlendMode.kSrcOver) {
            lastGeneratedSolidRectFallbackReason =
                "generated solid rect refuses ${d.mode}: expected kSrcOver fixed-function BlendPlan, got ${blendPlan.kind}"
            return false
        }
        if (d.clipKind != CLIP_KIND_NONE) {
            lastGeneratedSolidRectFallbackReason = "generated solid rect requires clipKind=none"
            return false
        }
        if (!d.colorFilterPacked.contentEquals(ZERO_COLOR_FILTER_24)) {
            lastGeneratedSolidRectFallbackReason = "generated solid rect does not support colorFilter"
            return false
        }
        val expectedRight = (d.x + d.w).toFloat()
        val expectedBottom = (d.y + d.h).toFloat()
        val isPixelAlignedFill = d.ol == d.x.toFloat() &&
            d.ot == d.y.toFloat() &&
            d.or == expectedRight &&
            d.ob == expectedBottom
        if (!isPixelAlignedFill) {
            lastGeneratedSolidRectFallbackReason = "generated solid rect currently supports only pixel-aligned fill bounds"
            return false
        }
        val isDegenerateInner = d.il > d.ir && d.it > d.ib
        if (!isDegenerateInner) {
            lastGeneratedSolidRectFallbackReason = "generated solid rect currently excludes stroke/hairline coverage path"
            return false
        }
        if (generatedSolidRectShader == null) return false
        return true
    }

    internal fun generatedSolidRectFallbackReasonForDiagnostics(): String? = lastGeneratedSolidRectFallbackReason

    internal fun solidRectMigrationDiagnosticsForTests(): SolidRectMigrationDiagnostics =
        SolidRectMigrationDiagnostics(
            shaderFamily = "Rect + SolidColor + SrcOver",
            selectedPath = lastSolidRectPathForDiagnostics,
            generatedDefaultAvailable = generatedSolidRectShader != null,
            retainedFallbackReason = lastGeneratedSolidRectFallbackReason,
            handwrittenRetirementCriteria =
                "Remove handwritten solid_color.wgsl fallback only after generated WGSL covers clips, " +
                    "color filters, stroke/hairline coverage, and non-SrcOver BlendPlans with green " +
                    "cross-backend tests and cache telemetry.",
        )

    internal fun coverageSelectionDiagnosticsForTests(): CoverageSelectionDiagnostics? =
        lastCoverageSelectionForDiagnostics?.let { selection ->
            CoverageSelectionDiagnostics(
                mode = if (selection.routeIdentifier == "webgpu.coverage.selector-disabled") "Rollback" else "Default",
                backend = org.skia.pipeline.BackendKind.GPU,
                drawKind = selection.drawKind,
                routeIdentifier = selection.routeIdentifier,
                strategy = selection.strategy,
                pipelineKeyDump = selection.pipelineKeyDump(),
                diagnosticDump = selection.diagnostic?.dump(),
                selectionDump = selection.dump(),
                productionDump = selection.toProductionRouteDiagnostics(cacheTelemetrySnapshot()).dump(),
            )
        }

    internal fun imageFilterRouteDiagnosticsForTests(): ImageFilterRouteDiagnostics? =
        lastImageFilterRouteForDiagnostics

    // ─── Polygon pipeline (G3.3a) — vertex buffer in device coords ─────────

    /** Shared vertex buffer layout for both the non-AA and AA polygon pipelines. */
    private val POLYGON_VERTEX_LAYOUT: VertexBufferLayout = VertexBufferLayout(
        arrayStride = 8uL, // 2 floats * 4 bytes
        attributes = listOf(
            VertexAttribute(
                shaderLocation = 0u,
                offset = 0uL,
                format = GPUVertexFormat.Float32x2,
            ),
        ),
    )

    private val polygonShader: GPUShaderModule = loadShader("shaders/solid_polygon.wgsl")

    private val polygonBindGroupLayout: GPUBindGroupLayout = context.device.createBindGroupLayout(
        BindGroupLayoutDescriptor(
            entries = listOf(
                // Same fragment-stage uniform layout as the rect pipeline plus
                // the viewport size used by the vertex stage's NDC remap
                // (visibility = Vertex | Fragment).
                BindGroupLayoutEntry(
                    binding = 0u,
                    visibility = GPUShaderStage.Vertex or GPUShaderStage.Fragment,
                    buffer = BufferBindingLayout(type = GPUBufferBindingType.Uniform),
                ),
            ),
        ),
    )

    private val polygonPipelineLayout = context.device.createPipelineLayout(
        PipelineLayoutDescriptor(bindGroupLayouts = listOf(polygonBindGroupLayout)),
    )

    /**
     * Polygon pipeline cache keyed by [SkBlendMode]. Same set of blends
     * as the rect pipeline ; the vertex shader is the differentiator.
     */
    private val polygonPipelineCache: MutableMap<SkBlendMode, GPURenderPipeline> = mutableMapOf()

    private fun polygonPipelineFor(mode: SkBlendMode): GPURenderPipeline =
        polygonPipelineCache.getOrPut(mode) {
            context.device.createRenderPipeline(
                RenderPipelineDescriptor(
                    layout = polygonPipelineLayout,
                    vertex = VertexState(
                        module = polygonShader,
                        entryPoint = "vs_main",
                        buffers = listOf(POLYGON_VERTEX_LAYOUT),
                    ),
                    fragment = FragmentState(
                        module = polygonShader,
                        entryPoint = "fs_main",
                        targets = listOf(
                            ColorTargetState(
                                format = intermediateFormat,
                                blend = blendStateFor(mode),
                            ),
                        ),
                    ),
                ),
            )
        }

    // ─── Stencil & cover (G3.3b.2b) — multi-contour / concave paths ────────

    /**
     * Stencil-write pipeline. Front-face triangles increment the stencil
     * byte (wrap on overflow), back-face triangles decrement. After
     * rendering all of a path's triangles, the stencil buffer carries
     * the **winding count** at each pixel. Color writes are masked off ;
     * the fragment stage runs but its output is discarded.
     */
    private val stencilWritePipeline: GPURenderPipeline = context.device.createRenderPipeline(
        RenderPipelineDescriptor(
            layout = polygonPipelineLayout,
            vertex = VertexState(
                module = polygonShader,
                entryPoint = "vs_main",
                buffers = listOf(POLYGON_VERTEX_LAYOUT),
            ),
            fragment = FragmentState(
                module = polygonShader,
                entryPoint = "fs_main",
                targets = listOf(
                    ColorTargetState(
                        format = intermediateFormat,
                        blend = blendAddBoth(GPUBlendFactor.One, GPUBlendFactor.Zero),
                        writeMask = GPUColorWrite.None,
                    ),
                ),
            ),
            depthStencil = DepthStencilState(
                format = GPUTextureFormat.Depth24PlusStencil8,
                depthWriteEnabled = false,
                depthCompare = GPUCompareFunction.Always,
                stencilFront = StencilFaceState(
                    compare = GPUCompareFunction.Always,
                    failOp = GPUStencilOperation.Keep,
                    depthFailOp = GPUStencilOperation.Keep,
                    passOp = GPUStencilOperation.IncrementWrap,
                ),
                stencilBack = StencilFaceState(
                    compare = GPUCompareFunction.Always,
                    failOp = GPUStencilOperation.Keep,
                    depthFailOp = GPUStencilOperation.Keep,
                    passOp = GPUStencilOperation.DecrementWrap,
                ),
                stencilReadMask = 0xFFu,
                stencilWriteMask = 0xFFu,
            ),
        ),
    )

    /**
     * Cover pipeline cache, one entry per `(blend mode, fill type)`. The
     * fragment stencil-test compares `(stencil & readMask)` against the
     * reference (0, set by `setStencilReference` before drawing) :
     *
     *  - `kWinding`         : `readMask = 0xFF`, compare `NotEqual` 0  -> fill where `count != 0`.
     *  - `kEvenOdd`         : `readMask = 0x01`, compare `NotEqual` 0  -> fill where the low bit is set (count is odd).
     *  - `kInverseWinding`  : `readMask = 0xFF`, compare `Equal` 0     -> fill where `count == 0` (outside the path).
     *  - `kInverseEvenOdd`  : `readMask = 0x01`, compare `Equal` 0     -> fill where the low bit is clear (count is even).
     *
     * Inverse variants pair with a viewport-spanning cover quad (not
     * the path bbox) so the entire clipped device area is rasterised
     * and the stencil decides which fragments belong to the "outside".
     */
    private val coverPipelineCache: MutableMap<Pair<SkBlendMode, SkPathFillType>, GPURenderPipeline> = mutableMapOf()

    private fun coverPipelineFor(mode: SkBlendMode, fillType: SkPathFillType): GPURenderPipeline =
        coverPipelineCache.getOrPut(mode to fillType) {
            val readMask: UInt = if (fillType.isEvenOdd()) 0x01u else 0xFFu
            val compare = if (fillType.isInverse()) GPUCompareFunction.Equal else GPUCompareFunction.NotEqual
            context.device.createRenderPipeline(
                RenderPipelineDescriptor(
                    layout = polygonPipelineLayout,
                    vertex = VertexState(
                        module = polygonShader,
                        entryPoint = "vs_main",
                        buffers = listOf(POLYGON_VERTEX_LAYOUT),
                    ),
                    fragment = FragmentState(
                        module = polygonShader,
                        entryPoint = "fs_main",
                        targets = listOf(
                            ColorTargetState(
                                format = intermediateFormat,
                                blend = blendStateFor(mode),
                            ),
                        ),
                    ),
                    depthStencil = DepthStencilState(
                        format = GPUTextureFormat.Depth24PlusStencil8,
                        depthWriteEnabled = false,
                        depthCompare = GPUCompareFunction.Always,
                        stencilFront = StencilFaceState(
                            compare = compare,
                            failOp = GPUStencilOperation.Keep,
                            depthFailOp = GPUStencilOperation.Keep,
                            passOp = GPUStencilOperation.Keep,
                        ),
                        stencilBack = StencilFaceState(
                            compare = compare,
                            failOp = GPUStencilOperation.Keep,
                            depthFailOp = GPUStencilOperation.Keep,
                            passOp = GPUStencilOperation.Keep,
                        ),
                        stencilReadMask = readMask,
                        stencilWriteMask = 0xFFu,
                    ),
                ),
            )
        }

    // ─── AA stencil-cover (G3.3b.3a / G3.3b.3d) — AA cover for multi-contour ──

    private val aaStencilCoverShader: GPUShaderModule = loadShader("shaders/aa_stencil_cover.wgsl")
    private val m60F16FragmentLaneDiagnosticShaderLazy: Lazy<GPUShaderModule> = lazy {
        loadM60F16FragmentLaneDiagnosticShader()
    }
    private val m60F16BoundedRuntimeCorrectionShaderLazy: Lazy<GPUShaderModule> = lazy {
