    private val m60F16BoundedRuntimeCorrectionDiagnosticShaderLazy: Lazy<GPUShaderModule> = lazy {
        loadM60F16BoundedRuntimeCorrectionDiagnosticShader()
    }
    private val m60F16BoundedCorrectionApplicationPointDiagnosticShaderLazy: Lazy<GPUShaderModule> = lazy {
        loadM60F16BoundedCorrectionApplicationPointDiagnosticShader()
    }
    private val m60F16CoverageStencilContributionMapDiagnosticShaderLazy: Lazy<GPUShaderModule> = lazy {
        loadM60F16CoverageStencilContributionMapDiagnosticShader()
    }
    private val m60F16AaStencilCoverContributionIsolationDiagnosticShaderLazy: Lazy<GPUShaderModule> = lazy {
        loadM60F16AaStencilCoverContributionIsolationDiagnosticShader()
    }
    private val m60F16AaStencilCoverShaderReturnDiagnosticShaderLazy: Lazy<GPUShaderModule> = lazy {
