    }
    private val m60F16ZeroMaskNeutralPathTraceFor448ShaderCache:
        MutableMap<String, GPUShaderModule> = mutableMapOf()
    private val m60F16WidthQuantizedColorReconstructionFor432ShaderLazy: Lazy<GPUShaderModule> = lazy {
        loadM60F16WidthQuantizedColorReconstructionFor432Shader()
    }

    private val m60F16FragmentLaneDiagnosticShader: GPUShaderModule
        get() = m60F16FragmentLaneDiagnosticShaderLazy.value

    private val m60F16BoundedRuntimeCorrectionShader: GPUShaderModule
        get() = m60F16BoundedRuntimeCorrectionShaderLazy.value

    private val m60F16BoundedRuntimeCorrectionDiagnosticShader: GPUShaderModule
        get() = m60F16BoundedRuntimeCorrectionDiagnosticShaderLazy.value

    private val m60F16BoundedCorrectionApplicationPointDiagnosticShader: GPUShaderModule
        get() = m60F16BoundedCorrectionApplicationPointDiagnosticShaderLazy.value

    private val m60F16CoverageStencilContributionMapDiagnosticShader: GPUShaderModule
        get() = m60F16CoverageStencilContributionMapDiagnosticShaderLazy.value

    private val m60F16AaStencilCoverContributionIsolationDiagnosticShader: GPUShaderModule
        get() = m60F16AaStencilCoverContributionIsolationDiagnosticShaderLazy.value

    private val m60F16AaStencilCoverShaderReturnDiagnosticShader: GPUShaderModule
        get() = m60F16AaStencilCoverShaderReturnDiagnosticShaderLazy.value

    private val m60F16AaStencilCoverShaderReturnStorageZeroCauseShader: GPUShaderModule
        get() = m60F16AaStencilCoverShaderReturnStorageZeroCauseShaderLazy.value

    private val m60F16WidthQuantizedRenderFixFor431Shader: GPUShaderModule
        get() = m60F16WidthQuantizedRenderFixFor431ShaderLazy.value

    private val m60F16ZeroMaskCorrectionFor447Shader: GPUShaderModule
        get() = m60F16ZeroMaskCorrectionFor447ShaderLazy.value

    private fun m60F16ZeroMaskNeutralPathTraceFor448Shader(mode: String): GPUShaderModule =
        m60F16ZeroMaskNeutralPathTraceFor448ShaderCache.getOrPut(mode) {
            loadM60F16ZeroMaskNeutralPathTraceFor448Shader(mode)
        }

    private val m60F16WidthQuantizedColorReconstructionFor432Shader: GPUShaderModule
        get() = m60F16WidthQuantizedColorReconstructionFor432ShaderLazy.value

    /**
     * G3.3b.3d — which half of the AA falloff a cover sub-draw paints.
     * `Inside` paints fragments the stencil counts as inside the fill
     * region with `coverage = clamp(minDist + 0.5, 0, 1)` ; `Outside`
     * paints fragments the stencil counts as outside with
     * `coverage = clamp(0.5 - minDist, 0, 1)`. Two mutually-exclusive
     * sub-draws over the same cover quad recover the full AA profile.
     */
    private enum class CoverageSide { Inside, Outside }

    private val aaStencilCoverPipelineCache: MutableMap<Triple<SkBlendMode, SkPathFillType, CoverageSide>, GPURenderPipeline> = mutableMapOf()
    private val m60F16FragmentLaneDiagnosticBindGroupLayoutLazy: Lazy<GPUBindGroupLayout> = lazy {
        context.device.createBindGroupLayout(
            BindGroupLayoutDescriptor(
                entries = buildList {
                    add(
                        BindGroupLayoutEntry(
                            binding = 0u,
                            visibility = GPUShaderStage.Vertex or GPUShaderStage.Fragment,
                            buffer = BufferBindingLayout(type = GPUBufferBindingType.Uniform),
                        ),
                    )
                    add(
                        BindGroupLayoutEntry(
                            binding = 1u,
                            visibility = GPUShaderStage.Fragment,
                            buffer = BufferBindingLayout(type = GPUBufferBindingType.Storage),
                        ),
                    )
                    if (m60F16RuntimeIntegerLaneMaskProbeFor445DiagnosticsEnabled) {
                        add(
                            BindGroupLayoutEntry(
                                binding = 2u,
                                visibility = GPUShaderStage.Fragment,
                                buffer = BufferBindingLayout(type = GPUBufferBindingType.Storage),
                            ),
                        )
                    }
                },
            ),
        )
    }

    private val m60F16FragmentLaneDiagnosticBindGroupLayout: GPUBindGroupLayout
        get() = m60F16FragmentLaneDiagnosticBindGroupLayoutLazy.value

    private val m60F16FragmentLaneDiagnosticPipelineLayoutLazy = lazy {
        context.device.createPipelineLayout(
            PipelineLayoutDescriptor(bindGroupLayouts = listOf(m60F16FragmentLaneDiagnosticBindGroupLayout)),
        )
    }

    private val m60F16FragmentLaneDiagnosticPipelineLayout
        get() = m60F16FragmentLaneDiagnosticPipelineLayoutLazy.value

    private val m60F16FragmentLaneDiagnosticPipelineCache:
        MutableMap<Triple<SkBlendMode, SkPathFillType, CoverageSide>, GPURenderPipeline> = mutableMapOf()
    private val m60F16BoundedRuntimeCorrectionPipelineCache:
        MutableMap<Pair<Triple<SkBlendMode, SkPathFillType, CoverageSide>, Boolean>, GPURenderPipeline> =
            mutableMapOf()
    private val m60F16AaStencilCoverIsolatedColorTargetPipelineCache:
        MutableMap<Triple<SkPathFillType, CoverageSide, Boolean>, GPURenderPipeline> = mutableMapOf()
    private val m60F16AaStencilCoverStorageColorTargetComparisonPipelineCache:
        MutableMap<Pair<SkPathFillType, CoverageSide>, GPURenderPipeline> = mutableMapOf()
    private val m60F16AaStencilCoverShaderReturnStorageZeroCausePipelineCache:
        MutableMap<Pair<SkPathFillType, CoverageSide>, GPURenderPipeline> = mutableMapOf()
    private val m60F16WidthQuantizedRenderFixFor431PipelineCache:
        MutableMap<Triple<SkBlendMode, SkPathFillType, CoverageSide>, GPURenderPipeline> = mutableMapOf()
    private val m60F16ZeroMaskCorrectionFor447PipelineCache:
        MutableMap<Triple<SkBlendMode, SkPathFillType, CoverageSide>, GPURenderPipeline> = mutableMapOf()
    private val m60F16ZeroMaskNeutralPathTraceFor448PipelineCache:
        MutableMap<Pair<Triple<SkBlendMode, SkPathFillType, CoverageSide>, String>, GPURenderPipeline> =
            mutableMapOf()
    private val m60F16WidthQuantizedColorReconstructionFor432PipelineCache:
        MutableMap<Triple<SkBlendMode, SkPathFillType, CoverageSide>, GPURenderPipeline> = mutableMapOf()

    /**
     * AA-cover pipeline. Same fill-type encoding as [coverPipelineFor]
     * (readMask + compare op derived from [SkPathFillType]) but the
     * fragment shader produces AA coverage from the path's edge segments.
     * Bind group layout is shared with the single-contour AA pipeline.
     *
     * G3.3b.3d — [side] selects whether this pipeline paints the inside
     * or outside half of the AA boundary. `Outside` flips the stencil
     * compare op (so the same stencil reference 0 gates the opposite set
     * of fragments) and switches to the `fs_outside` shader entry point.
     */
    private fun aaStencilCoverPipelineFor(
        mode: SkBlendMode,
        fillType: SkPathFillType,
        side: CoverageSide,
    ): GPURenderPipeline =
        aaStencilCoverPipelineCache.getOrPut(Triple(mode, fillType, side)) {
            val readMask: UInt = if (fillType.isEvenOdd()) 0x01u else 0xFFu
            val insideCompare =
                if (fillType.isInverse()) GPUCompareFunction.Equal else GPUCompareFunction.NotEqual
            val compare = when (side) {
                CoverageSide.Inside -> insideCompare
                CoverageSide.Outside ->
                    if (insideCompare == GPUCompareFunction.Equal) GPUCompareFunction.NotEqual
                    else GPUCompareFunction.Equal
            }
            val entryPoint = when (side) {
                CoverageSide.Inside -> "fs_inside"
                CoverageSide.Outside -> "fs_outside"
            }
            context.device.createRenderPipeline(
                RenderPipelineDescriptor(
                    layout = aaPolygonPipelineLayout,
                    vertex = VertexState(
                        module = aaStencilCoverShader,
                        entryPoint = "vs_main",
                        buffers = listOf(POLYGON_VERTEX_LAYOUT),
                    ),
                    fragment = FragmentState(
                        module = aaStencilCoverShader,
                        entryPoint = entryPoint,
                        targets = listOf(
                            ColorTargetState(
                                format = intermediateFormat,
                                blend = blendStateFor(mode),
                            ),
                        ),
                    ),
                    depthStencil = DepthStencilState(
                        format = GPUTextureFormat.Depth24PlusStencil8,
                        depthWriteEnabled = false,
                        depthCompare = GPUCompareFunction.Always,
                        stencilFront = StencilFaceState(
                            compare = compare,
                            failOp = GPUStencilOperation.Keep,
                            depthFailOp = GPUStencilOperation.Keep,
                            passOp = GPUStencilOperation.Keep,
                        ),
                        stencilBack = StencilFaceState(
                            compare = compare,
                            failOp = GPUStencilOperation.Keep,
                            depthFailOp = GPUStencilOperation.Keep,
                            passOp = GPUStencilOperation.Keep,
                        ),
                        stencilReadMask = readMask,
                        stencilWriteMask = 0xFFu,
                    ),
                ),
            )
        }

    private fun m60F16WidthQuantizedRenderFixFor431PipelineFor(
        mode: SkBlendMode,
        fillType: SkPathFillType,
