                    layout = aaPolygonPipelineLayout,
                    vertex = VertexState(
                        module = aaStencilCoverConicalFocalGradientShader,
                        entryPoint = "vs_main",
                        buffers = listOf(POLYGON_VERTEX_LAYOUT),
                    ),
                    fragment = FragmentState(
                        module = aaStencilCoverConicalFocalGradientShader,
                        entryPoint = entryPoint,
                        targets = listOf(
                            ColorTargetState(
                                format = intermediateFormat,
                                blend = blendStateFor(mode),
                            ),
                        ),
                    ),
                    depthStencil = DepthStencilState(
                        format = GPUTextureFormat.Depth24PlusStencil8,
                        depthWriteEnabled = false,
                        depthCompare = GPUCompareFunction.Always,
                        stencilFront = StencilFaceState(
                            compare = compare,
                            failOp = GPUStencilOperation.Keep,
                            depthFailOp = GPUStencilOperation.Keep,
                            passOp = GPUStencilOperation.Keep,
                        ),
                        stencilBack = StencilFaceState(
                            compare = compare,
                            failOp = GPUStencilOperation.Keep,
                            depthFailOp = GPUStencilOperation.Keep,
                            passOp = GPUStencilOperation.Keep,
                        ),
                        stencilReadMask = readMask,
                        stencilWriteMask = 0xFFu,
                    ),
                ),
            )
        }

    // ─── Bitmap shader on non-rect (G5.2.1) ─────────────────────────────
    //
    // AA stencil-and-cover cover-pass pipeline carrying a bitmap-shader
    // fragment shader. Mirror of the gradient stencil-cover pipelines
    // above but the bind group needs binding 1 (texture) + binding 2
    // (sampler) in addition to the uniform at binding 0 -- so this
    // family gets its own bind group layout + pipeline layout, plus its
    // own stencil-write pipeline (so both passes share the same 3-entry
    // bind group). The fragment shader has only 2 entry points (inside /
    // outside) -- the 4 tile modes are resolved by the per-draw sampler
    // (addressModeU / V for kClamp / kRepeat / kMirror) and a per-axis
    // in-shader kDecal check, matching `bitmap_shader.wgsl`'s scheme.
    // Hence the cache key shape is `(blend, fillType, side)` -- no
    // tileMode in the key. The (filter, tileX, tileY) tuple lives on the
    // bind group's sampler, not on the pipeline.

    private val aaStencilCoverBitmapShader: GPUShaderModule =
        loadShader("shaders/aa_stencil_cover_bitmap_shader.wgsl")

    /**
     * Bind group layout shared by the bitmap-shader stencil-write
     * pipeline AND the bitmap-shader cover pipelines :
     *   binding 0 -- uniform buffer (color + viewport + srcRect + dstRect +
     *                imageSize + paintColor + csFlags + csMatrix +
     *                edgeCountPad + edges), visibility = Vertex|Fragment
     *                (the stencil shader's vertex stage reads viewport
     *                from offset 16, the cover shader's fragment stage
     *                reads everything else)
     *   binding 1 -- sampled 2D texture (the cached image), visibility = Fragment
     *   binding 2 -- filtering sampler, visibility = Fragment
     * The stencil-write fragment shader (`solid_polygon.wgsl`) ignores
     * binding 1 / 2 -- they remain unread but must be bound, which
     * matches WebGPU's pipeline-vs-bind-group compatibility rule.
     */
    private val aaStencilCoverBitmapShaderBindGroupLayout: GPUBindGroupLayout =
        context.device.createBindGroupLayout(
            BindGroupLayoutDescriptor(
                entries = listOf(
                    BindGroupLayoutEntry(
                        binding = 0u,
                        visibility = GPUShaderStage.Vertex or GPUShaderStage.Fragment,
                        buffer = BufferBindingLayout(type = GPUBufferBindingType.Uniform),
                    ),
                    BindGroupLayoutEntry(
                        binding = 1u,
                        visibility = GPUShaderStage.Fragment,
                        texture = TextureBindingLayout(
                            sampleType = GPUTextureSampleType.Float,
                            viewDimension = GPUTextureViewDimension.TwoD,
                            multisampled = false,
                        ),
                    ),
                    BindGroupLayoutEntry(
                        binding = 2u,
                        visibility = GPUShaderStage.Fragment,
                        sampler = SamplerBindingLayout(type = GPUSamplerBindingType.Filtering),
                    ),
                ),
            ),
        )

    private val aaStencilCoverBitmapShaderPipelineLayout = context.device.createPipelineLayout(
        PipelineLayoutDescriptor(bindGroupLayouts = listOf(aaStencilCoverBitmapShaderBindGroupLayout)),
    )

    /**
     * Dedicated stencil-write pipeline that uses the bitmap-shader
     * pipeline layout (3-binding bind group). Functionally identical to
     * [stencilWritePipeline] -- same vertex shader (`solid_polygon.wgsl`),
     * same stencil ops (increment-front / decrement-back, color writes
     * masked off, depth always-pass). Only the bind group layout differs
     * so a single bind group can satisfy both the stencil and cover
     * passes for an [StencilCoverAaBitmapShaderDraw].
     */
    private val aaStencilCoverBitmapShaderStencilPipeline: GPURenderPipeline =
        context.device.createRenderPipeline(
            RenderPipelineDescriptor(
                layout = aaStencilCoverBitmapShaderPipelineLayout,
                vertex = VertexState(
                    module = polygonShader,
                    entryPoint = "vs_main",
                    buffers = listOf(POLYGON_VERTEX_LAYOUT),
                ),
                fragment = FragmentState(
                    module = polygonShader,
                    entryPoint = "fs_main",
                    targets = listOf(
                        ColorTargetState(
                            format = intermediateFormat,
                            blend = blendAddBoth(GPUBlendFactor.One, GPUBlendFactor.Zero),
                            writeMask = GPUColorWrite.None,
                        ),
                    ),
                ),
                depthStencil = DepthStencilState(
                    format = GPUTextureFormat.Depth24PlusStencil8,
                    depthWriteEnabled = false,
                    depthCompare = GPUCompareFunction.Always,
                    stencilFront = StencilFaceState(
                        compare = GPUCompareFunction.Always,
                        failOp = GPUStencilOperation.Keep,
                        depthFailOp = GPUStencilOperation.Keep,
                        passOp = GPUStencilOperation.IncrementWrap,
                    ),
                    stencilBack = StencilFaceState(
                        compare = GPUCompareFunction.Always,
                        failOp = GPUStencilOperation.Keep,
                        depthFailOp = GPUStencilOperation.Keep,
                        passOp = GPUStencilOperation.DecrementWrap,
                    ),
                    stencilReadMask = 0xFFu,
                    stencilWriteMask = 0xFFu,
                ),
            ),
        )

    private data class AaStencilCoverBitmapShaderKey(
        val mode: SkBlendMode,
        val fillType: SkPathFillType,
        val side: CoverageSide,
    )

    private val aaStencilCoverBitmapShaderPipelineCache:
        MutableMap<AaStencilCoverBitmapShaderKey, GPURenderPipeline> = mutableMapOf()

    private fun aaStencilCoverBitmapShaderFragmentEntryPoint(side: CoverageSide): String =
        when (side) {
            CoverageSide.Inside -> "fs_inside"
            CoverageSide.Outside -> "fs_outside"
        }

    private fun aaStencilCoverBitmapShaderPipelineFor(
        mode: SkBlendMode,
        fillType: SkPathFillType,
        side: CoverageSide,
    ): GPURenderPipeline =
        aaStencilCoverBitmapShaderPipelineCache.getOrPut(
            AaStencilCoverBitmapShaderKey(mode, fillType, side),
        ) {
            val readMask: UInt = if (fillType.isEvenOdd()) 0x01u else 0xFFu
            val insideCompare =
                if (fillType.isInverse()) GPUCompareFunction.Equal else GPUCompareFunction.NotEqual
            val compare = when (side) {
                CoverageSide.Inside -> insideCompare
                CoverageSide.Outside ->
                    if (insideCompare == GPUCompareFunction.Equal) GPUCompareFunction.NotEqual
                    else GPUCompareFunction.Equal
            }
            val entryPoint = aaStencilCoverBitmapShaderFragmentEntryPoint(side)
            context.device.createRenderPipeline(
                RenderPipelineDescriptor(
                    layout = aaStencilCoverBitmapShaderPipelineLayout,
                    vertex = VertexState(
                        module = aaStencilCoverBitmapShader,
                        entryPoint = "vs_main",
                        buffers = listOf(POLYGON_VERTEX_LAYOUT),
                    ),
                    fragment = FragmentState(
                        module = aaStencilCoverBitmapShader,
                        entryPoint = entryPoint,
                        targets = listOf(
                            ColorTargetState(
                                format = intermediateFormat,
                                blend = blendStateFor(mode),
                            ),
                        ),
                    ),
                    depthStencil = DepthStencilState(
                        format = GPUTextureFormat.Depth24PlusStencil8,
                        depthWriteEnabled = false,
                        depthCompare = GPUCompareFunction.Always,
                        stencilFront = StencilFaceState(
                            compare = compare,
                            failOp = GPUStencilOperation.Keep,
                            depthFailOp = GPUStencilOperation.Keep,
                            passOp = GPUStencilOperation.Keep,
                        ),
                        stencilBack = StencilFaceState(
                            compare = compare,
                            failOp = GPUStencilOperation.Keep,
                            depthFailOp = GPUStencilOperation.Keep,
                            passOp = GPUStencilOperation.Keep,
                        ),
                        stencilReadMask = readMask,
                        stencilWriteMask = 0xFFu,
                    ),
                ),
            )
        }

    /**
     * Translate a [SkBlendMode] into the WebGPU [BlendState] that
     * implements it. G2.2 covers the 4 modes WebGPU expresses natively
     * via `BlendComponent` (no shader-side blending, no `loadOp = load`
     * round-trip) :
     *
     *  - [SkBlendMode.kClear]   : `src * 0 + dst * 0 = 0`
     *  - [SkBlendMode.kSrc]     : `src * 1 + dst * 0 = src`
     *  - [SkBlendMode.kSrcOver] : `src * 1 + dst * (1 - src.a)`
     *  - [SkBlendMode.kDstOver] : `src * (1 - dst.a) + dst * 1`
     *
     * Other modes refuse through [BlendPlan] unless they are routed
     * through an explicit shader/layer composite path.
     *
     * Note that fragment output is **premultiplied** (see
     * `solid_color.wgsl`), so `src.a` and `src.rgb * src.a` are already
     * in lockstep when these factors apply — the standard premul-input
     * formulation is what these constants assume.
     */
    private fun blendStateFor(mode: SkBlendMode): BlendState {
        val plan = blendPlanFor(mode)
        if (!plan.isFixedFunction) {
            error(plan.reason)
        }
        return when (mode) {
            SkBlendMode.kClear -> blendAddBoth(src = GPUBlendFactor.Zero, dst = GPUBlendFactor.Zero)
            SkBlendMode.kSrc -> blendAddBoth(src = GPUBlendFactor.One, dst = GPUBlendFactor.Zero)
            SkBlendMode.kSrcOver -> blendAddBoth(src = GPUBlendFactor.One, dst = GPUBlendFactor.OneMinusSrcAlpha)
            SkBlendMode.kDstOver -> blendAddBoth(src = GPUBlendFactor.OneMinusDstAlpha, dst = GPUBlendFactor.One)
            // G3.3a.1 — kPlus is `out = clamp(src + dst, 0, 1)` per Skia
            // (`SkBlendMode.kPlus`). In premul-in / premul-out (our convention),
            // `(srcFactor=One, dstFactor=One, op=Add)` evaluates exactly to
            // that clamped sum.
            SkBlendMode.kPlus -> blendAddBoth(src = GPUBlendFactor.One, dst = GPUBlendFactor.One)
            else -> error("Fixed-function BlendPlan has no BlendState mapping for $mode")
        }
    }

    private fun blendPlanFor(mode: SkBlendMode): BlendPlan = selectWebGpuBlendPlan(mode)

    /**
     * Helper : symmetric `BlendComponent` for color AND alpha with
     * `op = Add`. Both Porter-Duff modes in G2.2 use the same factors
     * for color and alpha (the standard premul formulation), so a
     * single helper covers all 4.
     */
    private fun blendAddBoth(src: GPUBlendFactor, dst: GPUBlendFactor): BlendState {
        val component = BlendComponent(operation = GPUBlendOperation.Add, srcFactor = src, dstFactor = dst)
        return BlendState(color = component, alpha = component)
    }

    override fun deviceClipBounds(): SkIRect = SkIRect.MakeWH(width, height)

    /**
     * Phase G-saveLayer — allocate a child GPU device for a
     * `saveLayer` scope. The returned device shares this device's
     * [context] (so layer textures and parent textures live on the
     * same WebGPU adapter / queue) and the same
     * [intermediateFormat] (so a future direct-blit composite stays
     * bit-iso). The colorspace transform is forced to `false` on
     * layer devices : the layer renders into intermediate-format
     * pixels that the parent samples via [compositeFrom] ; the final
     * present pass (sRGB → Rec.2020) only runs once, on the root
     * canvas's flush.
     *
     * **Caveats.**
     *  - Layer devices have their own depth-stencil / pipeline caches.
     *    They cost N draw passes worth of resources per layer.
     *  - `width` and `height` are clamped to the layer bounds the
     *    canvas passes (already intersected with the parent clip), so
     *    1×1 minimum suffices. A zero-area layer never reaches this
     *    path (SkCanvas degenerates it to an empty save).
     *  - Currently used only for plain `saveLayer(bounds, paint)`. The
     *    SaveLayerRec backdrop / SkImageFilter / SkColorFilter slots
     *    on the layer paint fall through to `compositeFrom` with
     *    those slots dropped (documented deferred Phase G-saveLayer-X).
     */
    override fun makeLayerDevice(
        width: Int,
        height: Int,
        colorType: org.skia.foundation.SkColorType?,
    ): SkDevice =
        SkWebGpuDevice(
            context = context,
            width = width,
            height = height,
            applyColorspaceTransform = false,
            intermediateFormat = intermediateFormat,
        ).also {
            // Phase G-saveLayer-imageFilter-dropshadow -- saveLayer
            // semantics require the layer device to start transparent
            // (the layer captures only the draws that hit it ; pixels
            // not drawn remain alpha = 0 so the parent composite
            // sees-through to whatever was below). The root SkWebGpuDevice
            // ctor defaults `background` to opaque white (matching the
            // GM convention) ; we override here so the layer's first-
            // pass `loadOp = Clear` clears to transparent. Without this,
            // every saveLayer would have an opaque white background and
            // the imageFilter Blur / DropShadow paths would silhouette
            // the entire layer rect instead of the actually-drawn shape.
            it.setBackground(0)
        }

    /**
     * Phase G-saveLayer-backdrop (#591) + Phase J5 backdrop filter --
     * seed `this` layer device with a copy of [parent]'s pixels in
     * the rectangle `[originX, originY, originX + width, originY +
     * height)`, optionally filtered through the [backdrop]
     * [org.skia.foundation.SkImageFilter] before it lands.
     *
     * Mechanism :
     *   1. Flush [parent]'s pending draws onto its intermediate
     *      texture (so all preceding canvas draws are committed).
     *      Subsequent parent flushes use `loadOp = Load` (the
     *      [intermediateInitialized] guard) so this mid-render flush
     *      doesn't get wiped by the next
     *      [encodePendingDrawsToIntermediate].
     *   2. Enqueue a copy-only [LayerCompositeDraw] onto **this**
     *      (child) device's pending list. The draw samples [parent]'s
     *      intermediate via the existing `layer_composite.wgsl`
     *      pipeline (1:1 `textureLoad` -- no filter, no sampler) and
     *      writes onto this device's intermediate under blend mode
     *      `kSrc` (REPLACE, so the child's initial transparent clear
     *      is overwritten by the parent's pixels). The origin offset
     *      is encoded as the negative `dstOriginX/Y` in the composite
     *      uniform : at child pixel `(x, y)` the shader computes
     *      `layer_px = (x, y) - (-originX, -originY) = (x + originX,
     *      y + originY)`, sampling the matching parent pixel.
     *   3. (Phase J5) When [backdrop] is a `SkImageFilters.Blur` with
     *      a positive sigma on either axis, enqueue a follow-up
     *      [BlurredLayerCompositeDraw] on this device's pending list.
     *      The blur sources [intermediateView] (the just-seeded
     *      copy), runs the separable Gaussian via the two scratch
     *      H/V textures, and writes the blurred result back onto
     *      [intermediateView] with `mode = kSrc` (REPLACING the
     *      unfiltered copy). The composite uniform's `dstOrigin =
     *      (0, 0)` because both the source and the dst are layer-
     *      local at this stage. The scratch textures are owned by
     *      the draw and released after submission by
     *      `closeDrawResources`. The same shader resources as
     *      `paint.imageFilter = Blur` on `compositeFrom` are reused
     *      -- no new pipelines.
     *
     * **Scope.** Supported variants :
     *  - `SkImageFilters.Blur(input = null)` (Phase J5) -- separable
     *    Gaussian on the seeded copy, kClamp / kDecal tile modes.
     *  - `SkImageFilters.ColorFilter(cf, input = null)` (Phase K3) --
     *    the cf is folded into the copy-seed
     *    [LayerCompositeDraw]'s `colorFilterPacked` slot ; no extra
     *    render pass. Supports `SkColorFilters.Blend` and
     *    `SkColorFilters.Matrix` (the two variants the WGSL composite
     *    shader implements) ; other cf variants degrade to identity
     *    (filter dropped, layer seeded with raw parent pixels).
     *  - `SkImageFilters.DropShadow(dx, dy, sigmaX, sigmaY, color,
     *    input = null)` (Phase K3) -- copy-seed + 3-pass
     *    [BlurredLayerCompositeDraw] (H blur, V blur, tinted composite
     *    onto the seeded layer via `mode = kDstOver` so the shadow
     *    lands behind the existing content). Matches upstream
     *    DropShadowImageFilter semantics : the shadow shows through
     *    transparent regions of the seed (e.g. when the layer rect
     *    extends past opaque parent content).
     *  - `SkImageFilters.Offset(dx, dy, input = null)` (Phase L2a) --
     *    the integer-rounded `(dx, dy)` folds into the copy-seed's
     *    `dstOriginX/Y` slot ; the composite shader's existing
     *    integer-grid fast path samples the parent at a shifted
     *    address. Samples that land outside the parent's pixel grid
     *    return transparent (kDecal-equivalent), matching the CPU
     *    raster semantic for an Offset filter over a finite source.
     *    No extra render pass, no new pipeline.
     *
     * Other variants (`MatrixTransform`, `Compose`, ...) fall through
     * to copy-only : the layer is seeded with raw parent pixels, the
     * filter is silently dropped. Widening the supported set is a
     * follow-up slice ; the CPU raster path in `SkCanvas.saveLayer`
     * remains the full-featured fallback for offline / non-GPU
     * rendering.
     *
     * **Bail conditions** -- the seed silently no-ops (returns
     * `false`) when :
     *  - [parent] is not an [SkWebGpuDevice]. Cross-backend backdrop
     *    (CPU parent → GPU child, etc.) needs a readback round-trip
     *    that's out of scope.
     *  - [parent]'s [context] differs from this device's. Sampling
     *    across contexts is illegal in WebGPU.
     *  - [parent]'s [intermediateFormat] differs from this device's.
     *    Cross-format sampling needs a conversion render pass that's
     *    out of scope ; `makeLayerDevice` always copies the parent's
     *    format so this only fires for user-constructed mismatches.
     */
    override fun seedBackdropFrom(
        parent: SkDevice,
        originX: Int,
        originY: Int,
        width: Int,
        height: Int,
        backdrop: org.skia.foundation.SkImageFilter?,
    ): Boolean {
        val gpuParent = parent as? SkWebGpuDevice ?: return false
        if (gpuParent.context !== context) return false
        if (gpuParent.intermediateFormat != intermediateFormat) return false
        if (width <= 0 || height <= 0) return false

        // Flush the parent's pending draws so its intermediate holds
        // all preceding canvas draws. Subsequent parent flushes use
        // `loadOp = Load` (Phase G-saveLayer-backdrop guard) so this
        // mid-render flush doesn't get wiped by the next
        // [encodePendingDrawsToIntermediate].
        gpuParent.flushDrawsOnly()

        // Step 1 -- copy-only seed. Enqueue a composite draw on this
        // (child) device's pending list. `dstOriginX/Y` are the
        // NEGATIVE layer origins so the shader maps `child (x, y) →
        // parent (x + originX, y + originY)`. Scissor covers the full
        // child target. `mode = kSrc` so the child's transparent
        // clear (via `setBackground(0)`) is replaced -- subsequent
        // layer draws then composite ON TOP via `loadOp = Load`.
        //
        // Phase K3 -- when [backdrop] is a [SkImageFilters.ColorFilter]
        // wrap (with `input == null`), the inner [SkColorFilter] folds
        // directly into the copy-seed's `colorFilterPacked` slot --
        // the composite shader applies the cf per-sample, identical
        // result to a snapshot-then-apply-cf path. Supported variants
        // are [SkColorFilters.Blend] and [SkColorFilters.Matrix]
        // (the two the WGSL `apply_color_filter` helper implements) ;
        // others pack to the identity payload (kind = 0) and the seed
        // degrades silently to copy-only. See [packLayerCompositeColorFilter].
        val seedColorFilter = backdrop?.asColorFilterImageFilter()
            ?.takeIf { it.input == null }
            ?.colorFilter
        val seedColorFilterPacked = if (seedColorFilter != null) {
            packLayerCompositeColorFilter(seedColorFilter)
        } else {
            FloatArray(24) // identity (kind = 0).
        }

        // L2b -- when [backdrop] is a [SkImageFilters.MatrixTransform]
        // wrap (with `input == null`, no perspective, no cubic sampler,
        // invertible matrix), the seed pass replaces the plain copy with
        // an affine remap : at each child pixel `(cx, cy)`, the shader
        // samples the parent's intermediate at `M^{-1}(cx, cy) +
        // (originX, originY)`. Mirrors the top-level paint imageFilter
        // path's affine packing (see [enqueueMatrixTransformLayerComposite]
        // and [packLayerCompositeMatrixTransform]) but specialised for
        // the backdrop seed slot : the source is the PARENT's intermediate
        // (full width / height) rather than a layer's, the `c / f`
        // translation slots fold in `+originX / +originY` (the layer's
        // top-left in parent-device px) instead of `-originX / -originY`,
        // and the dst is THIS device's intermediate (the child layer).
        //
        // Variants we still degrade to copy-only (silent, matches the
        // [SkDevice.seedBackdropFrom] kdoc) :
        //  - non-null child filter (input != null) -- would need a
        //    render-to-texture pre-pass that the seed path doesn't ship.
        //  - perspective matrix -- the shader's `vec3 dot-product` only
        //    covers 2x3 affine ; a 3x3 with non-trivial bottom row needs
        //    a homogeneous divide.
        //  - cubic sampler -- shader implements kNearest / kLinear only.
        //  - non-invertible matrix -- the reverse map is undefined ;
        //    upstream `SkMatrixTransformImageFilter` returns the input
        //    unchanged in that case, so we just fall through to the copy-
        //    only seed (visible footprint is the unaltered parent copy).
        val matrixSeedParams = backdrop?.asMatrixTransformImageFilter()
            ?.takeIf {
                it.input == null &&
                    !it.matrix.hasPerspective() &&
                    it.sampling.cubic == null
            }
        val matrixSeedInverse = matrixSeedParams?.matrix?.invert()
        if (matrixSeedParams != null && matrixSeedInverse != null) {
            enqueueBackdropMatrixTransformSeed(
                gpuParent = gpuParent,
                originX = originX, originY = originY,
                width = width, height = height,
                params = matrixSeedParams,
                invMatrix = matrixSeedInverse,
            )
            return true
        }

        // Phase L2a -- when [backdrop] is a [SkImageFilters.Offset]
        // wrap (with `input == null`), fold the integer-rounded
        // translation `(dx, dy)` into the copy-seed's `dstOriginX/Y`.
        // Upstream `SkOffsetImageFilter` produces the source image
        // shifted by `(+dx, +dy)` in device space ; sampling that
        // filtered parent at layer-pixel `(x, y)` (which maps to
        // parent-global `(originX + x, originY + y)`) reads parent at
        // `(originX + x - dx, originY + y - dy)`. The composite shader
        // computes `parent_px = child_px - dstOrigin`, so subtracting
        // `(sdx, sdy)` from the layer origin (i.e. `dstOriginX =
        // -(originX - sdx) = -originX + sdx`) does the trick. No new
        // pipeline, no shader change -- the existing integer-grid
        // fast path (`imageFilterPacked` identity, `matrixPacked`
        // identity, `samplingMode == 0`) just samples at a shifted
        // address. Out-of-bounds samples land outside `[0, parent_w)
        // × [0, parent_h)` and the shader's `layer_load` guard returns
        // `vec4f(0)` (kDecal-equivalent), matching the CPU raster
        // semantic for an Offset filter over a finite source. The
        // integer rounding mirrors the top-level
        // `compositeFrom`'s offset path (`floor(d + 0.5)` -- the
        // saveLayer composite runs at identity CTM so `scale == 1`).
        // Offset is mutually exclusive with the ColorFilter wrap
        // (a backdrop is a single leaf filter here -- Compose with
        // multiple leaves remains deferred to a follow-up slice).
        val seedOffset = backdrop?.asOffsetImageFilter()?.takeIf { it.input == null }
        val seedShiftX = if (seedOffset != null) floor(seedOffset.dx + 0.5f).toInt() else 0
        val seedShiftY = if (seedOffset != null) floor(seedOffset.dy + 0.5f).toInt() else 0
        pending.add(
            LayerCompositeDraw(
                layerView = gpuParent.intermediateView,
                layerWidth = gpuParent.width,
                layerHeight = gpuParent.height,
                dstOriginX = -originX + seedShiftX,
                dstOriginY = -originY + seedShiftY,
                scissor = intArrayOf(0, 0, width, height),
                paintR = 1f, paintG = 1f, paintB = 1f, paintA = 1f,
                r = 1f, g = 1f, b = 1f, a = 1f,
                mode = SkBlendMode.kSrc,
                colorFilterPacked = seedColorFilterPacked,
                matrixPacked = IDENTITY_LAYER_MATRIX_12,
                imageFilterPacked = FloatArray(12), // identity (kind = 0).
            ),
        )

        // Step 2 -- optional filter application on the seeded copy.
        // Supported : Blur (Phase J5), DropShadow (Phase K3). ColorFilter
        // was already folded into the copy-seed's colorFilterPacked
        // above ; MatrixTransform took the early return branch above ;
        // other variants leave the seed at copy-only (silent degrade,
        // matches the SkDevice.seedBackdropFrom kdoc).
        if (backdrop != null) {
            val blur = backdrop.asBlurImageFilter()
            if (blur != null && blur.input == null &&
                (blur.sigmaX > 0f || blur.sigmaY > 0f) &&
                blur.sigmaX.isFinite() && blur.sigmaY.isFinite() &&
                blur.sigmaX >= 0f && blur.sigmaY >= 0f &&
                (blur.tileMode == SkTileMode.kClamp ||
                    blur.tileMode == SkTileMode.kDecal)
            ) {
                enqueueBackdropBlurSeed(
                    width = width, height = height,
                    sigmaX = blur.sigmaX, sigmaY = blur.sigmaY,
                    tileMode = blur.tileMode,
                )
            } else {
                val dropShadow = backdrop.asDropShadowImageFilter()
                if (dropShadow != null && dropShadow.input == null &&
                    dropShadow.sigmaX.isFinite() && dropShadow.sigmaY.isFinite() &&
                    dropShadow.sigmaX >= 0f && dropShadow.sigmaY >= 0f
                ) {
                    enqueueBackdropDropShadowSeed(
                        width = width, height = height,
                        dx = dropShadow.dx, dy = dropShadow.dy,
                        sigmaX = dropShadow.sigmaX, sigmaY = dropShadow.sigmaY,
                        shadowColor = dropShadow.color,
                    )
                }
            }
            // All other variants : seed stays at copy-only (silent
            // degrade -- matches the SkDevice.seedBackdropFrom kdoc).
        }
        return true
    }

    /**
     * Phase J5 helper -- enqueue a [BlurredLayerCompositeDraw] that
     * sources `this` device's [intermediateView] (the just-seeded
     * parent copy) and writes the blurred result back onto the same
     * intermediate via `mode = kSrc`. Mirrors
     * [enqueueBlurredLayerComposite] but specialised for the
     * backdrop seed slot :
     *  - `layerView` is `this.intermediateView`, not a child's --
     *    the parent's rect already lives in `this`'s intermediate
     *    after the preceding [LayerCompositeDraw].
     *  - `dstOrigin = (0, 0)`, `layerWidth = width`, `layerHeight =
     *    height` -- the composite is layer-local (no offset onto a
     *    parent device).
     *  - `mode = kSrc` -- the blurred pixels REPLACE the unfiltered
     *    copy. Subsequent user draws inside the layer scope then
     *    composite ON TOP via `loadOp = Load`.
     *  - No paint colour modulation (`paintR/G/B/A = 1`) and no
     *    colour filter / pre-CF -- the backdrop only carries the
     *    Blur, the post-restore composite still honours the layer
     *    paint's own alpha / colour filter / blend mode.
     *
     * The read-after-write hazard between the copy-only seed (which
     * writes `intermediateView`) and the blur's H pass (which reads
     * `intermediateView`) is naturally serialised : both draws are
     * separate render passes in [encodePendingDrawsToIntermediate],
     * dispatched in `pending` order, so WebGPU's execution model
     * orders the write before the read.
     */
    private fun enqueueBackdropBlurSeed(
        width: Int, height: Int,
        sigmaX: Float, sigmaY: Float,
        tileMode: SkTileMode,
    ) {
        val unboundedRadiusX = if (sigmaX > 0f) {
            ceil(3.0 * sigmaX).toInt().coerceAtLeast(1)
        } else 0
        val unboundedRadiusY = if (sigmaY > 0f) {
            ceil(3.0 * sigmaY).toInt().coerceAtLeast(1)
        } else 0
        val radiusX = unboundedRadiusX.coerceAtMost(MAX_BLUR_RADIUS)
        val radiusY = unboundedRadiusY.coerceAtMost(MAX_BLUR_RADIUS)
        val kernelX = if (radiusX > 0) {
            buildSymmetricGaussianHalfKernel(sigmaX, radiusX)
        } else floatArrayOf(1f)
        val kernelY = if (radiusY > 0) {
            buildSymmetricGaussianHalfKernel(sigmaY, radiusY)
        } else floatArrayOf(1f)

        val scratchH = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = width.toUInt(), height = height.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.backdropBlurScratchH",
            ),
        )
        val scratchHView = scratchH.createView()
        val scratchV = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = width.toUInt(), height = height.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.backdropBlurScratchV",
            ),
        )
        val scratchVView = scratchV.createView()

        pending.add(
            BlurredLayerCompositeDraw(
                layerView = intermediateView,
                layerWidth = width, layerHeight = height,
                scratchHTexture = scratchH, scratchHView = scratchHView,
                scratchVTexture = scratchV, scratchVView = scratchVView,
                dstOriginX = 0, dstOriginY = 0,
                scissor = intArrayOf(0, 0, width, height),
                kernelX = kernelX, radiusX = radiusX,
                kernelY = kernelY, radiusY = radiusY,
                tileModeOrdinal = tileMode.ordinal,
                paintR = 1f, paintG = 1f, paintB = 1f, paintA = 1f,
                colorFilterPacked = FloatArray(24), // identity (kind = 0).
                preBlurColorFilterPacked = null,
                scratchPreCfTexture = null,
                scratchPreCfView = null,
                r = 1f, g = 1f, b = 1f, a = 1f,
                mode = SkBlendMode.kSrc,
            ),
        )
    }

    /**
     * Phase K3 helper -- enqueue a [BlurredLayerCompositeDraw] that
     * sources `this` device's [intermediateView] (the just-seeded
     * parent copy) and lands a colorized blurred shadow BEHIND it
     * via `mode = kDstOver`. Mirrors [enqueueBackdropBlurSeed] but
     * specialised for the DropShadow backdrop variant :
     *  - The blur runs on the seeded copy (3-pass : H -> scratchH,
     *    V -> scratchV, composite -> intermediate).
     *  - The composite slot ships a `Blend(shadowColor, kSrcIn)`
     *    color filter that masks the blurred RGB out and keeps the
     *    blurred alpha tinted to the shadow colour (premul).
     *  - The composite uses `dstOrigin = (sdx, sdy)` to offset the
     *    shadow by the integer-rounded DropShadow displacement.
     *  - `mode = kDstOver` so the shadow lands BEHIND the existing
     *    seed (which holds the parent pixels). The shadow shows
     *    through transparent regions of the seed -- e.g. when the
     *    layer rect extends past opaque parent content, mirroring
     *    upstream `SkDropShadowImageFilter::filterImage` semantics.
     *
     * Tile mode for the blur is forced to kDecal -- the shadow alpha
     * falls off to zero outside the layer rect, so the kernel sees a
     * decaled silhouette (matches the `enqueueDropShadowLayerComposite`
     * choice for the `paint.imageFilter = DropShadow` path).
     *
     * The read-after-write hazard between the copy-seed (writes
     * `intermediateView`) and the blur's H pass (reads
     * `intermediateView`) is naturally serialised : both draws are
     * separate render passes in [encodePendingDrawsToIntermediate],
     * dispatched in `pending` order. Likewise the V scratch read in
     * the final composite is decoupled from the composite's write to
     * `intermediateView` (different textures).
     */
    private fun enqueueBackdropDropShadowSeed(
        width: Int, height: Int,
        dx: Float, dy: Float,
        sigmaX: Float, sigmaY: Float,
        // `SkColor` is `Int` (see math/SkColor.kt) -- the ushr below
        // unpacks the ARGB nibbles.
        shadowColor: Int,
    ) {
        val unboundedRadiusX = if (sigmaX > 0f) {
            ceil(3.0 * sigmaX).toInt().coerceAtLeast(1)
        } else 0
        val unboundedRadiusY = if (sigmaY > 0f) {
            ceil(3.0 * sigmaY).toInt().coerceAtLeast(1)
        } else 0
        val radiusX = unboundedRadiusX.coerceAtMost(MAX_BLUR_RADIUS)
        val radiusY = unboundedRadiusY.coerceAtMost(MAX_BLUR_RADIUS)
        val kernelX = if (radiusX > 0) {
            buildSymmetricGaussianHalfKernel(sigmaX, radiusX)
        } else floatArrayOf(1f)
        val kernelY = if (radiusY > 0) {
            buildSymmetricGaussianHalfKernel(sigmaY, radiusY)
        } else floatArrayOf(1f)

        // Integer-round the shadow displacement -- same rounding the
        // CPU raster's SkDropShadowImageFilter uses (and the existing
        // [enqueueDropShadowLayerComposite] for paint.imageFilter).
        val sdx = floor(dx + 0.5f).toInt()
        val sdy = floor(dy + 0.5f).toInt()

        // Pack the shadow tint as Blend(shadowColor, kSrcIn) -- the
        // composite shader masks the blurred RGB out and keeps only
        // the blurred alpha multiplied by the shadow colour (premul),
        // matching upstream SkDropShadow semantics.
        val ca = ((shadowColor ushr 24) and 0xFF) / 255f
        val crNonPre = ((shadowColor ushr 16) and 0xFF) / 255f
        val cgNonPre = ((shadowColor ushr 8) and 0xFF) / 255f
        val cbNonPre = (shadowColor and 0xFF) / 255f
        val tintPacked = FloatArray(24)
        tintPacked[0] = 1f // kind = 1 (Blend)
        tintPacked[1] = SkBlendMode.kSrcIn.ordinal.toFloat()
        tintPacked[4] = crNonPre * ca // premul R
        tintPacked[5] = cgNonPre * ca // premul G
        tintPacked[6] = cbNonPre * ca // premul B
        tintPacked[7] = ca            // alpha

        val scratchH = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = width.toUInt(), height = height.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.backdropDropShadowScratchH",
            ),
        )
        val scratchHView = scratchH.createView()
        val scratchV = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = width.toUInt(), height = height.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.backdropDropShadowScratchV",
            ),
        )
        val scratchVView = scratchV.createView()

        pending.add(
            BlurredLayerCompositeDraw(
                layerView = intermediateView,
                layerWidth = width, layerHeight = height,
                scratchHTexture = scratchH, scratchHView = scratchHView,
                scratchVTexture = scratchV, scratchVView = scratchVView,
                // Composite offset by the integer-rounded shadow
                // displacement. Out-of-bounds samples on the V scratch
                // fall outside the scratch extent and the composite
                // shader's textureLoad returns the implicit clamp ;
                // the scissor below culls the off-rect pixels back to
                // the layer's footprint anyway.
                dstOriginX = sdx, dstOriginY = sdy,
                scissor = intArrayOf(0, 0, width, height),
                kernelX = kernelX, radiusX = radiusX,
                kernelY = kernelY, radiusY = radiusY,
                tileModeOrdinal = SkTileMode.kDecal.ordinal,
                paintR = 1f, paintG = 1f, paintB = 1f, paintA = 1f,
                colorFilterPacked = tintPacked,
                preBlurColorFilterPacked = null,
                scratchPreCfTexture = null,
                scratchPreCfView = null,
                r = 1f, g = 1f, b = 1f, a = 1f,
                // kDstOver : shadow lands BEHIND existing seed pixels.
                // The seed already holds opaque parent content where
                // the parent is opaque, so the shadow shows through
                // transparent seed regions only (matches the upstream
                // DropShadowImageFilter::filterImage semantic of "the
                // shadow is a separate layer composited under the
                // source").
                mode = SkBlendMode.kDstOver,
            ),
        )
    }

    /**
     * L2b helper -- enqueue a single [LayerCompositeDraw] that seeds
     * `this` device's intermediate from [gpuParent]'s intermediate
     * through a user-supplied 2x3 affine matrix [params.matrix]. The
     * affine is the upstream `SkImageFilters.MatrixTransform` filter,
     * which applies `M` to the input image (here the parent's snapshot
     * in the layer's bbox). The composite shader receives the inverse
     * `M^{-1}` (with the parent origin baked into the translation
     * slots) plus the sampling-mode selector, and walks the child's
     * scissor box one fragment at a time.
     *
     * Math :
     *  - The shader fragment at child-device px `(cx, cy)` evaluates
     *    `u = a*cx + b*cy + c`, `v = d*cx + e*cy + f` (the inverse 2x3
     *    dot-product path -- same as [enqueueMatrixTransformLayerComposite],
     *    just sourced from the parent's intermediate this time).
     *  - We want `(u, v)` to land at the parent texel the backdrop's
     *    `M(input)` would produce for output px `(cx, cy)` -- i.e.
     *    `M^{-1}(cx, cy) + (originX, originY)` (the `+ origin` shift
     *    converts layer-space coords back to parent-device px so the
     *    `textureLoad` reads the right parent pixel).
     *  - So the packed translation is `c = M^{-1}.tx + originX`,
     *    `f = M^{-1}.ty + originY`. The 2x2 (a, b, d, e) stays the
     *    bare inverse 2x2.
     *
     * Layer dims passed to the draw are the PARENT's full intermediate
     * extent (`gpuParent.width / height`) so the shader's kDecal
     * `layer_load` clamp returns transparent black for `(u, v)` outside
     * the parent's footprint -- this matches the CPU raster's
     * "transparent black backdrop padding" behaviour (see
     * `SkCanvas::seedLayerFromBackdrop`).
     *
     * Scissor is the axis-aligned bbox of `M([0, 0, w, h])` clamped to
     * the child's full extent : the backdrop only writes where the
     * MatrixTransform's output footprint hits the layer rect. Outside
     * the scissor the child's transparent clear survives, matching the
     * CPU semantic (the MatrixTransform output has zero alpha outside
     * `M(input bounds)`).
     *
     * Blend mode is `kSrc` (REPLACE the transparent clear) -- same as
     * the plain copy-only seed path. Subsequent user draws inside the
     * layer scope then composite ON TOP via `loadOp = Load`.
     */
    private fun enqueueBackdropMatrixTransformSeed(
        gpuParent: SkWebGpuDevice,
        originX: Int, originY: Int,
        width: Int, height: Int,
        params: org.skia.foundation.SkMatrixTransformImageFilterParams,
        invMatrix: org.graphiks.math.SkMatrix,
    ) {
        val samplingModeOrdinal = when (params.sampling.filter) {
            SkFilterMode.kNearest -> 1
            SkFilterMode.kLinear -> 2
        }

        // Bake the parent origin shift into the inverse translation
        // slots : the shader's `c / f` slots receive `M^{-1}.tx +
        // originX / M^{-1}.ty + originY` so the final sample coord is
        // `M^{-1}(cx, cy) + (originX, originY)` -- i.e. the parent
        // texel that maps onto the child fragment under the backdrop's
        // affine. Mirrors the `c = inv.tx - a*origin - b*origin` baking
        // in [enqueueMatrixTransformLayerComposite], but with a `+`
        // sign because the seed reverses the relationship (the source
        // is the PARENT, not the layer, so the origin shifts FROM layer
        // space TO parent space rather than the other way around).
        val matrixPacked = FloatArray(12)
        matrixPacked[0] = invMatrix.sx
        matrixPacked[1] = invMatrix.kx
        matrixPacked[2] = invMatrix.tx + originX
        matrixPacked[4] = invMatrix.ky
        matrixPacked[5] = invMatrix.sy
        matrixPacked[6] = invMatrix.ty + originY
        matrixPacked[8] = samplingModeOrdinal.toFloat()

        // Cover-quad scissor in child-device pixel coords. The output
        // footprint is `M([0..w] × [0..h])` (the backdrop's mapped
        // input rect), clamped to the child's full extent. Floor / ceil
        // matches the integer-grid convention used by
        // [enqueueMatrixTransformLayerComposite] above.
        val mappedRect = params.matrix.mapRect(
            org.graphiks.math.SkRect.MakeLTRB(0f, 0f, width.toFloat(), height.toFloat()),
        )
        val ix0 = floor(mappedRect.left).toInt().coerceAtLeast(0)
        val iy0 = floor(mappedRect.top).toInt().coerceAtLeast(0)
        val ix1 = ceil(mappedRect.right).toInt().coerceAtMost(width)
        val iy1 = ceil(mappedRect.bottom).toInt().coerceAtMost(height)
        if (ix0 >= ix1 || iy0 >= iy1) {
            // Mapped footprint lies entirely outside the child -- the
            // CPU semantic is "transparent black backdrop", which the
            // child's existing transparent clear already provides.
            // Skip the draw rather than enqueuing a zero-area pass.
            return
        }

        pending.add(
            LayerCompositeDraw(
                layerView = gpuParent.intermediateView,
                layerWidth = gpuParent.width,
                layerHeight = gpuParent.height,
                // dstOriginX / dstOriginY are unused on the
                // MatrixTransform path (the shader's identity branch
                // is the only consumer of `dstOriginSize.xy`, and
                // `samplingMode != 0` skips it). We still ship
                // `(0, 0)` -- the seed writes layer-local coords, so
                // any diagnostic readback hits the layer's top-left.
                dstOriginX = 0, dstOriginY = 0,
                scissor = intArrayOf(ix0, iy0, ix1 - ix0, iy1 - iy0),
                paintR = 1f, paintG = 1f, paintB = 1f, paintA = 1f,
                r = 1f, g = 1f, b = 1f, a = 1f,
                mode = SkBlendMode.kSrc,
                colorFilterPacked = FloatArray(24), // identity (kind = 0).
                matrixPacked = matrixPacked,
                imageFilterPacked = FloatArray(12), // identity (kind = 0).
            ),
        )
    }

    /**
     * Phase G-saveLayer — composite a child device's pixels back onto
     * this device, honouring [paint]'s alpha + blendMode. **Direct
     * GPU-to-GPU blit** (Phase G-saveLayer-fast) : drains the child
     * device's pending draws onto its intermediate texture via
     * [flushDrawsOnly], then enqueues a [LayerCompositeDraw] that the
     * parent's flush replays as a fullscreen-quad render pass sampling
     * the child's intermediate via `textureLoad`. No readback, no
     * re-upload -- both textures live on the same WebGPU adapter / queue
     * (the child device was built via [makeLayerDevice], which shares
     * the parent's [context] + [intermediateFormat]).
     *
     * Blend mode is selected through [BlendPlan]. Fixed-function modes
     * use the direct composite pipeline; shader-layer composite modes
     * route through the snapshot/rebind path; unsupported modes refuse
     * with a stable diagnostic.
     *
     * **Constraints.**
     *  - [src] must be a child [SkWebGpuDevice] (same context). A
     *    mismatched backend errors out — the cross-device path is not
     *    in scope.
     *  - Blend modes outside the M7 [BlendPlan] allowlist error out.
     *  - **Colour filter** : honoured for the two upstream variants
     *    the WGSL shader implements -- `SkColorFilters.Blend(colour,
     *    mode)` and `SkColorFilters.Matrix(20 floats)`. Other variants
     *    (compose, lerp, table, sRGB-gamma, luma, working-CS wrapper,
     *    ...) silently fall through with the filter dropped -- same
     *    behaviour as before, scoped follow-ups will widen this set
     *    (Phase G-saveLayer-colorFilter-x). The supported blend modes
     *    for the `Blend` variant are the 15 Porter-Duff modes the WGSL
     *    `blend_premul` helper expresses (kClear...kScreen) ; the rest
     *    fall back to identity in-shader.
     *  - **Image filter** on [paint] : the tree is flattened via
     *    [resolveLayerImageFilterPlan] into a normalized
     *    `[preCF?][Blur?][postCF?]` plan. Supported variants :
     *      - `SkImageFilters.ColorFilter(cf, input = null)` -- routed
     *        through the composite-pass colour filter slot, same code
     *        path as `paint.colorFilter` (Phase G-saveLayer-imageFilter).
     *      - `SkImageFilters.Blur(sigmaX, sigmaY, kClamp / kDecal, input
     *        = null)` -- separable Gaussian via the 3-pass pipeline
     *        (Phase G-saveLayer-imageFilter-blur).
     *      - `SkImageFilters.Offset(dx, dy, input = null)` -- shifts the
     *        composite's `dstOriginSize.xy` -- no new pipeline (Phase
     *        G-saveLayer-imageFilter-offset).
     *      - `SkImageFilters.DropShadow(dx, dy, sigmaX, sigmaY, color,
     *        input = null)` -- 4-pass blur + colorize-via-Blend(color,
     *        kSrcIn) + offset composite + original composite, kSrcOver
     *        only (Phase G-saveLayer-imageFilter-dropshadow).
     *      - `SkImageFilters.Compose(outer, inner)` -- recursive walk
     *        of the chain (Phase G-saveLayer-imageFilter-compose), with
     *        leaves classified as "pre-blur CF" / "Blur" / "post-blur
     *        CF" depending on where they fall. A pre-blur CF triggers
     *        an extra (4th) render pass that applies the colour filter
     *        to the layer texture into a scratch before the Blur reads
     *        from it. Compose where a child is Offset or DropShadow is
     *        deferred -- throws.
     *    Other variants (MatrixTransform, DisplacementMap, Magnifier,
     *    Tile, Crop, Blend, Erode / Dilate, MatrixConvolution, Lighting,
     *    Arithmetic, ...) throw a clear "not yet supported" error. The
     *    single-occupancy rule still applies : `paint.colorFilter` may
     *    not coexist with a CF in the same stage of the Compose chain.
     */
    override fun compositeFrom(
        src: SkDevice,
        originX: Int,
        originY: Int,
        clip: SkIRect,
        paint: SkPaint?,
    ) {
        lastImageFilterRouteForDiagnostics = null
        val gpuSrc = src as? SkWebGpuDevice
            ?: error(
                "SkWebGpuDevice.compositeFrom : source device is " +
                    "${src::class.simpleName} ; GPU composite only consumes " +
                    "SkWebGpuDevice. Cross-backend composite (CPU layer onto " +
                    "GPU root, or vice-versa) is out of scope — keep the " +
                    "layer device backend-matched to its parent."
            )
        if (gpuSrc.context !== context) {
            error(
                "SkWebGpuDevice.compositeFrom : child device's WebGPU " +
                    "context does not match the parent's. The layer texture " +
                    "cannot be sampled across contexts -- ensure the child " +
                    "was built via makeLayerDevice() so it inherits the " +
                    "parent's context."
            )
        }
        val mode = paint?.blendMode ?: SkBlendMode.kSrcOver
        // M7 BlendPlan -- the fixed-function subset goes
        // through the fast `LayerCompositeDraw` path (no snapshot, no
        // in-shader blend). The shader-layer composite subset implemented
        // by `layer_composite_blend.wgsl` (kModulate / kScreen / kDarken /
        // kLighten / kDifference / kExclusion / kMultiply)
        // runs through the snapshot-and-rebind in-shader blend path. Any
        // other mode (kOverlay, kHardLight, kColorDodge, kColorBurn,
        // kSoftLight, HSL, ...) is deferred.
        val blendPlan = selectLayerCompositeBlendPlan(mode)
        if (blendPlan.kind == BlendPlan.Kind.RefuseDiagnostic) {
            error(blendPlan.reason)
        }
        val nonNativeBlend = blendPlan.isShaderLayerComposite

        // Phase G-saveLayer-imageFilter-crop/-tile/-magnifier -- pure
        // UV-remap variants that fold into the composite fragment shader
        // without any scratch pass. We detect them BEFORE the Compose-
        // tree resolver runs (which would otherwise throw on these
        // leaves) and route through the existing LayerCompositeDraw
        // plumbing with a packed [imageFilterPacked] payload. Only
        // top-level (non-Compose) occurrences with `input == null` and
        // no paint.colorFilter ride this path -- mixing with Compose /
        // ColorFilter / Blur / Offset / DropShadow / paint.colorFilter
        // would need cross-pass coordination that the first slice
        // doesn't ship.
        //
        // Rectangles in [paint.imageFilter] sit in DEVICE-space pixel
        // coords (upstream Skia convention). The shader operates in
        // LAYER-local pixel coords (after `dstOrigin` subtraction), so
        // we translate the rect coordinates by `-(originX, originY)`
        // here, where the device-to-layer offset is in scope.
        val imageFilterPackedEarly = computeImageFilterUvRemapPayload(paint)
        if (imageFilterPackedEarly != null) {
            // Translate the two RectA / RectB slots from device-space
            // into layer-local pixel space by subtracting (originX,
            // originY). The kind / tileMode / zoom / inset payload
            // (slots 0..3) is coord-free and stays unchanged.
            val ox = originX.toFloat()
            val oy = originY.toFloat()
            imageFilterPackedEarly[4]  -= ox
            imageFilterPackedEarly[5]  -= oy
            imageFilterPackedEarly[6]  -= ox
            imageFilterPackedEarly[7]  -= oy
            imageFilterPackedEarly[8]  -= ox
            imageFilterPackedEarly[9]  -= oy
            imageFilterPackedEarly[10] -= ox
            imageFilterPackedEarly[11] -= oy
            val w0 = gpuSrc.width
            val h0 = gpuSrc.height
            gpuSrc.flushDrawsOnly()
            val ix0e = originX.coerceAtLeast(clip.left).coerceAtLeast(0)
            val iy0e = originY.coerceAtLeast(clip.top).coerceAtLeast(0)
            val ix1e = (originX + w0).coerceAtMost(clip.right).coerceAtMost(width)
            val iy1e = (originY + h0).coerceAtMost(clip.bottom).coerceAtMost(height)
            if (ix0e >= ix1e || iy0e >= iy1e) return
            val paintAlphaE = (paint?.alpha ?: 0xFF) / 255f
            pending.add(
                LayerCompositeDraw(
                    layerView = gpuSrc.intermediateView,
                    layerWidth = w0, layerHeight = h0,
                    dstOriginX = originX, dstOriginY = originY,
                    scissor = intArrayOf(ix0e, iy0e, ix1e - ix0e, iy1e - iy0e),
                    paintR = paintAlphaE, paintG = paintAlphaE,
                    paintB = paintAlphaE, paintA = paintAlphaE,
                    r = 1f, g = 1f, b = 1f, a = paintAlphaE,
                    mode = mode,
                    colorFilterPacked = FloatArray(24),
                    matrixPacked = IDENTITY_LAYER_MATRIX_12,
                    imageFilterPacked = imageFilterPackedEarly,
                ),
            )
            return
        }

        val cropNonNullOffsetPrePass = resolveCropNonNullOffsetPrePassPlan(paint)
        if (cropNonNullOffsetPrePass != null) {
            if (nonNativeBlend) {
                error(
                    "SkWebGpuDevice.compositeFrom : paint.imageFilter routes " +
                        "through webgpu.image-filter.crop-nonnull.prepass." +
                        "offset-child but the layer paint's blendMode is $mode. " +
                        "Combining the Crop(input = nonNull) pre-pass with a " +
                        "non-native layer blend mode is deferred -- the first " +
                        "M38 slice materialises the child and then composites " +
                        "through the fixed-function layer path only."
                )
            }
            val w0 = gpuSrc.width
            val h0 = gpuSrc.height
            val ix0e = originX.coerceAtLeast(clip.left).coerceAtLeast(0)
            val iy0e = originY.coerceAtLeast(clip.top).coerceAtLeast(0)
            val ix1e = (originX + w0).coerceAtMost(clip.right).coerceAtMost(width)
            val iy1e = (originY + h0).coerceAtMost(clip.bottom).coerceAtMost(height)
            if (ix0e >= ix1e || iy0e >= iy1e) return

            gpuSrc.flushDrawsOnly()
            val childScratch = context.device.createTexture(
                TextureDescriptor(
                    size = Extent3D(width = w0.toUInt(), height = h0.toUInt()),
                    format = intermediateFormat,
                    usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                    label = "SkWebGpuDevice.cropNonNullOffsetChildPrePassScratch",
                ),
            )
            val childScratchView = childScratch.createView()

            if (shouldProbeFor247CropOffsetScratch(
                    originX = originX,
                    originY = originY,
                    layerWidth = w0,
                    layerHeight = h0,
                    cropNonNullOffsetPrePass = cropNonNullOffsetPrePass,
                )
            ) {
                pending.add(
                    LayerCompositeDraw(
                        layerView = gpuSrc.intermediateView,
                        layerWidth = w0,
                        layerHeight = h0,
                        dstOriginX = -5,
                        dstOriginY = -5,
                        scissor = intArrayOf(0, 0, 1, 1),
                        paintR = 1f,
                        paintG = 1f,
                        paintB = 1f,
                        paintA = 1f,
                        r = 1f,
                        g = 1f,
                        b = 1f,
                        a = 1f,
                        mode = SkBlendMode.kSrc,
                        colorFilterPacked = FloatArray(24),
                        matrixPacked = IDENTITY_LAYER_MATRIX_12,
                        imageFilterPacked = FloatArray(12),
                    ),
                )
            }

            pending.add(
                LayerCompositeDraw(
                    layerView = gpuSrc.intermediateView,
                    layerWidth = w0,
                    layerHeight = h0,
                    dstOriginX = cropNonNullOffsetPrePass.offsetDx,
                    dstOriginY = cropNonNullOffsetPrePass.offsetDy,
                    scissor = intArrayOf(0, 0, w0, h0),
                    paintR = 1f,
                    paintG = 1f,
                    paintB = 1f,
                    paintA = 1f,
                    r = 1f,
                    g = 1f,
                    b = 1f,
                    a = 1f,
                    mode = SkBlendMode.kSrc,
                    colorFilterPacked = FloatArray(24),
                    matrixPacked = IDENTITY_LAYER_MATRIX_12,
                    imageFilterPacked = FloatArray(12),
                    materializeTargetTexture = childScratch,
                    materializeTargetView = childScratchView,
                ),
            )

            if (shouldProbeFor247CropOffsetScratch(
                    originX = originX,
                    originY = originY,
                    layerWidth = w0,
                    layerHeight = h0,
                    cropNonNullOffsetPrePass = cropNonNullOffsetPrePass,
                )
            ) {
                pending.add(
                    LayerCompositeDraw(
                        layerView = childScratchView,
                        layerWidth = w0,
                        layerHeight = h0,
                        dstOriginX = -44,
                        dstOriginY = -5,
                        scissor = intArrayOf(1, 0, 1, 1),
                        paintR = 1f,
                        paintG = 1f,
                        paintB = 1f,
                        paintA = 1f,
                        r = 1f,
                        g = 1f,
                        b = 1f,
                        a = 1f,
                        mode = SkBlendMode.kSrc,
                        colorFilterPacked = FloatArray(24),
                        matrixPacked = IDENTITY_LAYER_MATRIX_12,
                        imageFilterPacked = FloatArray(12),
                    ),
                )
            }

            val cropPacked = packCropImageFilterPayload(
                cropNonNullOffsetPrePass.cropRect,
                cropNonNullOffsetPrePass.cropTileMode,
            )
            // The selected M38 shape runs under drawRect's implicit
            // saveLayer. That saveLayer already shifts the CTM by the
            // layer origin, so Crop(rect) is in layer-local pixels here.
            // Subtracting originX/originY again double-compensates
            // translated GM cells and incorrectly decals the crop output.

            val paintAlphaE = (paint?.alpha ?: 0xFF) / 255f
            if (shouldProbeFor248FinalCropComposite(
                    originX = originX,
                    originY = originY,
                    layerWidth = w0,
                    layerHeight = h0,
                    cropNonNullOffsetPrePass = cropNonNullOffsetPrePass,
                )
            ) {
                pending.add(
                    LayerCompositeDraw(
                        layerView = childScratchView,
                        layerWidth = w0,
                        layerHeight = h0,
                        dstOriginX = -43,
                        dstOriginY = -5,
                        scissor = intArrayOf(2, 0, 1, 1),
                        paintR = 1f,
                        paintG = 1f,
                        paintB = 1f,
                        paintA = 1f,
                        r = 1f,
                        g = 1f,
                        b = 1f,
                        a = 1f,
                        mode = SkBlendMode.kSrc,
                        colorFilterPacked = FloatArray(24),
                        matrixPacked = IDENTITY_LAYER_MATRIX_12,
                        imageFilterPacked = FloatArray(12),
                    ),
                )
                pending.add(
                    LayerCompositeDraw(
                        layerView = childScratchView,
                        layerWidth = w0,
                        layerHeight = h0,
                        dstOriginX = -42,
                        dstOriginY = -5,
                        scissor = intArrayOf(3, 0, 1, 1),
                        paintR = paintAlphaE,
                        paintG = paintAlphaE,
                        paintB = paintAlphaE,
                        paintA = paintAlphaE,
                        r = 1f,
                        g = 1f,
                        b = 1f,
                        a = paintAlphaE,
                        mode = SkBlendMode.kSrc,
                        colorFilterPacked = FloatArray(24),
                        matrixPacked = IDENTITY_LAYER_MATRIX_12,
                        imageFilterPacked = cropPacked,
                    ),
                )
            }
            pending.add(
                LayerCompositeDraw(
                    layerView = childScratchView,
                    layerWidth = w0,
                    layerHeight = h0,
                    dstOriginX = originX,
                    dstOriginY = originY,
                    scissor = intArrayOf(ix0e, iy0e, ix1e - ix0e, iy1e - iy0e),
                    paintR = paintAlphaE,
                    paintG = paintAlphaE,
                    paintB = paintAlphaE,
                    paintA = paintAlphaE,
                    r = 1f,
                    g = 1f,
                    b = 1f,
                    a = paintAlphaE,
                    mode = mode,
                    colorFilterPacked = FloatArray(24),
                    matrixPacked = IDENTITY_LAYER_MATRIX_12,
                    imageFilterPacked = cropPacked,
                ),
            )
            return
        }

        // Phase G-saveLayer-imageFilter-compose -- walk the paint's
        // imageFilter tree (possibly Compose-wrapped) into a normalized
        // plan of "[pre-blur CF][Blur?][post-blur CF folded with
        // paint.colorFilter]". Unsupported leaves throw inside the
        // walker so the call site (saveLayer + restore) surfaces the
        // missing backend support rather than silently dropping the
        // filter. See [resolveLayerImageFilterPlan] for the full set
        // of supported / rejected patterns.
        val plan = resolveLayerImageFilterPlan(paint)
        val selectedM45CfMatrixTransformRoute =
            plan.materialiseChain.size == 1 &&
                plan.materialiseChain.single().matrixTransform != null &&
                !plan.materialiseChain.single().hasBlurCfPrefix &&
                plan.preBlurColorFilter == null &&
                plan.blurParams == null &&
                plan.effectiveColorFilter != null &&
                plan.offsetDx == 0 &&
                plan.offsetDy == 0

        val w = gpuSrc.width
        val h = gpuSrc.height
        // Drain the child's pending draws onto its intermediateTexture.
        // We must not run the child's flush() : that would copy through
        // its identity present pass to the readback target and stage a
        // CPU buffer back -- exactly the round-trip we're killing. The
        // child's intermediateTexture is in the same WebGPU queue as
        // ours, so encoding a render pass that samples it on a later
        // command buffer is well-ordered as long as the child's draws
        // have already been submitted.
        gpuSrc.flushDrawsOnly()

        // N1 -- chain-of-passes : iterate through the materialise chain
        // emitted by [resolveLayerImageFilterPlan], in walk order
        // (inner → outer). For each pre-stage :
        //  - If the stage carries a BlurCF prefix (a Blur / ColorFilter
        //    bundle accumulated BETWEEN the previous materialise leaf and
        //    THIS one in the walk), materialise that BlurCF bundle into a
        //    layer-sized scratch first via [enqueueMaterializeBlurCfToScratch]
        //    (the materialise-mode [BlurredLayerCompositeDraw] writes to
        //    the scratch via `loadOp = Clear` + `mode = kSrc`). That
        //    scratch becomes the leaf's source.
        //  - Materialise the leaf (DropShadow or MatrixTransform) into a
        //    fresh layer-sized scratch via
        //    [enqueueMaterializeDropShadowToScratch] /
        //    [enqueueMaterializeMatrixTransformToScratch], reading from
        //    the current source (the BlurCF prefix scratch OR the
        //    previous stage's output OR the raw layer view for the first
        //    stage with no prefix).
        //  - The leaf's scratch becomes the source for the NEXT stage
        //    (or for the final composite when this is the last stage).
        //
        // Generalises L1a's `innerDropShadow` / L1b's
        // `innerMatrixTransform` single-slot shortcut : the chain handles
        // a single materialise leaf (= L1a/L1b shapes) AND multi-stage
        // chains (= N1 shapes : Compose(DS, Blur), Compose(DS, DS),
        // Compose(DS, MT), Compose(MT, Blur), etc.). Non-invertible MT
        // returns `null` from its materialise helper -- we keep the
        // current source view unchanged (matches the CPU raster's
        // "return input unchanged" degenerate behaviour). The scratch
        // texture lifetimes are managed by the per-stage materialise
        // draws + their [DrawResources] (closed in [closeDrawResources]
        // after the whole pending batch is submitted).
        var innerSourceView: GPUTextureView = gpuSrc.intermediateView
        for (stage in plan.materialiseChain) {
            // Apply the stage's BlurCF prefix (if any) by materialising
            // it into a scratch first.
            if (stage.hasBlurCfPrefix) {
                innerSourceView = enqueueMaterializeBlurCfToScratch(
                    gpuSrc = gpuSrc,
                    w = w, h = h,
                    preBlurColorFilter = stage.preBlurColorFilter,
                    blurParams = stage.blurParams,
                    postBlurColorFilter = stage.postBlurColorFilter,
                    sourceLayerView = innerSourceView,
                )
            }
            // Materialise the terminal leaf.
            innerSourceView = if (stage.dropShadow != null) {
                enqueueMaterializeDropShadowToScratch(
                    gpuSrc = gpuSrc,
                    w = w, h = h,
                    params = stage.dropShadow,
                    sourceLayerView = innerSourceView,
                )
            } else {
                // stage.matrixTransform != null (enforced by
                // MaterialisePreStage.init).
                enqueueMaterializeMatrixTransformToScratch(
                    gpuSrc = gpuSrc,
                    w = w, h = h,
                    params = stage.matrixTransform!!,
                    sourceLayerView = innerSourceView,
                ) ?: innerSourceView // Non-invertible MT : pass through.
            }
        }

        // K1 GPU follow-up to PR #605 -- Offset leaves inside the Compose
        // chain accumulate onto a single dst-origin shift on the final
        // composite. The Blur kernel is fixed-pixel and the per-pixel
        // ColorFilter passes don't sample neighbours, so the cumulative
        // (dx, dy) commutes with all the stages of the normalized
        // `[preCF?][Blur?][postCF?]` plan. We bake the shift into
        // [originX] / [originY] BEFORE clipping so the scissor follows
        // suit ; the top-level Offset early branch below stays as-is
        // (it sees imf.asOffsetImageFilter() != null, which fires only
        // when the layer paint's imageFilter is a pure Offset -- the
        // Compose walker rebuilds the plan with offsetDx/Dy = 0 in
        // that case via the structural top-level guard above).
        val composeShiftedOriginX = originX + plan.offsetDx
        val composeShiftedOriginY = originY + plan.offsetDy

        // Compute the integer dst rect on the parent device, clipped
        // against the caller's [clip] (already intersected with the
        // parent's clip stack by SkCanvas) and the viewport.
        val ix0 = composeShiftedOriginX.coerceAtLeast(clip.left).coerceAtLeast(0)
        val iy0 = composeShiftedOriginY.coerceAtLeast(clip.top).coerceAtLeast(0)
        val ix1 = (composeShiftedOriginX + w).coerceAtMost(clip.right).coerceAtMost(width)
        val iy1 = (composeShiftedOriginY + h).coerceAtMost(clip.bottom).coerceAtMost(height)
        if (ix0 >= ix1 || iy0 >= iy1) return

        // Paint colour scale : alpha (and future colour filter) multiplies
        // the loaded texel. Default = (1, 1, 1, 1) when paint is null.
        // The layer pixels are premul, so we scale all 4 channels by the
        // paint alpha (matches the scaffolding's drawImageRect path which
        // unpremul-then-premul-with-paintAlpha collapsed to the same
        // multiply for premul sources).
        val paintAlpha = (paint?.alpha ?: 0xFF) / 255f

        // Phase G-saveLayer-colorFilter -- pack the post-blur colour
        // filter (or the only colour filter, if no blur is present)
        // into the 6-vec4f payload consumed by `layer_composite.wgsl`.
        // Unsupported variants leave the payload at the identity
        // (kind = 0) so the shader's fast path stays warm.
        val colorFilterPacked = packLayerCompositeColorFilter(plan.effectiveColorFilter)

        // Phase G-saveLayer-imageFilter-blur / -compose -- if the
        // imageFilter tree contains a Blur (with sigma > 0 on either
        // axis), route through the multi-pass blur pipeline. The pass
        // count is 3 when there is no pre-blur CF (H, V, composite) ;
        // 4 when a pre-blur CF is present (preCF, H, V, composite).
        val blurParams = plan.blurParams
        if (blurParams != null &&
            (blurParams.sigmaX > 0f || blurParams.sigmaY > 0f)
        ) {
            if (nonNativeBlend) {
                error(
                    "SkWebGpuDevice.compositeFrom : paint.imageFilter is a " +
                        "SkImageFilters.Blur AND the layer paint's blendMode " +
                        "is $mode. Combining a Blur image-filter with a " +
                        "non-native blend mode is deferred (Phase " +
                        "G-saveLayer-blend) -- the blur path composites " +
                        "via the fixed-function blend pipeline ; routing " +
                        "the blur output through the in-shader blend path " +
                        "needs a separate plumbing slice."
                )
            }
            enqueueBlurredLayerComposite(
                gpuSrc = gpuSrc,
                w = w, h = h,
                originX = composeShiftedOriginX, originY = composeShiftedOriginY,
                scissor = intArrayOf(ix0, iy0, ix1 - ix0, iy1 - iy0),
                sigmaX = blurParams.sigmaX,
                sigmaY = blurParams.sigmaY,
                tileMode = blurParams.tileMode,
                paintAlpha = paintAlpha,
                colorFilterPacked = colorFilterPacked,
                preBlurColorFilter = plan.preBlurColorFilter,
                mode = mode,
                // L1a -- when a DropShadow leaf was materialised above,
                // route the blur's H pass to read from the materialised
                // scratch instead of the raw layer view.
                sourceLayerView = innerSourceView,
            )
            return
        }

        // Phase G-saveLayer-imageFilter-offset -- `SkImageFilters.Offset(
        // dx, dy, input = null)` is a pure UV translation : the layer
        // pixels are unchanged, only the dst origin shifts by (dx, dy).
        // We reuse the plain [LayerCompositeDraw] path with the dst
        // origin and scissor shifted by the integer-rounded offset. No
        // new pipeline, no new shader -- the composite shader's existing
        // `dstOriginSize.xy` slot already drives the parent-pixel
        // mapping. Out-of-bounds samples land outside the integer dst
        // rect and the scissor culls them.
        val offsetParams = paint?.imageFilter?.asOffsetImageFilter()
        if (offsetParams != null) {
            if (offsetParams.input != null) {
                error(
                    "SkWebGpuDevice.compositeFrom : paint.imageFilter is a " +
                        "SkImageFilters.Offset(input = nonNull) with a non-null " +
                        "child filter. Only the input == null case is supported " +
                        "(Phase G-saveLayer-imageFilter-offset) -- a non-null " +
                        "child needs a render-to-texture pre-pass that the " +
                        "WebGPU layer composite pipeline cannot express yet."
                )
            }
            if (nonNativeBlend) {
                error(
                    "SkWebGpuDevice.compositeFrom : paint.imageFilter is a " +
                        "SkImageFilters.Offset AND the layer paint's blendMode " +
                        "is $mode. Combining an Offset image-filter with a " +
                        "non-native blend mode is deferred (Phase " +
                        "G-saveLayer-blend) -- the offset path composites via " +
                        "the fixed-function blend pipeline and would need to " +
                        "shift the in-shader blend's dstOrigin too."
                )
            }
            // Apply the (dx, dy) translation by shifting the dst origin
            // and the scissor by the same integer rounding the CPU
            // raster's `SkOffsetImageFilter.filterImage` applies
            // (`(dx * scale + 0.5).toInt()` with `scale >= 1`). The
            // saveLayer composite runs at the device's identity CTM, so
            // `scale == 1` and the rounding collapses to `floor(dx + 0.5)`.
            val sdx = floor(offsetParams.dx + 0.5f).toInt()
            val sdy = floor(offsetParams.dy + 0.5f).toInt()
            val shiftedOriginX = originX + sdx
            val shiftedOriginY = originY + sdy
            val shiftedIx0 = shiftedOriginX.coerceAtLeast(clip.left).coerceAtLeast(0)
            val shiftedIy0 = shiftedOriginY.coerceAtLeast(clip.top).coerceAtLeast(0)
            val shiftedIx1 = (shiftedOriginX + w).coerceAtMost(clip.right).coerceAtMost(width)
            val shiftedIy1 = (shiftedOriginY + h).coerceAtMost(clip.bottom).coerceAtMost(height)
            if (shiftedIx0 >= shiftedIx1 || shiftedIy0 >= shiftedIy1) return
            pending.add(
                LayerCompositeDraw(
                    layerView = gpuSrc.intermediateView,
                    layerWidth = w, layerHeight = h,
                    dstOriginX = shiftedOriginX, dstOriginY = shiftedOriginY,
                    scissor = intArrayOf(
                        shiftedIx0, shiftedIy0,
                        shiftedIx1 - shiftedIx0, shiftedIy1 - shiftedIy0,
                    ),
                    paintR = paintAlpha, paintG = paintAlpha,
                    paintB = paintAlpha, paintA = paintAlpha,
                    r = 1f, g = 1f, b = 1f, a = paintAlpha,
                    mode = mode,
                    colorFilterPacked = colorFilterPacked,
                    // Phase G-saveLayer-imageFilter-matrixTransform --
                    // Offset is a pure translation expressed via the
                    // composite shader's existing `dstOriginSize.xy`
                    // slot ; no affine UV remap, so the matrix payload
                    // is the identity / off sentinel that flags the
                    // integer-grid `textureLoad` fast path.
                    matrixPacked = IDENTITY_LAYER_MATRIX_12,
                    imageFilterPacked = FloatArray(12),
                ),
            )
            return
        }

        // Phase G-saveLayer-imageFilter-dropshadow -- `SkImageFilters
        // .DropShadow(dx, dy, sigmaX, sigmaY, color, input = null)`
        // renders a colorized blurred copy of the layer (offset by
        // (dx, dy)) BEHIND the original layer content. Two composite
        // sub-passes :
        //   1. shadow : layer alpha -> blur(sigma) -> tint(color, kSrcIn)
        //               -> composite at (originX + sdx, originY + sdy).
        //   2. original : layer RGBA -> composite at (originX, originY)
        //                 with the paint's regular colorFilter / alpha.
        // The user's [mode] is gated to kSrcOver here -- the Skia
        // semantic Compose(srcOver, original) commutes with the parent
        // composite only for kSrcOver. Other modes need an intermediate
        // layer to hold (shadow + original) before applying the user's
        // mode against the parent -- deferred follow-up.
        val dropShadowParams = paint?.imageFilter?.asDropShadowImageFilter()
        if (dropShadowParams != null) {
            if (dropShadowParams.input != null) {
                error(
                    "SkWebGpuDevice.compositeFrom : paint.imageFilter is a " +
                        "SkImageFilters.DropShadow(input = nonNull) with a " +
                        "non-null child filter. Only the input == null case is " +
                        "supported (Phase G-saveLayer-imageFilter-dropshadow) " +
                        "-- a non-null child needs a render-to-texture pre-pass " +
                        "that the WebGPU layer composite pipeline cannot " +
                        "express yet."
                )
            }
            if (mode != SkBlendMode.kSrcOver) {
                error(
                    "SkWebGpuDevice.compositeFrom : paint.imageFilter is a " +
                        "SkImageFilters.DropShadow but the layer paint's " +
                        "blendMode is $mode. Only kSrcOver is supported in " +
                        "the first DropShadow slice (Phase " +
                        "G-saveLayer-imageFilter-dropshadow) -- other modes " +
                        "need an intermediate layer to hold the (shadow + " +
                        "original) composite before applying the user's mode " +
                        "against the parent, which is a follow-up slice."
                )
            }
            enqueueDropShadowLayerComposite(
                gpuSrc = gpuSrc,
                w = w, h = h,
                originX = originX, originY = originY,
                clip = clip,
                params = dropShadowParams,
                paintAlpha = paintAlpha,
                colorFilterPacked = colorFilterPacked,
            )
            return
        }

        // Phase G-saveLayer-imageFilter-matrixTransform -- `SkImageFilters
        // .MatrixTransform(matrix, sampling, input = null)` applies an
        // arbitrary 2x3 affine to the layer pixels before composite. We
        // pack the inverse 2x3 into the composite uniform's matrix payload
        // and let the fragment shader sample the layer texture per the
        // selected SkFilterMode (kNearest / kLinear). The cover-quad
        // geometry covers the bbox of the matrix-mapped layer rect (the
        // four corners of `(0, 0)..(w, h)` mapped through the user matrix
        // and offset by the layer's origin in parent-device pixels).
        //
        // Perspective rows are out of scope (the shader's vec3 dot-product
        // path covers 2x3 affine only -- a 3x3 with non-trivial bottom
        // row would need a homogeneous divide that the first slice ships
        // without). Cubic sampling is also deferred -- the shader only
        // implements kNearest / kLinear (same as `drawImageRect`'s cubic
        // deferral).
        val matrixTransformParams = paint?.imageFilter?.asMatrixTransformImageFilter()
        if (matrixTransformParams != null) {
            enqueueMatrixTransformLayerComposite(
                gpuSrc = gpuSrc,
                w = w, h = h,
                originX = originX, originY = originY,
                clip = clip,
                params = matrixTransformParams,
                paintAlpha = paintAlpha,
                colorFilterPacked = colorFilterPacked,
                mode = mode,
            )
            return
        }

        // No blur (or sigma == 0). A pre-blur CF from the Compose tree
        // collapses to the post-blur slot when there is no blur ; the
        // resolver folded both into `effectiveColorFilter` above.
        // Defensive : if the resolver ever leaves a stray preBlurCF
        // without a blur, surface it as an error rather than dropping
        // the filter.
        if (plan.preBlurColorFilter != null) {
            error(
                "SkWebGpuDevice.compositeFrom : internal -- pre-blur " +
                    "colour filter present without a Blur. The plan resolver " +
                    "should have folded it into effectiveColorFilter."
            )
        }
        if (nonNativeBlend) {
            // Phase G-saveLayer-blend -- non-natively-blendable mode
            // routes through the in-shader blend pipeline. The dispatch
            // expands this entry into a snapshot pass (parent intermediate
            // -> snapshot scratch) followed by the blend composite (layer
            // + snapshot -> in-shader blend -> parent intermediate). The
            // snapshot texture is allocated here so its lifetime aligns
            // with the draw ; [closeDrawResources] releases it after
            // submission.
            pending.add(
                NonNativeBlendLayerCompositeDraw(
                    // L1a -- source the materialised scratch when an
                    // inner DropShadow ran above ; else the raw layer view.
                    layerView = innerSourceView,
                    layerWidth = w, layerHeight = h,
                    dstOriginX = composeShiftedOriginX, dstOriginY = composeShiftedOriginY,
                    scissor = intArrayOf(ix0, iy0, ix1 - ix0, iy1 - iy0),
                    paintR = paintAlpha, paintG = paintAlpha,
                    paintB = paintAlpha, paintA = paintAlpha,
                    r = 1f, g = 1f, b = 1f, a = paintAlpha,
                    mode = mode,
                    colorFilterPacked = colorFilterPacked,
                ),
            )
            return
        }
        pending.add(
            LayerCompositeDraw(
                // L1a -- source the materialised scratch when an inner
                // DropShadow ran above ; else the raw layer view.
                layerView = innerSourceView,
                layerWidth = w, layerHeight = h,
                dstOriginX = composeShiftedOriginX, dstOriginY = composeShiftedOriginY,
                scissor = intArrayOf(ix0, iy0, ix1 - ix0, iy1 - iy0),
                paintR = paintAlpha, paintG = paintAlpha,
                paintB = paintAlpha, paintA = paintAlpha,
                r = 1f, g = 1f, b = 1f, a = paintAlpha,
                mode = mode,
                colorFilterPacked = colorFilterPacked,
                // Phase G-saveLayer-imageFilter-matrixTransform -- no
                // imageFilter on this path : ship the identity matrix
                // payload so the shader takes the integer-grid fast
                // path (bit-iso with the pre-MatrixTransform slice).
                matrixPacked = IDENTITY_LAYER_MATRIX_12,
                imageFilterPacked = FloatArray(12),
            ),
        )
        if (selectedM45CfMatrixTransformRoute) {
            lastImageFilterRouteForDiagnostics = ImageFilterRouteDiagnostics(
                selectedRoute = "webgpu.image-filter.compose.cf-matrix-transform.final-color-filter-composite",
                prepassRoute = "webgpu.image-filter.compose.cf-matrix-transform.materialize-matrix",
                scratchOwner = "LayerCompositeDraw.materializeTargetTexture",
                scratchLifetime = "per-composite-dispatch",
                materialiseStages = 1,
                fallbackReason = null,
            )
        }
    }

    /**
     * Phase G-saveLayer-imageFilter-blur -- helper for [compositeFrom].
     * Allocates the two scratch textures (H and V passes), pre-computes
     * the per-axis Gaussian half-kernels (matches the MaskFilter blur's
     * [buildSymmetricGaussianHalfKernel]), and enqueues a single
     * [BlurredLayerCompositeDraw] that the dispatch loop expands into
     * three render passes.
     *
     * Sigma 0 on a given axis -> radius 0 (centre tap only, weight 1) :
     * the convolution along that axis is the identity. We still run
     * the pass for layout simplicity ; the cost is a single textureLoad
     * per pixel and the output is bit-iso with the non-blurred sample.
     */
    private fun enqueueBlurredLayerComposite(
        gpuSrc: SkWebGpuDevice,
        w: Int, h: Int,
        originX: Int, originY: Int,
        scissor: IntArray,
        sigmaX: Float, sigmaY: Float,
        tileMode: SkTileMode,
        paintAlpha: Float,
        colorFilterPacked: FloatArray,
        // Phase G-saveLayer-imageFilter-compose -- optional pre-blur
        // ColorFilter (from a Compose chain). `null` -> 3-pass pipeline
        // (H, V, composite). Non-null -> 4-pass pipeline (preCF, H, V,
        // composite) ; the preCF pass runs `layer_composite.wgsl` with
        // kSrc blend on the layer texture into a fresh scratch, then
        // the blur reads from that scratch.
        preBlurColorFilter: org.skia.foundation.SkColorFilter?,
        mode: SkBlendMode,
        // L1a -- the texture the blur's H pass samples from. Default is
        // `gpuSrc.intermediateView` (raw layer pixels). When a DropShadow
        // materialise pre-pass ran (Phase L1a), the caller substitutes the
        // materialised scratch's view here so the blur consumes the
        // shadowed result instead.
        sourceLayerView: GPUTextureView = gpuSrc.intermediateView,
    ) {
        if (!sigmaX.isFinite() || !sigmaY.isFinite() || sigmaX < 0f || sigmaY < 0f) {
            error(
                "SkWebGpuDevice.compositeFrom : SkImageFilters.Blur sigma " +
                    "must be finite and non-negative ; got (sigmaX = $sigmaX, " +
                    "sigmaY = $sigmaY)."
            )
        }
        val unboundedRadiusX = if (sigmaX > 0f) {
            ceil(3.0 * sigmaX).toInt().coerceAtLeast(1)
        } else 0
        val unboundedRadiusY = if (sigmaY > 0f) {
            ceil(3.0 * sigmaY).toInt().coerceAtLeast(1)
        } else 0
        val radiusX = unboundedRadiusX.coerceAtMost(MAX_BLUR_RADIUS)
        val radiusY = unboundedRadiusY.coerceAtMost(MAX_BLUR_RADIUS)
        val kernelX = if (radiusX > 0) {
            buildSymmetricGaussianHalfKernel(sigmaX, radiusX)
        } else floatArrayOf(1f)
        val kernelY = if (radiusY > 0) {
            buildSymmetricGaussianHalfKernel(sigmaY, radiusY)
        } else floatArrayOf(1f)

        // Allocate two scratch textures of the same dimensions as the
        // layer texture. Both are colour-attachment + texture-binding
        // usage : the H pass writes scratchH (sampled by the V pass) ;
        // the V pass writes scratchV (sampled by the composite pass).
        val scratchH = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = w.toUInt(), height = h.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.blurImageFilterScratchH",
            ),
        )
        val scratchHView = scratchH.createView()
        val scratchV = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = w.toUInt(), height = h.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.blurImageFilterScratchV",
            ),
        )
        val scratchVView = scratchV.createView()

        // Phase G-saveLayer-imageFilter-compose -- allocate the pre-CF
        // scratch only when needed. The Blur H pass reads from this
        // texture (instead of the raw layer view) when a pre-blur CF is
        // present.
        val preCfScratch: GPUTexture?
        val preCfScratchView: GPUTextureView?
        val preCfPacked: FloatArray?
        if (preBlurColorFilter != null) {
            preCfScratch = context.device.createTexture(
                TextureDescriptor(
                    size = Extent3D(width = w.toUInt(), height = h.toUInt()),
                    format = intermediateFormat,
                    usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                    label = "SkWebGpuDevice.blurImageFilterScratchPreCf",
                ),
            )
            preCfScratchView = preCfScratch.createView()
            preCfPacked = packLayerCompositeColorFilter(preBlurColorFilter)
        } else {
            preCfScratch = null
            preCfScratchView = null
            preCfPacked = null
        }

        pending.add(
            BlurredLayerCompositeDraw(
                layerView = sourceLayerView,
                layerWidth = w, layerHeight = h,
                scratchHTexture = scratchH, scratchHView = scratchHView,
                scratchVTexture = scratchV, scratchVView = scratchVView,
                dstOriginX = originX, dstOriginY = originY,
                scissor = scissor,
                kernelX = kernelX, radiusX = radiusX,
                kernelY = kernelY, radiusY = radiusY,
                tileModeOrdinal = tileMode.ordinal,
                paintR = paintAlpha, paintG = paintAlpha,
                paintB = paintAlpha, paintA = paintAlpha,
                colorFilterPacked = colorFilterPacked,
                preBlurColorFilterPacked = preCfPacked,
                scratchPreCfTexture = preCfScratch,
                scratchPreCfView = preCfScratchView,
                r = 1f, g = 1f, b = 1f, a = paintAlpha,
                mode = mode,
            ),
        )
    }

    /**
     * Phase G-saveLayer-imageFilter-dropshadow -- helper for
     * [compositeFrom]. Allocates the two scratch textures (H and V
     * blur), pre-computes the per-axis Gaussian half-kernels, packs the
     * shadow-pass colour filter as `Blend(shadowColor, kSrcIn)` (the
     * colorize-from-alpha step), and enqueues a single
     * [DropShadowLayerCompositeDraw] that the dispatch loop expands into
     * four render passes.
     *
     * Sigma constraints mirror [enqueueBlurredLayerComposite] -- the
     * radius is clamped to [MAX_BLUR_RADIUS] and the kernel is
     * renormalised after the clamp. The blur tile mode is forced to
     * kDecal (transparent border) -- a kClamp blur would extend the
     * edge alpha out indefinitely, which doesn't match the upstream
     * SkDropShadowImageFilter semantic.
     */
    private fun enqueueDropShadowLayerComposite(
        gpuSrc: SkWebGpuDevice,
        w: Int, h: Int,
        originX: Int, originY: Int,
        clip: SkIRect,
        params: org.skia.foundation.SkDropShadowImageFilterParams,
        paintAlpha: Float,
        colorFilterPacked: FloatArray,
        // N1 -- chain-of-passes : the source texture this top-level DS
        // composite reads from for its H blur + original sub-passes.
        // Default = the raw layer view (the unchained top-level case).
        // For chained dispatch (e.g. `Compose(DS, Blur)` where the inner
        // Blur materialised into scratch1 first), the caller substitutes
        // that scratch's view so the final-composite DropShadow consumes
        // the chained source.
        sourceLayerView: GPUTextureView = gpuSrc.intermediateView,
    ) {
        if (!params.sigmaX.isFinite() || !params.sigmaY.isFinite() ||
            params.sigmaX < 0f || params.sigmaY < 0f
        ) {
            error(
                "SkWebGpuDevice.compositeFrom : SkImageFilters.DropShadow " +
                    "sigma must be finite and non-negative ; got (sigmaX = " +
                    "${params.sigmaX}, sigmaY = ${params.sigmaY})."
            )
        }
        val unboundedRadiusX = if (params.sigmaX > 0f) {
            ceil(3.0 * params.sigmaX).toInt().coerceAtLeast(1)
        } else 0
        val unboundedRadiusY = if (params.sigmaY > 0f) {
            ceil(3.0 * params.sigmaY).toInt().coerceAtLeast(1)
        } else 0
        val radiusX = unboundedRadiusX.coerceAtMost(MAX_BLUR_RADIUS)
        val radiusY = unboundedRadiusY.coerceAtMost(MAX_BLUR_RADIUS)
        val kernelX = if (radiusX > 0) {
            buildSymmetricGaussianHalfKernel(params.sigmaX, radiusX)
        } else floatArrayOf(1f)
        val kernelY = if (radiusY > 0) {
            buildSymmetricGaussianHalfKernel(params.sigmaY, radiusY)
        } else floatArrayOf(1f)

        // Allocate two scratch textures of the same dimensions as the
        // layer texture -- same shape as [enqueueBlurredLayerComposite].
        val scratchH = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = w.toUInt(), height = h.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.dropShadowScratchH",
            ),
        )
        val scratchHView = scratchH.createView()
        val scratchV = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = w.toUInt(), height = h.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.dropShadowScratchV",
            ),
        )
        val scratchVView = scratchV.createView()

        // Integer-round the shadow displacement -- same rounding the
        // CPU raster's [SkDropShadowImageFilter] uses ([SkOffsetImageFilter]
        // shares this rounding). The saveLayer composite runs at the
        // device's identity CTM, so the `scale >= 1` factor collapses
        // to 1.
        val sdx = floor(params.dx + 0.5f).toInt()
        val sdy = floor(params.dy + 0.5f).toInt()
        val shadowOriginX = originX + sdx
        val shadowOriginY = originY + sdy

        // Original-pass scissor (the layer pixels land at the original
        // origin -- same shape as the no-filter composite path).
        val origIx0 = originX.coerceAtLeast(clip.left).coerceAtLeast(0)
        val origIy0 = originY.coerceAtLeast(clip.top).coerceAtLeast(0)
        val origIx1 = (originX + w).coerceAtMost(clip.right).coerceAtMost(width)
        val origIy1 = (originY + h).coerceAtMost(clip.bottom).coerceAtMost(height)
        // Shadow-pass scissor (the shadow lands at the offset origin --
        // its kernel-spread band is captured by the layer texture's
        // own bounds since the blur runs in layer space, no padding).
        val shadIx0 = shadowOriginX.coerceAtLeast(clip.left).coerceAtLeast(0)
        val shadIy0 = shadowOriginY.coerceAtLeast(clip.top).coerceAtLeast(0)
        val shadIx1 = (shadowOriginX + w).coerceAtMost(clip.right).coerceAtMost(width)
        val shadIy1 = (shadowOriginY + h).coerceAtMost(clip.bottom).coerceAtMost(height)

        // Both passes need a non-empty scissor to do useful work. If
        // the shadow lands entirely outside the parent clip, we still
        // need to draw the original. Skip the shadow pass by collapsing
        // its scissor to (0, 0, 0, 0) ; the dispatch loop honours
        // zero-area scissors (no draw).
        val shadowScissor = if (shadIx0 >= shadIx1 || shadIy0 >= shadIy1) {
            intArrayOf(0, 0, 0, 0)
        } else {
            intArrayOf(shadIx0, shadIy0, shadIx1 - shadIx0, shadIy1 - shadIy0)
        }
        if (origIx0 >= origIx1 || origIy0 >= origIy1) {
            // The original layer is entirely clipped out. Still draw
            // the shadow when its scissor is non-empty. If both are
            // empty, fall through to add nothing.
            if (shadowScissor[2] == 0 || shadowScissor[3] == 0) {
                scratchHView.close(); scratchH.close()
                scratchVView.close(); scratchV.close()
                return
            }
        }
        val originalScissor = if (origIx0 >= origIx1 || origIy0 >= origIy1) {
            intArrayOf(0, 0, 0, 0)
        } else {
            intArrayOf(origIx0, origIy0, origIx1 - origIx0, origIy1 - origIy0)
        }

        // Pack the shadow-pass colour filter as `Blend(shadowColor,
        // kSrcIn)`. Decompose the [SkColor] (ARGB) into non-premul
        // floats, premultiply by the paint alpha (the shadow inherits
        // the paint's alpha modulation -- mirrors the upstream
        // SkDropShadowImageFilter::filterImage which composes its
        // `Blend(SK_ColorBLACK, kSrcIn)` ColorFilterImageFilter into
        // the shadow output before the parent's SrcOver), then premul
        // the colour by its own alpha for the shader's premul-source
        // assumption.
        val shadowColor = params.color
        val ca = (((shadowColor ushr 24) and 0xFF) / 255f) * paintAlpha
        val crNonPre = ((shadowColor ushr 16) and 0xFF) / 255f
        val cgNonPre = ((shadowColor ushr 8) and 0xFF) / 255f
        val cbNonPre = (shadowColor and 0xFF) / 255f
        val shadowColorFilterPacked = FloatArray(24)
        shadowColorFilterPacked[0] = 1f                              // kind = 1 (Blend)
        shadowColorFilterPacked[1] = SkBlendMode.kSrcIn.ordinal.toFloat()
        shadowColorFilterPacked[4] = crNonPre * ca                   // premul R
        shadowColorFilterPacked[5] = cgNonPre * ca                   // premul G
        shadowColorFilterPacked[6] = cbNonPre * ca                   // premul B
        shadowColorFilterPacked[7] = ca                              // alpha

        pending.add(
            DropShadowLayerCompositeDraw(
                layerView = sourceLayerView,
                layerWidth = w, layerHeight = h,
                scratchHTexture = scratchH, scratchHView = scratchHView,
                scratchVTexture = scratchV, scratchVView = scratchVView,
                dstOriginX = originX, dstOriginY = originY,
                shadowDstOriginX = shadowOriginX, shadowDstOriginY = shadowOriginY,
                originalScissor = originalScissor,
                shadowScissor = shadowScissor,
                kernelX = kernelX, radiusX = radiusX,
                kernelY = kernelY, radiusY = radiusY,
                tileModeOrdinal = SkTileMode.kDecal.ordinal,
                shadowColorFilterPacked = shadowColorFilterPacked,
                paintR = paintAlpha, paintG = paintAlpha,
                paintB = paintAlpha, paintA = paintAlpha,
                originalColorFilterPacked = colorFilterPacked,
                r = 1f, g = 1f, b = 1f, a = paintAlpha,
                mode = SkBlendMode.kSrcOver,
            ),
        )
    }

    /**
     * L1a -- render-to-texture pre-pass that materialises a `DropShadow`
     * filter into a layer-sized scratch texture, used by [compositeFrom]
     * when the filter sits INSIDE a Compose tree (rather than at the top
     * level where it dispatches directly onto the parent's intermediate).
     *
     * Allocates the scratch + the two blur H/V scratches, enqueues a
     * [DropShadowLayerCompositeDraw] in **materialise mode** :
     *  - `materializeTargetView` = the new scratch's view
     *  - `dstOriginX/Y` = (0, 0) (the original sits at the top-left of
     *    the scratch -- layer-local)
     *  - `shadowDstOriginX/Y` = (sdx, sdy) (the shadow shifted by the
     *    integer-rounded displacement, layer-local)
     *  - `originalScissor` = (0, 0, w, h) (full layer rect)
     *  - `shadowScissor` = clipped against (0, 0, w, h) (the shadow's
     *    offset rect intersected with the layer footprint -- matches the
     *    upstream `SkDropShadowImageFilter` semantic when running inside
     *    saveLayer : the layer rect bounds the output, the shadow outside
     *    that rect is clipped)
     *  - The dispatch loop forces `loadOp = Clear` + `mode = kSrc` on the
     *    shadow sub-pass and `loadOp = Load` + `mode = kSrcOver` on the
     *    original sub-pass when `materializeTargetView` is non-null.
     *
     * Returns the (texture, view) pair so the caller can :
     *  - Pass the view to downstream Blur / ColorFilter / LayerComposite
     *    enqueue helpers as their `sourceLayerView`
     *  - Keep the texture alive until the consumer draws are submitted
     *    (the texture is registered on the materialise DrawResources and
     *    closed in [closeDrawResources] after the entire `pending` batch
     *    is flushed)
     *
     * Sigma / colour / displacement constraints mirror
     * [enqueueDropShadowLayerComposite] (sigmas must be finite + non-
     * negative, displacement integer-rounded per upstream Skia's
     * `(d + 0.5).toInt()` convention).
     */
    private fun enqueueMaterializeDropShadowToScratch(
        gpuSrc: SkWebGpuDevice,
        w: Int, h: Int,
        params: org.skia.foundation.SkDropShadowImageFilterParams,
        // N1 -- chain-of-passes : the source texture this materialise
        // pre-pass reads from. Default = the raw layer view (the first
        // materialise leaf in the walk). For subsequent materialise
        // leaves in a chain (e.g. `Compose(DS, DS)` or `Compose(DS,
        // Blur)` after the BlurCF pre-stage materialises into scratch1),
        // the caller substitutes the previous stage's output here so the
        // DropShadow consumes the chained source.
        sourceLayerView: GPUTextureView = gpuSrc.intermediateView,
    ): GPUTextureView {
        if (!params.sigmaX.isFinite() || !params.sigmaY.isFinite() ||
            params.sigmaX < 0f || params.sigmaY < 0f
        ) {
            error(
                "SkWebGpuDevice.compositeFrom : a Compose-nested DropShadow's " +
                    "sigma must be finite and non-negative ; got (sigmaX = " +
                    "${params.sigmaX}, sigmaY = ${params.sigmaY})."
            )
        }
        val unboundedRadiusX = if (params.sigmaX > 0f) {
            ceil(3.0 * params.sigmaX).toInt().coerceAtLeast(1)
        } else 0
        val unboundedRadiusY = if (params.sigmaY > 0f) {
            ceil(3.0 * params.sigmaY).toInt().coerceAtLeast(1)
        } else 0
        val radiusX = unboundedRadiusX.coerceAtMost(MAX_BLUR_RADIUS)
        val radiusY = unboundedRadiusY.coerceAtMost(MAX_BLUR_RADIUS)
        val kernelX = if (radiusX > 0) {
            buildSymmetricGaussianHalfKernel(params.sigmaX, radiusX)
        } else floatArrayOf(1f)
        val kernelY = if (radiusY > 0) {
            buildSymmetricGaussianHalfKernel(params.sigmaY, radiusY)
        } else floatArrayOf(1f)

        // Blur H/V scratches : same shape as the top-level DropShadow path.
        val scratchH = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = w.toUInt(), height = h.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.materializeDropShadowScratchH",
            ),
        )
        val scratchHView = scratchH.createView()
        val scratchV = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = w.toUInt(), height = h.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.materializeDropShadowScratchV",
            ),
        )
        val scratchVView = scratchV.createView()

        // The materialised target : holds the (shadow + original)
        // composite in layer-local coords. Sampled by downstream Blur /
        // ColorFilter / LayerComposite draws via the returned view.
        val materializeTarget = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = w.toUInt(), height = h.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.materializeDropShadowTarget",
            ),
        )
        val materializeTargetView = materializeTarget.createView()

        // Integer-round the shadow displacement, layer-local (no parent
        // origin shift here -- the materialised scratch IS layer space).
        val sdx = floor(params.dx + 0.5f).toInt()
        val sdy = floor(params.dy + 0.5f).toInt()

        // Original-pass scissor : full layer rect (layer-local).
        val originalScissor = intArrayOf(0, 0, w, h)
        // Shadow-pass scissor : the shadow's (sdx, sdy)..(sdx+w, sdy+h)
        // intersected with the layer rect (0, 0, w, h). Pixels outside
        // the layer are clipped -- matches the upstream
        // SkDropShadowImageFilter semantic when running inside saveLayer
        // (the layer rect bounds the output ; the shadow that would land
        // outside the layer rect is dropped).
        val shadIx0 = sdx.coerceAtLeast(0)
        val shadIy0 = sdy.coerceAtLeast(0)
        val shadIx1 = (sdx + w).coerceAtMost(w)
        val shadIy1 = (sdy + h).coerceAtMost(h)
        val shadowScissor = if (shadIx0 >= shadIx1 || shadIy0 >= shadIy1) {
            intArrayOf(0, 0, 0, 0)
        } else {
            intArrayOf(shadIx0, shadIy0, shadIx1 - shadIx0, shadIy1 - shadIy0)
        }

        // Shadow colour filter : `Blend(shadowColor, kSrcIn)`. Same
        // packing as [enqueueDropShadowLayerComposite]. The paintAlpha
        // term collapses to 1 here because the OUTER plan's paintAlpha
        // applies on the FINAL composite (when the materialised scratch
        // is consumed) ; the materialised pixels stay at their natural
        // alpha so the outer Blur / ColorFilter operates on the same
        // pixels the CPU raster would see at the DropShadow boundary.
        val shadowColor = params.color
        val ca = ((shadowColor ushr 24) and 0xFF) / 255f
        val crNonPre = ((shadowColor ushr 16) and 0xFF) / 255f
        val cgNonPre = ((shadowColor ushr 8) and 0xFF) / 255f
        val cbNonPre = (shadowColor and 0xFF) / 255f
        val shadowColorFilterPacked = FloatArray(24)
        shadowColorFilterPacked[0] = 1f
        shadowColorFilterPacked[1] = SkBlendMode.kSrcIn.ordinal.toFloat()
        shadowColorFilterPacked[4] = crNonPre * ca
        shadowColorFilterPacked[5] = cgNonPre * ca
        shadowColorFilterPacked[6] = cbNonPre * ca
        shadowColorFilterPacked[7] = ca

        // No colour filter on the original sub-pass -- the outer plan's
        // [effectiveColorFilter] applies on the FINAL composite, not on
        // the materialised pixels.
        val noColorFilter = FloatArray(24)

        pending.add(
            DropShadowLayerCompositeDraw(
                layerView = sourceLayerView,
                layerWidth = w, layerHeight = h,
                scratchHTexture = scratchH, scratchHView = scratchHView,
                scratchVTexture = scratchV, scratchVView = scratchVView,
                // Layer-local origins : the original sits at (0, 0)
                // inside the scratch ; the shadow at (sdx, sdy).
                dstOriginX = 0, dstOriginY = 0,
                shadowDstOriginX = sdx, shadowDstOriginY = sdy,
                originalScissor = originalScissor,
                shadowScissor = shadowScissor,
                kernelX = kernelX, radiusX = radiusX,
                kernelY = kernelY, radiusY = radiusY,
                tileModeOrdinal = SkTileMode.kDecal.ordinal,
                shadowColorFilterPacked = shadowColorFilterPacked,
                // paintAlpha = 1 on the materialised original -- the
                // outer plan handles the layer paint's alpha + colour
                // filter on the FINAL composite (where the materialised
                // scratch is the source).
                paintR = 1f, paintG = 1f, paintB = 1f, paintA = 1f,
                originalColorFilterPacked = noColorFilter,
                // Materialise mode : the dispatch will redirect both
                // sub-passes to [materializeTargetView] instead of the
                // parent's colorView, and force the blend modes /
                // load ops described in the [DropShadowLayerCompositeDraw]
                // kdoc.
                materializeTargetTexture = materializeTarget,
                materializeTargetView = materializeTargetView,
                r = 1f, g = 1f, b = 1f, a = 1f,
                mode = SkBlendMode.kSrcOver,
            ),
        )

        return materializeTargetView
    }

    /**
     * L1b -- render-to-texture pre-pass that materialises a `MatrixTransform`
     * filter into a layer-sized scratch texture, used by [compositeFrom]
     * when the filter sits INSIDE a Compose tree (rather than at the top
     * level where it dispatches directly onto the parent's intermediate
     * via [enqueueMatrixTransformLayerComposite]).
     *
     * Allocates the scratch, enqueues a [LayerCompositeDraw] in
     * **materialise mode** :
     *  - `materializeTargetView` = the new scratch's view
     *  - `dstOriginX/Y` = (0, 0) (the matrix-transformed image sits at the
     *    top-left of the scratch -- layer-local)
     *  - matrix payload : the inverse 2x3 of the user matrix, with NO
     *    parent-origin shift baked in (the layer-local case has `originX
     *    = originY = 0`, so the `c / f` translation slots are just the
     *    bare inverse's `tx / ty`)
     *  - scissor : the axis-aligned bbox of `M([0..w] × [0..h])`,
     *    clamped to the layer rect (layer-local)
     *  - mode : kSrc (the scratch starts blank, the matrix-transformed
     *    image IS the only contribution -- the dispatch forces this)
     *
     * Returns the (texture, view) pair so the caller can :
     *  - Pass the view to downstream Blur / ColorFilter / LayerComposite
     *    enqueue helpers as their `sourceLayerView`
     *  - Keep the texture alive until the consumer draws are submitted
     *    (the texture is registered on the materialise DrawResources and
     *    closed in [closeDrawResources] after the entire `pending` batch
     *    is flushed)
     *
     * Bail conditions mirror [enqueueMatrixTransformLayerComposite] :
     *  - Non-null child filter -- throws (input == null required).
     *  - Perspective matrix -- throws (2x3 affine only).
     *  - Cubic sampling -- throws (kNearest / kLinear only).
     *  - Non-invertible matrix -- returns null (the CPU raster's
     *    `MatrixTransform` returns the input image unchanged in that
     *    case ; mapping that semantic onto a materialise scratch is
     *    a no-op, so we return null and the caller falls back to the
     *    raw layer view as its source).
     */
    private fun enqueueMaterializeMatrixTransformToScratch(
        gpuSrc: SkWebGpuDevice,
        w: Int, h: Int,
        params: org.skia.foundation.SkMatrixTransformImageFilterParams,
        // N1 -- chain-of-passes : same shape as
        // [enqueueMaterializeDropShadowToScratch]. The MatrixTransform
        // pre-pass samples this view (default = raw layer) for the
        // affine remap ; a chained caller substitutes the previous
        // stage's scratch view here.
        sourceLayerView: GPUTextureView = gpuSrc.intermediateView,
    ): GPUTextureView? {
        if (params.input != null) {
            error(
                "SkWebGpuDevice.compositeFrom : a Compose-nested MatrixTransform " +
                    "leaf has a non-null child filter. The Compose support " +
                    "flattens the tree, so leaves must have input == null -- " +
                    "nest the child via a Compose node instead (e.g. " +
                    "SkImageFilters.Compose(MatrixTransform(m, sampling), child) " +
                    "rather than MatrixTransform(m, sampling, input = child))."
            )
        }
        if (params.matrix.hasPerspective()) {
            error(
                "SkWebGpuDevice.compositeFrom : a Compose-nested MatrixTransform " +
                    "leaf has a perspective matrix (non-trivial bottom row). " +
                    "Only 2x3 affine is supported in the L1b slice (Phase " +
                    "G-saveLayer-imageFilter-matrixTransform-compose) -- " +
                    "perspective needs a homogeneous divide in the fragment " +
                    "shader (the current shader uses a vec3 dot-product affine " +
                    "path) and is deferred to a follow-up slice."
            )
        }
        if (params.sampling.cubic != null) {
            error(
                "SkWebGpuDevice.compositeFrom : a Compose-nested MatrixTransform " +
                    "leaf has a cubic resampler. Only kNearest and kLinear are " +
                    "supported in the L1b slice (Phase G-saveLayer-imageFilter-" +
                    "matrixTransform-compose) -- cubic resampling needs a " +
                    "16-tap kernel in the composite shader and is deferred."
            )
        }
        val samplingModeOrdinal = when (params.sampling.filter) {
            SkFilterMode.kNearest -> 1
            SkFilterMode.kLinear -> 2
        }

        // Layer-local inverse : no parent origin shift to bake in (the
        // materialised scratch IS layer space, so `originX = originY = 0`
        // and `c / f` collapse to the bare inverse's `tx / ty`).
        val invMatrix = params.matrix.invert()
            ?: return null  // Non-invertible -- fall back to raw layer view.
        val matrixPacked = FloatArray(12)
        matrixPacked[0] = invMatrix.sx
        matrixPacked[1] = invMatrix.kx
        matrixPacked[2] = invMatrix.tx
        matrixPacked[4] = invMatrix.ky
        matrixPacked[5] = invMatrix.sy
        matrixPacked[6] = invMatrix.ty
        matrixPacked[8] = samplingModeOrdinal.toFloat()

        // Materialised target : holds the matrix-transformed image in
        // layer-local coords. Sampled by downstream Blur / ColorFilter /
        // LayerComposite draws via the returned view.
        val materializeTarget = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = w.toUInt(), height = h.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.materializeMatrixTransformTarget",
            ),
        )
        val materializeTargetView = materializeTarget.createView()

        // Cover-quad scissor in LAYER-LOCAL pixel coords : the axis-
        // aligned bbox of the four corners of the layer rect mapped
        // through the user matrix, clamped to the layer rect (the
        // scratch is layer-sized -- pixels outside the layer rect are
        // dropped, matching the upstream SkMatrixTransformImageFilter
        // semantic when running inside saveLayer).
        val mappedRect = params.matrix.mapRect(
            org.graphiks.math.SkRect.MakeLTRB(0f, 0f, w.toFloat(), h.toFloat()),
        )
        val ix0 = floor(mappedRect.left).toInt().coerceAtLeast(0)
        val iy0 = floor(mappedRect.top).toInt().coerceAtLeast(0)
        val ix1 = ceil(mappedRect.right).toInt().coerceAtMost(w)
        val iy1 = ceil(mappedRect.bottom).toInt().coerceAtMost(h)
        if (ix0 >= ix1 || iy0 >= iy1) {
            // Mapped footprint lies entirely outside the layer rect.
            // The downstream consumers should see a fully-transparent
            // source : return the scratch view as-is (the dispatch's
            // `loadOp = Clear` will leave it transparent). We still
            // need a draw entry on `pending` so the scratch is owned by
            // a [DrawResources] and gets cleaned up after submit ; we
            // ship a zero-area scissor so the draw is a clear-only pass.
            pending.add(
                LayerCompositeDraw(
                    layerView = sourceLayerView,
                    layerWidth = w, layerHeight = h,
                    dstOriginX = 0, dstOriginY = 0,
                    scissor = intArrayOf(0, 0, 0, 0),
                    paintR = 1f, paintG = 1f, paintB = 1f, paintA = 1f,
                    r = 1f, g = 1f, b = 1f, a = 1f,
                    mode = SkBlendMode.kSrc,
                    colorFilterPacked = FloatArray(24),
                    matrixPacked = matrixPacked,
                    imageFilterPacked = FloatArray(12),
                    materializeTargetTexture = materializeTarget,
                    materializeTargetView = materializeTargetView,
                ),
            )
            return materializeTargetView
        }

        pending.add(
            LayerCompositeDraw(
                layerView = sourceLayerView,
                layerWidth = w, layerHeight = h,
                // Layer-local origin : the matrix-transformed image lands
                // inside the layer-sized scratch starting at (0, 0).
                dstOriginX = 0, dstOriginY = 0,
                scissor = intArrayOf(ix0, iy0, ix1 - ix0, iy1 - iy0),
                // paintAlpha = 1 on the materialised image -- the outer
                // plan handles the layer paint's alpha + colour filter
                // on the FINAL composite (where the materialised scratch
                // is the source).
                paintR = 1f, paintG = 1f, paintB = 1f, paintA = 1f,
                r = 1f, g = 1f, b = 1f, a = 1f,
                // Materialise mode forces `kSrc` at the dispatch site
                // regardless of `mode` ; we still ship a sentinel.
                mode = SkBlendMode.kSrc,
                colorFilterPacked = FloatArray(24),
                matrixPacked = matrixPacked,
                imageFilterPacked = FloatArray(12),
                // Materialise mode : the dispatch redirects this draw's
                // render pass to write into the scratch (with `loadOp =
                // Clear`) instead of the parent's `colorView`.
                materializeTargetTexture = materializeTarget,
                materializeTargetView = materializeTargetView,
            ),
        )

        return materializeTargetView
    }

    /**
     * N1 -- chain-of-passes : render-to-texture pre-pass that materialises
     * a `[preBlurCF?][Blur?][postBlurCF?]` bundle into a layer-sized
     * scratch. Used by [compositeFrom] when a BlurCF stage sits BEFORE a
     * materialise leaf in a Compose chain (e.g. `Compose(DropShadow,
     * Blur)` walks Blur first, accumulating it ; then DropShadow needs to
     * consume the BLURRED layer pixels as its source, not the raw layer).
     *
     * The implementation reuses [enqueueBlurredLayerComposite]'s pipeline
     * (preCF + H + V + composite passes) but routes the COMPOSITE pass's
     * output to a layer-sized scratch instead of the parent's `colorView`
     * via the [BlurredLayerCompositeDraw.materializeTargetView] override.
     * The dispatch loop forces `loadOp = Clear` + `mode = kSrc` on the
     * composite pass when materialising, so the scratch holds the
     * isolated BlurCF output (no parent-pixel contamination).
     *
     * Returns the (texture, view) pair so the caller can :
     *  - Pass the view as `sourceLayerView` to the next stage's enqueue
     *    helper (the chain's next materialise leaf, or the final
     *    composite).
     *  - The texture is registered on the materialise DrawResources
     *    (transferred from the [BlurredLayerCompositeDraw]) and closed
     *    in [closeDrawResources] after the consumer draws are submitted.
     *
     * Layer-local semantics : the scratch is layer-sized, so the
     * composite pass uses `dstOriginX/Y = (0, 0)` and a layer-rect
     * scissor (no parent clip / viewport intersection -- the scratch is
     * scoped to the layer footprint).
     */
    private fun enqueueMaterializeBlurCfToScratch(
        gpuSrc: SkWebGpuDevice,
        w: Int, h: Int,
        preBlurColorFilter: org.skia.foundation.SkColorFilter?,
        blurParams: org.skia.foundation.SkBlurImageFilterParams?,
        postBlurColorFilter: org.skia.foundation.SkColorFilter?,
        sourceLayerView: GPUTextureView,
    ): GPUTextureView {
        // Resolve the kernel + tile mode. A null `blurParams` (CF-only
        // pre-stage) collapses to radius 0 ; the H/V passes become
        // identity copies and the composite pass applies the CF. We
        // ship a synthetic kDecal/sigma=0 in that case to keep the
        // existing BlurredLayerCompositeDraw pipeline warm.
        val sigmaX = blurParams?.sigmaX ?: 0f
        val sigmaY = blurParams?.sigmaY ?: 0f
        val tileMode = blurParams?.tileMode ?: SkTileMode.kDecal
        if (!sigmaX.isFinite() || !sigmaY.isFinite() ||
            sigmaX < 0f || sigmaY < 0f
        ) {
            error(
                "SkWebGpuDevice.compositeFrom : a Compose-nested Blur's " +
                    "sigma must be finite and non-negative ; got (sigmaX = " +
                    "$sigmaX, sigmaY = $sigmaY)."
            )
        }
        val unboundedRadiusX = if (sigmaX > 0f) {
            ceil(3.0 * sigmaX).toInt().coerceAtLeast(1)
        } else 0
        val unboundedRadiusY = if (sigmaY > 0f) {
            ceil(3.0 * sigmaY).toInt().coerceAtLeast(1)
        } else 0
        val radiusX = unboundedRadiusX.coerceAtMost(MAX_BLUR_RADIUS)
        val radiusY = unboundedRadiusY.coerceAtMost(MAX_BLUR_RADIUS)
        val kernelX = if (radiusX > 0) {
            buildSymmetricGaussianHalfKernel(sigmaX, radiusX)
        } else floatArrayOf(1f)
        val kernelY = if (radiusY > 0) {
            buildSymmetricGaussianHalfKernel(sigmaY, radiusY)
        } else floatArrayOf(1f)

        // Blur H/V scratches : same shape as the top-level Blur path.
        val scratchH = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = w.toUInt(), height = h.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.materializeBlurCfScratchH",
            ),
        )
        val scratchHView = scratchH.createView()
        val scratchV = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = w.toUInt(), height = h.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.materializeBlurCfScratchV",
            ),
        )
        val scratchVView = scratchV.createView()

        // Pre-blur CF scratch (only when a pre-blur CF is present).
        val preCfScratch: GPUTexture?
        val preCfScratchView: GPUTextureView?
        val preCfPacked: FloatArray?
        if (preBlurColorFilter != null) {
            preCfScratch = context.device.createTexture(
                TextureDescriptor(
                    size = Extent3D(width = w.toUInt(), height = h.toUInt()),
                    format = intermediateFormat,
                    usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                    label = "SkWebGpuDevice.materializeBlurCfScratchPreCf",
                ),
            )
            preCfScratchView = preCfScratch.createView()
            preCfPacked = packLayerCompositeColorFilter(preBlurColorFilter)
        } else {
            preCfScratch = null
            preCfScratchView = null
            preCfPacked = null
        }

        // Materialised target : holds the BlurCF output in layer-local
        // coords. Sampled by the next stage's enqueue helper via the
        // returned view.
        val materializeTarget = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = w.toUInt(), height = h.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.materializeBlurCfTarget",
            ),
        )
        val materializeTargetView = materializeTarget.createView()

        // Post-blur CF : packed into the composite pass's colorFilter
        // slot (mirrors the non-materialise [enqueueBlurredLayerComposite]
        // path).
        val colorFilterPacked = packLayerCompositeColorFilter(postBlurColorFilter)

        // Layer-local scissor : the materialise scratch is layer-sized,
        // covering the full (0, 0)..(w, h) rect.
        val scissor = intArrayOf(0, 0, w, h)

        pending.add(
            BlurredLayerCompositeDraw(
                layerView = sourceLayerView,
                layerWidth = w, layerHeight = h,
                scratchHTexture = scratchH, scratchHView = scratchHView,
                scratchVTexture = scratchV, scratchVView = scratchVView,
                // Layer-local origin : the BlurCF output lands at (0, 0)
                // inside the layer-sized scratch.
                dstOriginX = 0, dstOriginY = 0,
                scissor = scissor,
                kernelX = kernelX, radiusX = radiusX,
                kernelY = kernelY, radiusY = radiusY,
                tileModeOrdinal = tileMode.ordinal,
                // paintAlpha = 1 on the materialised output -- the outer
                // plan handles the layer paint's alpha + colour filter
                // on the FINAL composite.
                paintR = 1f, paintG = 1f, paintB = 1f, paintA = 1f,
                colorFilterPacked = colorFilterPacked,
                preBlurColorFilterPacked = preCfPacked,
                scratchPreCfTexture = preCfScratch,
                scratchPreCfView = preCfScratchView,
                // Materialise mode : the dispatch redirects the
                // composite pass to write into [materializeTargetView]
                // with `loadOp = Clear` + `mode = kSrc`.
                materializeTargetTexture = materializeTarget,
                materializeTargetView = materializeTargetView,
                r = 1f, g = 1f, b = 1f, a = 1f,
                mode = SkBlendMode.kSrc,
            ),
        )

        return materializeTargetView
    }

    /**
     * Phase G-saveLayer-imageFilter-matrixTransform -- helper for
     * [compositeFrom]. Computes the inverse 2x3 of the user matrix, the
     * cover-quad scissor (axis-aligned bbox of the mapped layer rect,
     * intersected with the parent clip + viewport), and enqueues a single
     * [LayerCompositeDraw] with the matrix payload packed into its
     * `matrixPacked` slot. The fragment shader applies the inverse to
     * the device-pixel coords and samples the layer texture per the
     * SkFilterMode selected (kNearest -> mode 1, kLinear -> mode 2).
     *
     * **Bail conditions.**
     *  - Non-null child filter -- the structural pre-pass needed to
     *    render the child filter's output into a scratch before the
     *    affine remap is deferred to a follow-up slice. Throws a clear
     *    "input == null required" error.
     *  - Perspective matrix -- the shader's `vec3 dot-product` path
     *    handles 2x3 affine only. A 3x3 with non-trivial bottom row
     *    needs a homogeneous divide that the first slice doesn't ship.
     *    Throws a clear "perspective deferred" error.
     *  - Cubic sampling -- the shader implements kNearest / kLinear
     *    only ; cubic resampling is deferred (same as drawImageRect).
     *  - Non-invertible matrix -- the inverse 2x3 doesn't exist, so the
     *    fragment shader can't reverse-map device pixels to layer pixels.
     *    Returns silently (mirrors `SkImageFilters.MatrixTransform`'s
     *    own treatment of non-invertible matrices : it returns the input
     *    unchanged, which on a composite path means a no-op).
     */
    private fun enqueueMatrixTransformLayerComposite(
        gpuSrc: SkWebGpuDevice,
        w: Int, h: Int,
        originX: Int, originY: Int,
        clip: SkIRect,
        params: org.skia.foundation.SkMatrixTransformImageFilterParams,
        paintAlpha: Float,
        colorFilterPacked: FloatArray,
        mode: SkBlendMode,
        // N1 -- chain-of-passes : same shape as the DropShadow variant.
        // The MatrixTransform's affine remap samples this view (default =
        // raw layer). For chained dispatch (e.g. `Compose(MT, Blur)`
        // where Blur was materialised first), the caller substitutes the
        // previous stage's scratch view.
        sourceLayerView: GPUTextureView = gpuSrc.intermediateView,
    ) {
        if (params.input != null) {
            error(
                "SkWebGpuDevice.compositeFrom : paint.imageFilter is a " +
                    "SkImageFilters.MatrixTransform(input = nonNull) with a " +
                    "non-null child filter. Only the input == null case is " +
                    "supported (Phase G-saveLayer-imageFilter-matrixTransform) " +
                    "-- a non-null child needs a render-to-texture pre-pass " +
                    "that the WebGPU layer composite pipeline cannot express yet."
            )
        }
        if (params.matrix.hasPerspective()) {
            error(
                "SkWebGpuDevice.compositeFrom : paint.imageFilter is a " +
                    "SkImageFilters.MatrixTransform with a perspective matrix " +
                    "(non-trivial bottom row). Only 2x3 affine is supported " +
                    "in the first MatrixTransform slice (Phase " +
                    "G-saveLayer-imageFilter-matrixTransform) -- perspective " +
                    "needs a homogeneous divide in the fragment shader (the " +
                    "current shader uses a vec3 dot-product affine path) and " +
                    "is deferred to a follow-up slice."
            )
        }
        // Cubic sampling deferral matches `drawImageRect`'s cubic gate.
        // The composite shader only implements kNearest / kLinear ; a
        // cubic resampler would need a 16-tap kernel + B/C coefs in the
        // uniform.
        if (params.sampling.cubic != null) {
            error(
                "SkWebGpuDevice.compositeFrom : paint.imageFilter is a " +
                    "SkImageFilters.MatrixTransform with a cubic resampler. " +
                    "Only kNearest and kLinear are supported in the first " +
                    "MatrixTransform slice (Phase G-saveLayer-imageFilter-" +
                    "matrixTransform) -- cubic resampling needs a 16-tap " +
                    "kernel in the composite shader and is deferred."
            )
        }
        val samplingModeOrdinal = when (params.sampling.filter) {
            SkFilterMode.kNearest -> 1
            SkFilterMode.kLinear -> 2
        }

        // The user matrix is expressed in layer-pixel coords (it
        // operates on the input image's pixel grid, before the dst
        // origin shifts it onto the parent device). To convert
        // device-pixel coords -> layer-pixel coords, the fragment
        // shader needs to :
        //   1. subtract the layer's dst origin (parent-device px ->
        //      transformed-layer-px)
        //   2. invert the user matrix (transformed-layer-px ->
        //      original-layer-px the texture stores)
        //
        // Composed as a single 2x3 : `inv(M) * T(-originX, -originY)`.
        // We bake this composition into `devToLayerRow*` so the shader
        // only has to evaluate `dot(row, vec3(pos.x, pos.y, 1))` per
        // axis. Mirrors the bitmap shader's "device -> local" pack in
        // #574.
        val invMatrix = params.matrix.invert()
        if (invMatrix == null) {
            // Non-invertible : the CPU raster's MatrixTransform returns
            // the input image unchanged. A composite of "unchanged but
            // displaced by a non-invertible matrix" has no well-defined
            // dst -- the visible footprint collapses to zero area. Skip
            // the draw to mirror the CPU raster's degenerate behaviour.
            return
        }
        // Bake the dst-origin translation into the inverse : the
        // composed transform is `inv(M) * T(-originX, -originY)`, i.e.
        // first translate the device pixel into layer-relative-of-the-
        // transformed-image coords, then invert the user matrix to
        // land in the texture's original layer-pixel coords.
        val a = invMatrix.sx
        val b = invMatrix.kx
        val c = invMatrix.tx - a * originX - b * originY
        val d = invMatrix.ky
        val e = invMatrix.sy
        val f = invMatrix.ty - d * originX - e * originY
        val matrixPacked = FloatArray(12)
        matrixPacked[0] = a; matrixPacked[1] = b; matrixPacked[2] = c
        matrixPacked[4] = d; matrixPacked[5] = e; matrixPacked[6] = f
        matrixPacked[8] = samplingModeOrdinal.toFloat()

        // Cover-quad geometry : the axis-aligned bbox of the four
        // corners of the layer rect mapped through the user matrix,
        // offset by the layer's dst origin in parent-device pixels.
        // We then floor / ceil to integer device-pixel coords (the
        // shader's `floor(pos.xy)` -> int conversion expects integer-
        // aligned scissor edges) and intersect with the parent clip
        // + viewport so fragments outside the visible composite never
        // reach the shader.
        val mappedRect = params.matrix.mapRect(
            org.graphiks.math.SkRect.MakeLTRB(0f, 0f, w.toFloat(), h.toFloat()),
        )
        val coverL = floor(mappedRect.left).toInt() + originX
        val coverT = floor(mappedRect.top).toInt() + originY
        val coverR = ceil(mappedRect.right).toInt() + originX
        val coverB = ceil(mappedRect.bottom).toInt() + originY
        val ix0 = coverL.coerceAtLeast(clip.left).coerceAtLeast(0)
        val iy0 = coverT.coerceAtLeast(clip.top).coerceAtLeast(0)
        val ix1 = coverR.coerceAtMost(clip.right).coerceAtMost(width)
        val iy1 = coverB.coerceAtMost(clip.bottom).coerceAtMost(height)
        if (ix0 >= ix1 || iy0 >= iy1) return

        pending.add(
            LayerCompositeDraw(
                layerView = sourceLayerView,
                layerWidth = w, layerHeight = h,
                // dstOriginX / dstOriginY are unused on the
                // MatrixTransform path (the shader's identity branch
                // is the only consumer of `dstOriginSize.xy`, and
                // `samplingMode != 0` skips it). We still ship the
                // original origin for diagnostic / fast-path safety.
                dstOriginX = originX, dstOriginY = originY,
                scissor = intArrayOf(ix0, iy0, ix1 - ix0, iy1 - iy0),
                paintR = paintAlpha, paintG = paintAlpha,
                paintB = paintAlpha, paintA = paintAlpha,
                r = 1f, g = 1f, b = 1f, a = paintAlpha,
                mode = mode,
                colorFilterPacked = colorFilterPacked,
                matrixPacked = matrixPacked,
                imageFilterPacked = FloatArray(12),
            ),
        )
    }

    /**
     * Phase G-saveLayer-imageFilter-compose -- normalized plan for the
     * layer paint's [SkImageFilter] slot, built by walking the (possibly
     * Compose-wrapped) tree into the shape the WebGPU composite pipeline
     * can dispatch :
     *
     *   [optional pre-blur ColorFilter]
     *   [optional Blur]
     *   [optional post-blur ColorFilter (folded with paint.colorFilter)]
     *
     * The pre-blur ColorFilter runs in a dedicated pre-pass that reads
     * the layer texture and writes to a scratch (using
     * `layer_composite.wgsl` with `kSrc` blend) before the Blur's H pass
     * reads from that scratch. The post-blur ColorFilter rides in the
     * composite pass's uniform (the existing slot consumed by
     * `layer_composite.wgsl` after the paintColor scale).
     *
     * When the imageFilter contains no Blur, the whole plan collapses
     * onto the existing [LayerCompositeDraw] path : pre-blur and
     * post-blur slots fold into a single effective colour filter (the
     * existing single-occupancy rule applies -- if both slots are non-
     * null, the resolver throws).
     *
     * Top-level Offset / DropShadow are NOT modelled by the plan : the
     * dispatch in [compositeFrom] handles them BEFORE calling this
     * resolver. The resolver therefore only sees Blur, ColorFilter,
     * and Compose nodes ; encountering an Offset / DropShadow inside
     * a Compose tree throws a "deferred" error (mixing those structural
     * filters with the normalized `[preCF?][Blur?][postCF?]` plan needs
     * a render-to-texture intermediate that is out of scope for the
     * first Compose slice).
     */
    /**
     * N1 -- chain-of-passes : one entry in the ordered list of materialise
     * pre-stages emitted by the walker (in walk order = inner → outer).
     *
     * Each pre-stage carries an optional BlurCF prefix (the Blur /
     * ColorFilter leaves accumulated between the PREVIOUS materialise leaf
     * and THIS one in the walk) plus the terminal materialise leaf (a
     * DropShadow or a MatrixTransform). The dispatch :
     *  1. Reads the previous stage's output (or the raw layer for the
     *     first stage) as `sourceLayerView`.
     *  2. If the prefix carries a non-null `preBlurColorFilter`, `blur`,
     *     or `postBlurColorFilter`, materialises that BlurCF bundle into
     *     a layer-sized scratch first, then feeds it to the leaf's
     *     materialise helper as its `sourceLayerView`.
     *  3. Materialises the leaf into a fresh layer-sized scratch.
     *  4. That scratch becomes the source for the NEXT pre-stage (or the
     *     final composite when this is the last pre-stage).
     *
     * Supports the three deferred shapes left by L1a/L1b :
     *  - Pre-accumulation : `Compose(DS, Blur)` /
     *    `Compose(DS, ColorFilter)` / `Compose(MT, Blur)` / etc. -- the
     *    inner BlurCF lands as the prefix of the outer DS/MT pre-stage.
     *  - Two DropShadows : `Compose(DS, DS)` -- two DS pre-stages in
     *    the chain, the second reads the first's scratch.
     *  - DS + MT : `Compose(DS, MT)` / `Compose(MT, DS)` -- mixed
     *    materialise leaves in the chain.
     */
    private data class MaterialisePreStage(
        // BlurCF prefix : null fields = no prefix (the leaf consumes the
        // previous stage's source directly). When any of the three are
        // non-null, the dispatch materialises a
        // [BlurredLayerCompositeDraw] in materialise mode first.
        val preBlurColorFilter: org.skia.foundation.SkColorFilter? = null,
        val blurParams: org.skia.foundation.SkBlurImageFilterParams? = null,
        val postBlurColorFilter: org.skia.foundation.SkColorFilter? = null,
        // Terminal materialise leaf : exactly one of the two is non-null.
        val dropShadow: org.skia.foundation.SkDropShadowImageFilterParams? = null,
        val matrixTransform: org.skia.foundation.SkMatrixTransformImageFilterParams? = null,
    ) {
        init {
            require((dropShadow != null) xor (matrixTransform != null)) {
                "MaterialisePreStage must carry exactly one terminal leaf " +
                    "(DropShadow or MatrixTransform), not both / neither."
            }
        }

        /** True when the prefix carries any BlurCF stage. */
        val hasBlurCfPrefix: Boolean
            get() = preBlurColorFilter != null || blurParams != null ||
                postBlurColorFilter != null
    }

    private data class ResolvedLayerImageFilterPlan(
        // Single ColorFilter applied to the layer texture before the
        // Blur reads from it. `null` means no pre-blur stage.
        val preBlurColorFilter: org.skia.foundation.SkColorFilter?,
        // Blur parameters, or `null` if the filter tree carries no Blur.
        // When present, the dispatch enqueues a [BlurredLayerCompositeDraw]
        // (optionally extended with a pre-blur CF pass) ; when absent,
        // the dispatch enqueues a plain [LayerCompositeDraw].
        val blurParams: org.skia.foundation.SkBlurImageFilterParams?,
        // Effective ColorFilter consumed by the composite pass uniform.
        // Folds `paint.colorFilter` with any post-blur (or pre-blur when
        // no blur is present) ColorFilter from the tree.
        val effectiveColorFilter: org.skia.foundation.SkColorFilter?,
        // K1 GPU follow-up to PR #605 (CPU Compose with non-null inner)
        // -- accumulated integer pixel offset from `SkImageFilters.Offset`
        // leaves anywhere in a Compose chain. Both Blur and ColorFilter
        // are translation-invariant (the Gaussian kernel commutes with
        // translation, the per-pixel CF is point-wise) so the order
        // collapses : the only observable effect of any Offset leaf in
        // the chain is to shift the final composite's dst origin by the
        // sum of all (dx, dy) offsets, integer-rounded per upstream
        // Skia's `(dx + 0.5).toInt()` convention. The dispatch in
        // [compositeFrom] applies the shift to `originX/originY` and the
        // scissor rect before enqueuing the Blur / no-blur composite.
        val offsetDx: Int = 0,
        val offsetDy: Int = 0,
        // N1 -- ordered chain of materialise pre-stages (in walk order =
        // inner → outer). Each stage applies an optional BlurCF prefix to
        // its source then materialises a leaf (DropShadow or
        // MatrixTransform) into a scratch ; that scratch becomes the next
        // stage's source. The FINAL composite stage (the
        // [preBlurColorFilter] / [blurParams] / [effectiveColorFilter] /
        // [offsetDx] / [offsetDy] bundle above) runs on top of the LAST
        // stage's output (or the raw layer when the chain is empty).
        //
        // Supersedes L1a's `innerDropShadow` / L1b's
        // `innerMatrixTransform` single-slot shortcut : the chain
        // generalises both. The walker emits a one-entry chain for the
        // single-leaf case and a multi-entry chain for the chain-of-
        // passes cases unlocked by N1 :
        //  - Compose(DS,  Blur)              -- BlurCF prefix on DS stage
        //  - Compose(DS,  DS)                -- two DS materialise stages
        //  - Compose(DS,  MT) / Compose(MT, DS) -- mixed stages
        //  - Compose(MT,  Blur)              -- BlurCF prefix on MT stage
        //  - Compose(ColorFilter, DS) / (CF, MT) -- ColorFilter prefix
        // The dispatch in [compositeFrom] iterates through the chain,
        // allocating one materialise scratch per stage.
        val materialiseChain: List<MaterialisePreStage> = emptyList(),
    )

    private data class CropNonNullOffsetPrePassPlan(
        val cropRect: SkRect,
        val cropTileMode: SkTileMode,
        val offsetDx: Int,
        val offsetDy: Int,
    )

    /**
     * Phase G-saveLayer-imageFilter -- resolver for the layer paint's
     * [SkImageFilter] slot. See [ResolvedLayerImageFilterPlan] for the
     * shape of the normalized plan.
     *
     * Supported variants (Phase G-saveLayer-imageFilter / -blur /
     * -compose) :
     *  - `null` filter -> just `paint.colorFilter` (no blur, no pre-CF).
     *  - `SkImageFilters.ColorFilter(cf, input = null)` -> post-blur CF
     *    only ; folds with `paint.colorFilter` per the single-occupancy
     *    rule (throws if both are set).
     *  - `SkImageFilters.Blur(sigmaX, sigmaY, tileMode, input = null)`
     *    with any [SkTileMode] (N9 -- all four ordinals are handled
     *    in-shader by `blur_image_filter.wgsl`) -> blur params, no
     *    pre-CF, post-CF = `paint.colorFilter`.
     *  - `SkImageFilters.Offset(dx, dy, input = null)` / `SkImageFilters
     *    .DropShadow(...)` at the TOP level -> pass-through : no blur,
     *    no pre-CF, effective CF = `paint.colorFilter`. The dispatch
     *    in [compositeFrom] handles the structural shift / shadow pass
     *    before this resolver sees the filter.
     *  - `SkImageFilters.Compose(outer, inner)` -> walk the children
     *    recursively : `inner` is applied first to the source image,
     *    then `outer` to the inner's result. The walk classifies each
     *    leaf as "before blur" / "blur" / "after blur" depending on
     *    where it falls in the chain.
     *
     * Unsupported patterns throw with a clear error :
     *  - Any Compose chain that introduces more than one Blur (e.g.
     *    `Compose(Blur, Blur)`), or a non-null `input` on a leaf Blur /
     *    ColorFilter.
     *  - Any non-`null` `paint.colorFilter` combined with a post-blur
     *    ColorFilter from the Compose chain (single-occupancy uniform).
     *  - Any Offset / DropShadow inside a Compose tree -- deferred
     *    (the structural filter mixed with the normalized blur/CF plan
     *    needs a render-to-texture intermediate that the first Compose
     *    slice doesn't ship).
     *  - Any other [SkImageFilter] variant in a leaf position
     *    (MatrixTransform, DisplacementMap, ...).
     */
    private fun resolveLayerImageFilterPlan(
        paint: SkPaint?,
    ): ResolvedLayerImageFilterPlan {
        val imf = paint?.imageFilter
            ?: return ResolvedLayerImageFilterPlan(
                preBlurColorFilter = null,
                blurParams = null,
                effectiveColorFilter = paint?.colorFilter,
            )

        // Phase G-saveLayer-imageFilter-offset / -dropshadow /
        // -matrixTransform -- the three structural variants are folded
        // into the composite uniform / dispatch by [compositeFrom]
        // directly when they sit at the TOP of the filter tree ; the
        // plan here is just "no blur, no preCF, effectiveCF =
        // paint.colorFilter" (the offset / shadow / matrix placement
        // is structural, not per-pixel). The dispatch gate validates
        // input == null there too, so this branch only short-circuits
        // the throw path of the walker below.
        if (imf.asOffsetImageFilter() != null ||
            imf.asDropShadowImageFilter() != null ||
            imf.asMatrixTransformImageFilter() != null
        ) {
            return ResolvedLayerImageFilterPlan(
                preBlurColorFilter = null,
                blurParams = null,
                effectiveColorFilter = paint.colorFilter,
            )
        }

        // Walk the Compose tree, classifying each leaf as "pre-blur CF"
        // / "blur" / "post-blur CF". `inner` runs first, so we recurse
        // into it before `outer`. The walk uses a mutable accumulator
        // because the chain is left-associative (e.g.
        // `Compose(Compose(A, B), C)` resolves as `A(B(C(src)))`).
        var preBlurCF: org.skia.foundation.SkColorFilter? = null
        var blur: org.skia.foundation.SkBlurImageFilterParams? = null
        var postBlurCF: org.skia.foundation.SkColorFilter? = null
        // K1 GPU follow-up to PR #605 -- accumulated Offset leaves. Both
        // Blur and the per-pixel ColorFilter passes commute with
        // translation, so the order in which Offset leaves are
        // encountered doesn't matter ; the sum lands as a single dst-
        // origin shift on the final composite.
        var offsetDx = 0
        var offsetDy = 0
        // N1 -- ordered chain of materialise pre-stages. Each entry pairs
        // an optional BlurCF prefix (the Blur / ColorFilter leaves seen
        // BETWEEN the previous materialise leaf and THIS one in the walk)
        // with a terminal DS / MT leaf. Replaces L1a's
        // [innerDropShadow] / L1b's [innerMatrixTransform] single-slot
        // shortcut : a Compose chain may now hold multiple materialise
        // leaves with arbitrary BlurCF prefixes between them.
        val materialiseChain = mutableListOf<MaterialisePreStage>()
        // Snapshot the offset at the moment we last finalised a
        // materialise pre-stage. Offsets ACCUMULATED before any
        // materialise leaf land on the final composite (the existing
        // behavior for a Compose chain with no materialise leaf).
        // Offsets accumulated BETWEEN two materialise leaves are
        // problematic for non-translation MatrixTransforms (MT doesn't
        // commute with translation in general) -- we throw a clear
        // error in that case ; for DropShadow-only chains the
        // translation-equivariance lets the offset ride on the final
        // composite without semantic drift.
        var lastFinalizedOffsetDx = 0
        var lastFinalizedOffsetDy = 0

        // Helper : finalise the current BlurCF accumulator + the
        // observed materialise leaf into a [MaterialisePreStage] and
        // append to the chain. Resets the BlurCF accumulator.
        fun finaliseMaterialiseStage(
            dropShadow: org.skia.foundation.SkDropShadowImageFilterParams? = null,
            matrixTransform: org.skia.foundation.SkMatrixTransformImageFilterParams? = null,
        ) {
            // Check: offsets accumulated SINCE the last finalised stage
            // would shift the source going INTO this materialise leaf.
            // For a MatrixTransform that's not a pure translation, that
            // would shift in pre-MT space, which doesn't commute with
            // the affine remap. Throw a clear error for the MT case ;
            // DS is translation-equivariant so the offset can ride on
            // the final composite without semantic drift (handled by
            // the cumulative offsetDx/Dy applied at the final composite).
            val newOffsetDx = offsetDx - lastFinalizedOffsetDx
            val newOffsetDy = offsetDy - lastFinalizedOffsetDy
            if ((newOffsetDx != 0 || newOffsetDy != 0) &&
                matrixTransform != null &&
                matrixTransform.matrix.run {
                    // Pure translation = identity rotation/scale (sx=sy=1,
                    // kx=ky=0). Translation-only MT commutes with Offset.
                    sx != 1f || sy != 1f || kx != 0f || ky != 0f
                }
            ) {
                error(
                    "SkWebGpuDevice.compositeFrom : a Compose chain contains a " +
                        "non-translation MatrixTransform preceded by an Offset " +
                        "in the same chain segment (i.e. between two materialise " +
                        "leaves). MatrixTransform with non-trivial rotation / " +
                        "scale does not commute with translation, so the Offset " +
                        "cannot ride on the final composite -- the N1 chain-of-" +
                        "passes slice doesn't yet bake a pre-translation into " +
                        "the MatrixTransform's source-reading matrix. Deferred " +
                        "to a follow-up slice."
                )
            }
            materialiseChain.add(
                MaterialisePreStage(
                    preBlurColorFilter = preBlurCF,
                    blurParams = blur,
                    postBlurColorFilter = postBlurCF,
                    dropShadow = dropShadow,
                    matrixTransform = matrixTransform,
                ),
            )
            // Reset the BlurCF accumulator for the next stage.
            preBlurCF = null
            blur = null
            postBlurCF = null
            lastFinalizedOffsetDx = offsetDx
            lastFinalizedOffsetDy = offsetDy
        }

        fun walk(node: org.skia.foundation.SkImageFilter) {
            val composeParams = node.asComposeImageFilter()
            if (composeParams != null) {
                // inner runs first, then outer.
                walk(composeParams.inner)
                walk(composeParams.outer)
                return
            }
            // K1 GPU follow-up to PR #605 -- Offset leaves inside a
            // Compose chain collapse onto a single dst-origin shift on
            // the final composite. Blur is translation-invariant (the
            // Gaussian kernel commutes with translation -- shifting the
            // input is bit-iso with shifting the output) ; ColorFilter
            // is point-wise (it doesn't sample neighbouring pixels).
            // The cumulative (dx, dy) is integer-rounded per upstream
            // Skia's `(dx + 0.5).toInt()` convention -- same rule as
            // the top-level Offset dispatch in [compositeFrom].
            val offsetLeaf = node.asOffsetImageFilter()
            if (offsetLeaf != null) {
                if (offsetLeaf.input != null) {
                    error(
                        "SkWebGpuDevice.compositeFrom : an Offset leaf inside " +
                            "the imageFilter tree has a non-null child filter. " +
                            "The Compose support flattens the tree, so leaves " +
                            "must have input == null -- nest the child via a " +
                            "Compose node instead (e.g. SkImageFilters.Compose" +
                            "(Offset(dx, dy), child) rather than Offset(dx, dy, " +
                            "input = child))."
                    )
                }
                offsetDx += floor(offsetLeaf.dx + 0.5f).toInt()
                offsetDy += floor(offsetLeaf.dy + 0.5f).toInt()
                return
            }
            // N1 -- DropShadow leaf inside a Compose tree : append to the
            // materialise chain. The current BlurCF accumulator becomes
            // the stage's BlurCF prefix (the inner Blur / ColorFilter
            // leaves accumulated between the previous materialise leaf
            // and this one). For the FIRST materialise leaf in the chain
            // (no previous), the prefix BlurCF applies to the raw layer
            // source ; for subsequent ones it applies to the previous
            // materialise scratch.
            val dropShadowLeaf = node.asDropShadowImageFilter()
            if (dropShadowLeaf != null) {
                if (dropShadowLeaf.input != null) {
                    error(
                        "SkWebGpuDevice.compositeFrom : a DropShadow leaf inside " +
                            "the imageFilter tree has a non-null child filter. The " +
                            "Compose support flattens the tree, so leaves must have " +
                            "input == null -- nest the child via a Compose node " +
                            "instead (e.g. SkImageFilters.Compose(DropShadow(...), " +
                            "child) rather than DropShadow(..., input = child))."
                    )
                }
                finaliseMaterialiseStage(dropShadow = dropShadowLeaf)
                return
            }
            // N1 -- MatrixTransform leaf : same shape as DropShadow above.
            val matrixTransformLeaf = node.asMatrixTransformImageFilter()
            if (matrixTransformLeaf != null) {
                if (matrixTransformLeaf.input != null) {
                    error(
                        "SkWebGpuDevice.compositeFrom : a MatrixTransform leaf " +
                            "inside the imageFilter tree has a non-null child " +
                            "filter. The Compose support flattens the tree, so " +
                            "leaves must have input == null -- nest the child via " +
                            "a Compose node instead (e.g. SkImageFilters.Compose(" +
                            "MatrixTransform(m, sampling), child) rather than " +
                            "MatrixTransform(m, sampling, input = child))."
                    )
                }
                finaliseMaterialiseStage(matrixTransform = matrixTransformLeaf)
                return
            }
            val blurLeaf = node.asBlurImageFilter()
            if (blurLeaf != null) {
                if (blurLeaf.input != null) {
                    error(
                        "SkWebGpuDevice.compositeFrom : a Blur leaf inside the " +
                            "imageFilter tree has a non-null child filter. The " +
                            "Compose support flattens the tree, so leaves must " +
                            "have input == null -- nest the child via a Compose " +
                            "node instead (e.g. SkImageFilters.Compose(Blur(...), " +
                            "child) rather than Blur(..., input = child))."
                    )
                }
                // N9 -- all four SkTileMode variants are supported on the
                // WebGPU saveLayer Blur path. The shader
                // (`blur_image_filter.wgsl`) samples via `textureLoad` with
                // manual tile math (no sampler), mirroring the CPU raster's
                // `positiveModInternal` / `mirrorModInternal` helpers in
                // `SkBlurImageFilter`. kRepeat / kMirror always sample
                // in-bound, so the kernel mass is unitary by construction
                // and no per-pixel renormalisation is required ; kDecal
                // returns zero out-of-bound (intentional alpha falloff,
                // matches the CPU reference) ; kClamp reads the edge
                // texel. The ordinal is shipped to the shader via
                // [BlurredLayerCompositeDraw.tileModeOrdinal].
                if (blur != null) {
                    error(
                        "SkWebGpuDevice.compositeFrom : the imageFilter tree " +
                            "carries more than one Blur (e.g. Compose(Blur, " +
                            "Blur)). The first Compose support slice handles at " +
                            "most one Blur per layer composite -- folding two " +
                            "Gaussians via sigma = sqrt(s1^2 + s2^2) needs a " +
                            "follow-up slice that proves the kernel-mass " +
                            "renormalization on kDecal."
                    )
                }
                blur = blurLeaf
                return
            }
            val cfLeaf = node.asColorFilterImageFilter()
            if (cfLeaf != null) {
                if (cfLeaf.input != null) {
                    error(
                        "SkWebGpuDevice.compositeFrom : a ColorFilter leaf " +
                            "inside the imageFilter tree has a non-null child " +
                            "filter. Compose flattens the tree, so leaves must " +
                            "have input == null -- nest the child via a Compose " +
                            "node instead (e.g. SkImageFilters.Compose(" +
                            "ColorFilter(cf), child) rather than ColorFilter(cf, " +
                            "input = child))."
                    )
                }
                if (blur == null) {
                    // This CF runs before the Blur (or there is no Blur).
                    if (preBlurCF != null) {
                        error(
                            "SkWebGpuDevice.compositeFrom : the imageFilter tree " +
                                "carries more than one ColorFilter in the same " +
                                "stage (e.g. Compose(ColorFilter, ColorFilter) " +
                                "with no Blur between them). The composite " +
                                "shader's colorFilter uniform is single-occupancy " +
                                "per stage -- folding two arbitrary SkColorFilter " +
                                "variants needs an SkComposeColorFilter extractor " +
                                "that the scaffolding slice doesn't ship."
                        )
                    }
                    preBlurCF = cfLeaf.colorFilter
                } else {
                    // This CF runs after the Blur.
                    if (postBlurCF != null) {
                        error(
                            "SkWebGpuDevice.compositeFrom : the imageFilter tree " +
                                "carries more than one ColorFilter after the " +
                                "Blur (e.g. Compose(ColorFilter, Compose(" +
                                "ColorFilter, Blur))). The composite shader's " +
                                "colorFilter uniform is single-occupancy per " +
                                "stage."
                        )
                    }
                    postBlurCF = cfLeaf.colorFilter
                }
                return
            }
            error(
                "SkWebGpuDevice.compositeFrom : paint.imageFilter " +
                    "${node::class.simpleName} not yet supported on the WebGPU " +
                    "backend. Supported leaves in a Compose chain : " +
                    "SkImageFilters.Blur(kClamp / kDecal, input = null) and " +
                    "SkImageFilters.ColorFilter(cf, input = null). Other " +
                    "variants -- Offset, DropShadow, MatrixTransform, " +
                    "DisplacementMap, Magnifier, Tile, Crop, Blend, Erode / " +
                    "Dilate, MatrixConvolution, Lighting, Arithmetic -- need " +
                    "follow-up slices that add a fragment-side UV-remapping " +
                    "or multi-pass render-target pipeline. Note : Magnifier " +
                    "/ Tile / Crop are supported at the TOP level of the " +
                    "filter tree (Phase G-saveLayer-imageFilter-crop / -tile " +
                    "/ -magnifier) but not yet inside a Compose chain -- the " +
                    "UV-remap branch is folded into the composite shader " +
                    "directly, which precludes another stage running over it."
            )
        }
        walk(imf)

        // Single-occupancy rule -- a CF on paint.colorFilter may not
        // coexist with a CF from the Compose chain that lands in the
        // same stage (the composite shader's uniform is single-slot).
        // When no Blur is present, pre-blur and post-blur collapse onto
        // the same stage as the composite pass, so we treat any non-
        // null tree-side CF as the post-blur slot for the conflict check.
        if (blur == null) {
            // No blur : preBlurCF and postBlurCF are not both populated
            // (the walk classifies all CFs as "pre-blur" before any blur
            // is seen). Fold into a single effective CF.
            val treeCF = preBlurCF ?: postBlurCF
            if (treeCF != null && paint.colorFilter != null) {
                error(
                    "SkWebGpuDevice.compositeFrom : both paint.colorFilter and " +
                        "paint.imageFilter (ColorFilter / Compose chain) are " +
                        "set. The WebGPU layer composite uniform is single-" +
                        "occupancy (one SkColorFilter per draw) -- folding two " +
                        "arbitrary SkColorFilter variants needs an " +
                        "SkComposeColorFilter extractor that the scaffolding " +
                        "slice doesn't ship. Set only one of the two on the " +
                        "layer paint."
                )
            }
            return ResolvedLayerImageFilterPlan(
                preBlurColorFilter = null,
                blurParams = null,
                effectiveColorFilter = treeCF ?: paint.colorFilter,
                offsetDx = offsetDx,
                offsetDy = offsetDy,
                materialiseChain = materialiseChain,
            )
        }
        // Blur present : pre-blur CF (if any) stays as the pre-pass ;
        // post-blur CF folds with paint.colorFilter under the single-
        // occupancy rule.
        if (postBlurCF != null && paint.colorFilter != null) {
            error(
                "SkWebGpuDevice.compositeFrom : both paint.colorFilter and a " +
                    "post-blur ColorFilter from the imageFilter tree are set. " +
                    "The composite shader's colorFilter uniform is single-" +
                    "occupancy -- folding the two would need an " +
                    "SkComposeColorFilter extractor that the scaffolding slice " +
                    "doesn't ship. Set only one of the two."
            )
        }
        return ResolvedLayerImageFilterPlan(
            preBlurColorFilter = preBlurCF,
            blurParams = blur,
            effectiveColorFilter = postBlurCF ?: paint.colorFilter,
            offsetDx = offsetDx,
            offsetDy = offsetDy,
            materialiseChain = materialiseChain,
        )
    }

    /**
     * Phase G-saveLayer-colorFilter -- pack the layer paint's colour
     * filter into the 6-vec4f payload consumed by `layer_composite.wgsl`.
     *
     * Layout :
     *   [ 0..3 ] colorFilterKindMode : (kind, blendMode, 0, 0)
     *   [ 4..7 ] colorFilterParam0   : kind 1 -> premul colour ;
     *                                  kind 2 -> matrix row 0
     *   [ 8..11] colorFilterParam1   : matrix row 1
     *   [12..15] colorFilterParam2   : matrix row 2
     *   [16..19] colorFilterParam3   : matrix row 3
     *   [20..23] colorFilterBias     : per-row bias (R, G, B, A)
     *
     * Returns a 24-element [FloatArray] zeroed at kind 0 for the
     * identity / unsupported path. Supported variants :
     *  - `SkColorFilters.Blend(colour, mode)` -> kind = 1. The constant
     *    [SkColor] is decomposed to non-premul float RGBA and then
     *    premultiplied in-shader-friendly form (R*A, G*A, B*A, A).
     *  - `SkColorFilters.Matrix(20 floats)` -> kind = 2. The 20 row-
     *    major floats are unpacked into 4 vec4f rows (4 coefficients
     *    each) + a 1 vec4f bias (5th column per row).
     *
     * All other variants return the identity payload -- the shader
     * fast-path through `kind == 0` makes the composite bit-iso with
     * the no-filter case.
     */
    private fun packLayerCompositeColorFilter(filter: org.skia.foundation.SkColorFilter?): FloatArray {
        val out = FloatArray(24) // 6 vec4f * 4 floats each.
        if (filter == null) return out
        val blendParams = filter.asBlendModeFilter()
        if (blendParams != null) {
            out[0] = 1f                                  // kind = 1
            out[1] = blendParams.mode.ordinal.toFloat()  // SkBlendMode ordinal
            val c = blendParams.colour
            val ca = ((c ushr 24) and 0xFF) / 255f
            val cr = ((c ushr 16) and 0xFF) / 255f
            val cg = ((c ushr 8)  and 0xFF) / 255f
            val cb = ((c       )  and 0xFF) / 255f
            // Premul the constant colour -- the shader's blend operates
            // on premul vec4fs, matching SkBlendColorFilter's CPU path.
            out[4] = cr * ca
            out[5] = cg * ca
            out[6] = cb * ca
            out[7] = ca
            return out
        }
        val matrixParams = filter.asMatrixFilter()
        if (matrixParams != null) {
            out[0] = 2f // kind = 2
            // matrix is row-major, 20 floats : 4 rows of (R, G, B, A
            // coefs + bias). Pack each row's 4 coefs into a vec4f and
            // the 4 biases into the shared bias vec4f.
            val m = matrixParams.matrix
            // Row 0 (R) -- coefs (m0..m3), bias m4.
            out[4]  = m[0]; out[5]  = m[1]; out[6]  = m[2];  out[7]  = m[3]
            // Row 1 (G) -- coefs (m5..m8), bias m9.
            out[8]  = m[5]; out[9]  = m[6]; out[10] = m[7];  out[11] = m[8]
            // Row 2 (B) -- coefs (m10..m13), bias m14.
            out[12] = m[10]; out[13] = m[11]; out[14] = m[12]; out[15] = m[13]
            // Row 3 (A) -- coefs (m15..m18), bias m19.
            out[16] = m[15]; out[17] = m[16]; out[18] = m[17]; out[19] = m[18]
            // Bias vec4f -- (R, G, B, A) biases (m4, m9, m14, m19).
            out[20] = m[4]; out[21] = m[9]; out[22] = m[14]; out[23] = m[19]
            return out
        }
        // Unsupported variant -- drop the filter, fall through to the
        // no-filter composite path (matches the pre-slice behaviour).
        return out
    }

    /**
     * Phase G-saveLayer-imageFilter-crop/-tile/-magnifier -- pack one of
     * the three pure UV-remap variants into the 3-vec4f payload consumed
     * by `layer_composite.wgsl`. Returns `null` when `paint.imageFilter`
     * is none of these variants, in which case the dispatch falls
     * through to the existing Blur / Offset / DropShadow / Compose
     * resolver path.
     *
     * Layout (12 floats, 3 vec4f) :
     *   [ 0..3 ] imageFilterKindMode : (kind, tileMode, zoom, inset)
     *   [ 4..7 ] imageFilterRectA    : (left, top, right, bottom)
     *                                  -- Crop rect, Magnifier lens,
     *                                  or Tile dst rect.
     *   [ 8..11] imageFilterRectB    : (left, top, right, bottom)
     *                                  -- Tile src rect ; else zeroed.
     *
     * The rect coordinates are translated into layer-pixel space here :
     * the [SkImageFilter] API ships rectangles in device-pixel coords,
     * but the shader operates after `dstOrigin` subtraction (i.e. in
     * layer-pixel coords). The saveLayer composite runs at the device's
     * identity CTM, so the conversion is just `rect.translate(-origin)`
     * -- folded directly into the payload by the call site that knows
     * `originX` / `originY`.
     *
     * Wait -- that's wrong : we DON'T know the dstOrigin here. The
     * coordinate domain of `paint.imageFilter` rectangles is the LAYER's
     * own pixel space (the imageFilter is applied during the composite,
     * to the layer's pixels). Upstream Skia treats `lensBounds` / Crop
     * `rect` / Tile rects as device-space, but since the saveLayer
     * composite happens after the layer's draws and at identity CTM,
     * the rectangles align with the layer's local pixel grid 1:1 modulo
     * the dst-origin shift. We bake the dst-origin shift into the
     * payload at the call site, where it has the origin handy.
     *
     * To keep this helper self-contained and parameter-light, we ship
     * the raw rects unchanged ; the shader subtracts `dstOrigin` from
     * the fragment coord BEFORE applying the remap, so the rects must
     * also be in that same (post-origin-subtraction) space. Translation
     * happens at the call site, not here.
     *
     * Validation : `input == null` is enforced (a non-null child would
     * need a render-to-texture pre-pass that the first slice doesn't
     * ship). `paint.colorFilter` is enforced to be null (the composite
     * shader's colorFilter slot is single-occupancy and the UV-remap
     * branch may interact with it -- this slice keeps the two
     * orthogonal).
     */
    private fun resolveCropNonNullOffsetPrePassPlan(paint: SkPaint?): CropNonNullOffsetPrePassPlan? {
        val cropParams = paint?.imageFilter?.asCropImageFilter() ?: return null
        val childOffset = cropParams.input?.asOffsetImageFilter()
            ?: return null
        if (cropParams.tileMode != SkTileMode.kDecal ||
            childOffset.input != null ||
            paint.colorFilter != null
        ) {
            return null
        }
        return CropNonNullOffsetPrePassPlan(
            cropRect = cropParams.rect,
            cropTileMode = cropParams.tileMode,
            offsetDx = floor(childOffset.dx + 0.5f).toInt(),
            offsetDy = floor(childOffset.dy + 0.5f).toInt(),
        )
    }

    private fun shouldProbeFor247CropOffsetScratch(
        originX: Int,
        originY: Int,
        layerWidth: Int,
        layerHeight: Int,
        cropNonNullOffsetPrePass: CropNonNullOffsetPrePassPlan,
    ): Boolean {
        if (System.getProperty(WEBGPU_FOR247_CROP_OFFSET_SCRATCH_PROBE_FLAG) != "true") {
            return false
        }
        return isSelectedCropOffsetPrePassProbeCase(
            originX = originX,
            originY = originY,
            layerWidth = layerWidth,
            layerHeight = layerHeight,
            cropNonNullOffsetPrePass = cropNonNullOffsetPrePass,
        )
    }

    private fun shouldProbeFor248FinalCropComposite(
        originX: Int,
        originY: Int,
        layerWidth: Int,
        layerHeight: Int,
        cropNonNullOffsetPrePass: CropNonNullOffsetPrePassPlan,
    ): Boolean {
        if (System.getProperty(WEBGPU_FOR248_FINAL_CROP_COMPOSITE_PROBE_FLAG) != "true") {
            return false
        }
        return isSelectedCropOffsetPrePassProbeCase(
            originX = originX,
            originY = originY,
            layerWidth = layerWidth,
            layerHeight = layerHeight,
            cropNonNullOffsetPrePass = cropNonNullOffsetPrePass,
        )
    }

    private fun isSelectedCropOffsetPrePassProbeCase(
        originX: Int,
        originY: Int,
        layerWidth: Int,
        layerHeight: Int,
        cropNonNullOffsetPrePass: CropNonNullOffsetPrePassPlan,
    ): Boolean {
        val crop = cropNonNullOffsetPrePass.cropRect
        return originX == 340 &&
            originY == 120 &&
            layerWidth == 80 &&
            layerHeight == 40 &&
            cropNonNullOffsetPrePass.offsetDx == 40 &&
            cropNonNullOffsetPrePass.offsetDy == 0 &&
            cropNonNullOffsetPrePass.cropTileMode == SkTileMode.kDecal &&
            crop.left == 40f &&
            crop.top == 0f &&
            crop.right == 80f &&
            crop.bottom == 40f
    }

    private fun packCropImageFilterPayload(rect: SkRect, tileMode: SkTileMode): FloatArray {
        val out = FloatArray(12)
        out[0] = 1f
        out[1] = tileMode.ordinal.toFloat()
        out[4] = rect.left
        out[5] = rect.top
        out[6] = rect.right
        out[7] = rect.bottom
        return out
    }

    private fun computeImageFilterUvRemapPayload(paint: SkPaint?): FloatArray? {
        val imf = paint?.imageFilter ?: return null
        if (resolveCropNonNullOffsetPrePassPlan(paint) != null) return null

        val cropParams = imf.asCropImageFilter()
        if (cropParams != null) {
            if (cropParams.input != null) {
                error(
                    "SkWebGpuDevice.compositeFrom refused route=webgpu.image-filter.crop-nonnull " +
                        "diagnostic=backend=GPU,reason=image-filter.crop-input-nonnull-prepass-required," +
                        "action=RefuseDiagnostic(image-filter.crop-input-nonnull-prepass-required): " +
                        "paint.imageFilter is a " +
                        "SkImageFilters.Crop(input = nonNull) with a non-null " +
                        "child filter. Only the input == null case is " +
                        "supported (Phase G-saveLayer-imageFilter-crop) -- a " +
                        "non-null child needs a render-to-texture pre-pass " +
                        "that the WebGPU layer composite pipeline cannot " +
                        "express yet."
                )
            }
            if (paint.colorFilter != null) {
                error(
                    "SkWebGpuDevice.compositeFrom : paint.imageFilter is a " +
                        "SkImageFilters.Crop combined with a paint.colorFilter " +
                        "-- not yet supported. The UV-remap and colour-filter " +
                        "branches are kept orthogonal in the first Crop slice " +
                        "; pre-fold the colour filter into the imageFilter " +
                        "tree via SkImageFilters.Compose(Crop, ColorFilter), " +
                        "or set only one of the two on the layer paint."
                )
            }
            return packCropImageFilterPayload(cropParams.rect, cropParams.tileMode)
        }

        val tileParams = imf.asTileImageFilter()
        if (tileParams != null) {
            if (tileParams.input != null) {
                error(
                    "SkWebGpuDevice.compositeFrom : paint.imageFilter is a " +
                        "SkImageFilters.Tile(input = nonNull) with a non-null " +
                        "child filter. Only the input == null case is " +
                        "supported (Phase G-saveLayer-imageFilter-tile)."
                )
            }
            if (paint.colorFilter != null) {
                error(
                    "SkWebGpuDevice.compositeFrom : paint.imageFilter is a " +
                        "SkImageFilters.Tile combined with a paint.colorFilter " +
                        "-- not yet supported. Use SkImageFilters.Compose to " +
                        "chain a ColorFilter onto the Tile, or set only one " +
                        "of the two on the layer paint."
                )
            }
            // Empty src -> degenerate (the shader's sw/sh > 0 guard
            // returns transparent). Match the CPU raster's empty-tile
            // semantic.
            val out = FloatArray(12)
            out[0] = 2f                                        // kind = 2
            // out[1..3] : tileMode / zoom / inset unused, zeroed.
            out[4] = tileParams.dst.left
            out[5] = tileParams.dst.top
            out[6] = tileParams.dst.right
            out[7] = tileParams.dst.bottom
            out[8]  = tileParams.src.left
            out[9]  = tileParams.src.top
            out[10] = tileParams.src.right
            out[11] = tileParams.src.bottom
            return out
        }

        val magParams = imf.asMagnifierImageFilter()
        if (magParams != null) {
            if (magParams.input != null) {
                error(
                    "SkWebGpuDevice.compositeFrom : paint.imageFilter is a " +
                        "SkImageFilters.Magnifier(input = nonNull) with a " +
                        "non-null child filter. Only the input == null case " +
                        "is supported (Phase G-saveLayer-imageFilter-" +
                        "magnifier)."
                )
            }
            if (paint.colorFilter != null) {
                error(
                    "SkWebGpuDevice.compositeFrom : paint.imageFilter is a " +
                        "SkImageFilters.Magnifier combined with a paint." +
                        "colorFilter -- not yet supported. Use SkImageFilters." +
                        "Compose to chain a ColorFilter onto the Magnifier, " +
                        "or set only one of the two on the layer paint."
                )
            }
            // Zoom <= 0 is the CPU raster's no-op convention ; the
            // shader's `inside && zoom > 0` guard mirrors it.
            val out = FloatArray(12)
            out[0] = 3f                                        // kind = 3
            // out[1] : tileMode unused for Magnifier, zeroed.
            out[2] = magParams.zoomAmount
            out[3] = magParams.inset
            out[4] = magParams.lensBounds.left
            out[5] = magParams.lensBounds.top
            out[6] = magParams.lensBounds.right
            out[7] = magParams.lensBounds.bottom
            // out[8..11] : RectB unused, zeroed.
            return out
        }
        return null
    }

    /**
     * Phase G-saveLayer-imageFilter-matrixTransform -- pack the inverse
     * of the user's 2x3 affine into the trailing 12-float payload that
     * `layer_composite.wgsl` reads as `(devToLayerRow0, devToLayerRow1,
     * samplingMode)`. The fragment shader applies the inverse to the
     * device-pixel coords `(pos.x, pos.y, 1)` to land in layer-pixel
     * coords ; the sampling-mode selector picks kNearest (mode = 1) or
     * kLinear (mode = 2) at that point.
     *
     * The inverse 2x3 has the same shape as the input (sx, kx, tx ; ky,
     * sy, ty) but the translation is recomputed via the standard 2x2
     * adjugate formula -- matches Skia's `SkMatrix::invert` affine path.
     *
     * `samplingMode` ordinal :
     *   1 = kNearest (default for the MatrixTransform identity case
     *                  too -- a kNearest sample on integer texel coords
     *                  collapses to the same texel the integer-grid
     *                  `textureLoad` would have returned),
     *   2 = kLinear.
     * `samplingMode == 0` is reserved for the no-MatrixTransform fast
     * path and **must not** be produced here -- callers that need that
     * payload should use the [IDENTITY_LAYER_MATRIX_12] sentinel.
     *
     * Returns 12 floats (3 vec4f -- row 0, row 1, samplingMode). The
     * `.w` slot of each row is zeroed (reserved for follow-up
     * perspective row).
     */
    private fun packLayerCompositeMatrixTransform(
        invMatrix: org.graphiks.math.SkMatrix,
        samplingModeOrdinal: Int,
    ): FloatArray {
        val out = FloatArray(12)
        out[0] = invMatrix.sx
        out[1] = invMatrix.kx
        out[2] = invMatrix.tx
        out[3] = 0f
        out[4] = invMatrix.ky
        out[5] = invMatrix.sy
        out[6] = invMatrix.ty
        out[7] = 0f
        out[8] = samplingModeOrdinal.toFloat()
        out[9] = 0f
        out[10] = 0f
        out[11] = 0f
        return out
    }

    /**
     * G2.x -- last [SkClipShape] pushed by [SkCanvas.bindClip]. Sampled
     * by [drawFillRect] at draw-record time, captured in the [RectDraw]
     * so the per-draw uniform encodes the clip alongside the rect
     * bounds. Other pipelines (gradients / bitmap shader / polygon /
     * stencil-and-cover) **do not** consume this slot yet -- they fall
     * back to the integer scissor (their current behaviour). When the
     * canvas's clip is a non-shape path on a non-rect-fill draw, the
     * canvas-side guard in [SkCanvas.bindClip] still throws. Future
     * slices widen the consumer set ; this first cut just covers
     * solid-color rect fills, the most common case.
    */
    private var activeClipShape: SkClipShape? = null
    private var strokeOutlineOverflowFallbackDepth: Int = 0
    private var activeDashIntervalCountForPathAaDiagnostics: Int? = null
    private var activeStrokeStyleForPathAaDiagnostics: StrokeStyleDiagnostics? = null

    private fun m60F16SourceFacingLaneRuntimeCandidateRequested(): Boolean =
        System.getProperty(WEBGPU_M60_F16_SOURCE_FACING_LANE_RUNTIME_CANDIDATE_FLAG, "false").toBoolean()

    private fun m60F16AaStencilCoverBandMetadataTransportEnabled(): Boolean =
        System.getProperty(WEBGPU_M60_F16_AA_STENCIL_COVER_BAND_METADATA_TRANSPORT_FLAG, "false").toBoolean() ||
            m60F16WidthQuantizedRenderFixFor431Requested

    private fun m60F16AaStencilCoverBandMetadata(paint: SkPaint): M60F16AaStencilCoverBandMetadata? {
        val style = activeStrokeStyleForPathAaDiagnostics ?: return null
        if (!m60F16AaStencilCoverBandMetadataTransportEnabled()) return null
        if (!targetColorSpaceBlend) return null
        if (intermediateFormat != GPUTextureFormat.RGBA16Float) return null
        if (width != 192 || height != 128) return null
        if (!System.getProperty(WEBGPU_STROKE_CAP_JOIN_EXPERIMENTAL_RENDER_FLAG, "false").toBoolean()) return null
        if (paint.blendMode != SkBlendMode.kSrcOver) return null
        if (paint.shader != null || paint.colorFilter != null || paint.maskFilter != null || paint.pathEffect != null) {
            return null
        }
        if (kotlin.math.abs(style.strokeWidth - 10f) > 0.001f) return null
        val sourceColor = paint.color
        return when {
            style.cap == "butt" && style.join == "bevel" && sourceColor == 0xFF0066CC.toInt() ->
                M60F16AaStencilCoverBandMetadata(
                    bandXStart = 0f,
                    bandXEnd = 48f,
                    strokeBandId = 1f,
                    capId = 1f,
                    joinId = 1f,
                    sourceFacingLeftMaxLocalX = 17f,
                    sourceFacingRightMinLocalX = 39f,
                )
            style.cap == "round" && style.join == "round" && sourceColor == 0xFF008A4C.toInt() ->
                M60F16AaStencilCoverBandMetadata(
                    bandXStart = 48f,
                    bandXEnd = 96f,
                    strokeBandId = 2f,
                    capId = 2f,
                    joinId = 2f,
                    sourceFacingLeftMaxLocalX = 17f,
                    sourceFacingRightMinLocalX = 39f,
                )
            style.cap == "square" && style.join == "bevel" && sourceColor == 0xFFB33C00.toInt() ->
                M60F16AaStencilCoverBandMetadata(
                    bandXStart = 96f,
                    bandXEnd = 192f,
                    strokeBandId = 3f,
                    capId = 3f,
                    joinId = 1f,
                    sourceFacingLeftMaxLocalX = 17f,
                    sourceFacingRightMinLocalX = 39f,
                )
            else -> null
        }
    }

    private fun m60F16SourceColorCorrectionProbeEnabled(paint: SkPaint): Boolean {
        val style = activeStrokeStyleForPathAaDiagnostics ?: return false
        // FOR-392 recognizes the source-facing lane candidate guard but
        // refuses to route it through the older draw-wide FOR-380 probe.
        if (m60F16SourceFacingLaneRuntimeCandidateRequested()) return false
        if (!targetColorSpaceBlend) return false
        if (intermediateFormat != GPUTextureFormat.RGBA16Float) return false
        if (!System.getProperty(WEBGPU_STROKE_CAP_JOIN_EXPERIMENTAL_RENDER_FLAG, "false").toBoolean()) return false
        if (!System.getProperty(WEBGPU_M60_F16_SOURCE_COLOR_CORRECTION_PROBE_FLAG, "false").toBoolean()) return false
        if (paint.blendMode != SkBlendMode.kSrcOver) return false
        if (paint.shader != null || paint.colorFilter != null || paint.maskFilter != null || paint.pathEffect != null) {
            return false
        }
        if (kotlin.math.abs(style.strokeWidth - 10f) > 0.001f) return false
        return when (style.cap to style.join) {
            "butt" to "bevel",
            "round" to "round",
            "square" to "bevel" -> true
            else -> false
        }
    }

