                    recordM60F16AaStencilCoverPostPassFormatUnsupported(i, d)
                } else if (res.m60F16AaStencilCoverPostPassReadbackBindGroup != null) {
                    encoder.clearBuffer(
                        res.m60F16AaStencilCoverPostPassReadbackStorage!!,
                        0uL,
                        res.m60F16AaStencilCoverPostPassReadbackBufferSize,
                    )
                    val pass = encoder.beginComputePass()
                    pass.setPipeline(m60F16AaStencilCoverPostPassReadbackPipeline)
                    pass.setBindGroup(0u, res.m60F16AaStencilCoverPostPassReadbackBindGroup)
                    pass.dispatchWorkgroups(M60_F16_AA_STENCIL_COVER_POST_PASS_READBACK_SAMPLE_COUNT)
                    pass.end()
                    encoder.copyBufferToBuffer(
                        source = res.m60F16AaStencilCoverPostPassReadbackStorage,
                        sourceOffset = 0uL,
                        destination = res.m60F16AaStencilCoverPostPassReadbackStaging!!,
                        destinationOffset = 0uL,
                        size = res.m60F16AaStencilCoverPostPassReadbackBufferSize,
                    )
                    m60F16AaStencilCoverPostPassPendingReadbacks +=
                        M60F16AaStencilCoverPostPassReadback(
                            metadata = M60F16AaStencilCoverPostPassReadbackMetadata(
                                drawIndex = i,
                                fillType = d.fillType.name,
                                blendMode = d.mode.name,
                                scissor = d.scissor.copyOf(),
                                edgeCount = d.edgeCount,
                                coverVertexCount = d.coverVerts.size / 2,
                            ),
                            staging = res.m60F16AaStencilCoverPostPassReadbackStaging,
                            bufferSize = res.m60F16AaStencilCoverPostPassReadbackBufferSize,
                        )
                }
                if (res.m60F16FragmentLaneDiagnosticStorage != null &&
                    res.m60F16FragmentLaneDiagnosticStaging != null
                ) {
                    encoder.copyBufferToBuffer(
                        source = res.m60F16FragmentLaneDiagnosticStorage,
                        sourceOffset = 0uL,
                        destination = res.m60F16FragmentLaneDiagnosticStaging,
                        destinationOffset = 0uL,
                        size = res.m60F16FragmentLaneDiagnosticBufferSize,
                    )
                }
                if (res.m60F16RuntimeIntegerLaneMaskProbeFor445Storage != null &&
                    res.m60F16RuntimeIntegerLaneMaskProbeFor445Staging != null
                ) {
                    encoder.copyBufferToBuffer(
                        source = res.m60F16RuntimeIntegerLaneMaskProbeFor445Storage,
                        sourceOffset = 0uL,
                        destination = res.m60F16RuntimeIntegerLaneMaskProbeFor445Staging,
                        destinationOffset = 0uL,
                        size = res.m60F16RuntimeIntegerLaneMaskProbeFor445BufferSize,
                    )
                    m60F16RuntimeIntegerLaneMaskProbeFor445PendingReadbacks +=
                        M60F16RuntimeIntegerLaneMaskProbeFor445Readback(
                            metadata = M60F16AaStencilCoverPostPassReadbackMetadata(
                                drawIndex = i,
                                fillType = d.fillType.name,
                                blendMode = d.mode.name,
                                scissor = d.scissor.copyOf(),
                                edgeCount = d.edgeCount,
                                coverVertexCount = d.coverVerts.size / 2,
                            ),
                            storage = res.m60F16RuntimeIntegerLaneMaskProbeFor445Storage,
                            staging = res.m60F16RuntimeIntegerLaneMaskProbeFor445Staging,
                            bufferSize = res.m60F16RuntimeIntegerLaneMaskProbeFor445BufferSize,
                        )
                }
                return@forEachIndexed
            }
            if (d is StencilCoverAaGradientDraw) {
                // G4.1.2 — same stencil-and-cover envelope as
                // [StencilCoverAaPolygonDraw], but the two cover sub-draws
                // bind the gradient pipeline (linear gradient lookup per
                // fragment instead of a uniform color). Stencil sub-pass
                // is identical to the solid-color variant.
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = colorView,
                                loadOp = loadOp,
                                clearValue = background,
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                        depthStencilAttachment = RenderPassDepthStencilAttachment(
                            view = depthStencilView,
                            stencilClearValue = 0u,
                            stencilLoadOp = GPULoadOp.Clear,
                            stencilStoreOp = GPUStoreOp.Discard,
                            stencilReadOnly = false,
                            depthReadOnly = true,
                        ),
                    ),
                ) {
                    setBindGroup(0u, res.bindGroup)
                    setScissorRect(
                        x = d.scissor[0].toUInt(),
                        y = d.scissor[1].toUInt(),
                        width = d.scissor[2].toUInt(),
                        height = d.scissor[3].toUInt(),
                    )
                    setPipeline(stencilWritePipeline)
                    setVertexBuffer(slot = 0u, buffer = res.vertexBuffer!!)
                    draw((d.stencilVerts.size / 2).toUInt())
                    setStencilReference(0u)
                    setVertexBuffer(slot = 0u, buffer = res.coverVertexBuffer!!)
                    setPipeline(
                        aaStencilCoverGradientPipelineFor(
                            d.mode, d.fillType, d.tileMode, CoverageSide.Inside,
                        ),
                    )
                    draw((d.coverVerts.size / 2).toUInt())
                    setPipeline(
                        aaStencilCoverGradientPipelineFor(
                            d.mode, d.fillType, d.tileMode, CoverageSide.Outside,
                        ),
                    )
                    draw((d.coverVerts.size / 2).toUInt())
                    end()
                }
                return@forEachIndexed
            }
            if (d is StencilCoverAaRadialGradientDraw) {
                // G4.2.2 -- mirror of the [StencilCoverAaGradientDraw]
                // dispatch above. Same stencil-write sub-pass, but the
                // two cover sub-draws bind the radial-gradient pipeline.
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = colorView,
                                loadOp = loadOp,
                                clearValue = background,
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                        depthStencilAttachment = RenderPassDepthStencilAttachment(
                            view = depthStencilView,
                            stencilClearValue = 0u,
                            stencilLoadOp = GPULoadOp.Clear,
                            stencilStoreOp = GPUStoreOp.Discard,
                            stencilReadOnly = false,
                            depthReadOnly = true,
                        ),
                    ),
                ) {
                    setBindGroup(0u, res.bindGroup)
                    setScissorRect(
                        x = d.scissor[0].toUInt(),
                        y = d.scissor[1].toUInt(),
                        width = d.scissor[2].toUInt(),
                        height = d.scissor[3].toUInt(),
                    )
                    setPipeline(stencilWritePipeline)
                    setVertexBuffer(slot = 0u, buffer = res.vertexBuffer!!)
                    draw((d.stencilVerts.size / 2).toUInt())
                    setStencilReference(0u)
                    setVertexBuffer(slot = 0u, buffer = res.coverVertexBuffer!!)
                    setPipeline(
                        aaStencilCoverRadialGradientPipelineFor(
                            d.mode, d.fillType, d.tileMode, CoverageSide.Inside,
                        ),
                    )
                    draw((d.coverVerts.size / 2).toUInt())
                    setPipeline(
                        aaStencilCoverRadialGradientPipelineFor(
                            d.mode, d.fillType, d.tileMode, CoverageSide.Outside,
                        ),
                    )
                    draw((d.coverVerts.size / 2).toUInt())
                    end()
                }
                return@forEachIndexed
            }
            if (d is StencilCoverAaConicalGradientDraw) {
                // G4.4.3 -- conical gradient (kRadial sub-case) on a non-rect
                // path. Mirror of the linear / radial / sweep stencil-cover
                // gradient dispatches above ; same stencil-write sub-pass,
                // two cover sub-draws bind the conical-kRadial pipeline.
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = colorView,
                                loadOp = loadOp,
                                clearValue = background,
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                        depthStencilAttachment = RenderPassDepthStencilAttachment(
                            view = depthStencilView,
                            stencilClearValue = 0u,
                            stencilLoadOp = GPULoadOp.Clear,
                            stencilStoreOp = GPUStoreOp.Discard,
                            stencilReadOnly = false,
                            depthReadOnly = true,
                        ),
                    ),
                ) {
                    setBindGroup(0u, res.bindGroup)
                    setScissorRect(
                        x = d.scissor[0].toUInt(),
                        y = d.scissor[1].toUInt(),
                        width = d.scissor[2].toUInt(),
                        height = d.scissor[3].toUInt(),
                    )
                    setPipeline(stencilWritePipeline)
                    setVertexBuffer(slot = 0u, buffer = res.vertexBuffer!!)
                    draw((d.stencilVerts.size / 2).toUInt())
                    setStencilReference(0u)
                    setVertexBuffer(slot = 0u, buffer = res.coverVertexBuffer!!)
                    setPipeline(
                        aaStencilCoverConicalGradientPipelineFor(
                            d.mode, d.fillType, d.tileMode, CoverageSide.Inside,
                        ),
                    )
                    draw((d.coverVerts.size / 2).toUInt())
                    setPipeline(
                        aaStencilCoverConicalGradientPipelineFor(
                            d.mode, d.fillType, d.tileMode, CoverageSide.Outside,
                        ),
                    )
                    draw((d.coverVerts.size / 2).toUInt())
                    end()
                }
                return@forEachIndexed
            }
            if (d is StencilCoverAaConicalFocalGradientDraw) {
                // G4.4.3 -- conical gradient (focal-inside well-behaved sub-case)
                // on a non-rect path. Mirror of the kRadial dispatch just above
                // with the focal-inside pipeline + uniform layout.
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = colorView,
                                loadOp = loadOp,
                                clearValue = background,
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                        depthStencilAttachment = RenderPassDepthStencilAttachment(
                            view = depthStencilView,
                            stencilClearValue = 0u,
                            stencilLoadOp = GPULoadOp.Clear,
                            stencilStoreOp = GPUStoreOp.Discard,
                            stencilReadOnly = false,
                            depthReadOnly = true,
                        ),
                    ),
                ) {
                    setBindGroup(0u, res.bindGroup)
                    setScissorRect(
                        x = d.scissor[0].toUInt(),
                        y = d.scissor[1].toUInt(),
                        width = d.scissor[2].toUInt(),
                        height = d.scissor[3].toUInt(),
                    )
                    setPipeline(stencilWritePipeline)
                    setVertexBuffer(slot = 0u, buffer = res.vertexBuffer!!)
                    draw((d.stencilVerts.size / 2).toUInt())
                    setStencilReference(0u)
                    setVertexBuffer(slot = 0u, buffer = res.coverVertexBuffer!!)
                    setPipeline(
                        aaStencilCoverConicalFocalGradientPipelineFor(
                            d.mode, d.fillType, d.tileMode, CoverageSide.Inside,
                        ),
                    )
                    draw((d.coverVerts.size / 2).toUInt())
                    setPipeline(
                        aaStencilCoverConicalFocalGradientPipelineFor(
                            d.mode, d.fillType, d.tileMode, CoverageSide.Outside,
                        ),
                    )
                    draw((d.coverVerts.size / 2).toUInt())
                    end()
                }
                return@forEachIndexed
            }
            if (d is StencilCoverAaBitmapShaderDraw) {
                // G5.2.1 -- mirror of the gradient stencil-cover dispatches
                // above ; same two-sub-pass structure (stencil-write +
                // inside/outside cover), the cover sub-draws bind the
                // bitmap-shader pipeline. The stencil-write pass uses the
                // dedicated [aaStencilCoverBitmapShaderStencilPipeline]
                // (3-binding pipeline layout) so the bind group satisfies
                // both passes' layouts in one go.
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = colorView,
                                loadOp = loadOp,
                                clearValue = background,
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                        depthStencilAttachment = RenderPassDepthStencilAttachment(
                            view = depthStencilView,
                            stencilClearValue = 0u,
                            stencilLoadOp = GPULoadOp.Clear,
                            stencilStoreOp = GPUStoreOp.Discard,
                            stencilReadOnly = false,
                            depthReadOnly = true,
                        ),
                    ),
                ) {
                    setBindGroup(0u, res.bindGroup)
                    setScissorRect(
                        x = d.scissor[0].toUInt(),
                        y = d.scissor[1].toUInt(),
                        width = d.scissor[2].toUInt(),
                        height = d.scissor[3].toUInt(),
                    )
                    setPipeline(aaStencilCoverBitmapShaderStencilPipeline)
                    setVertexBuffer(slot = 0u, buffer = res.vertexBuffer!!)
                    draw((d.stencilVerts.size / 2).toUInt())
                    setStencilReference(0u)
                    setVertexBuffer(slot = 0u, buffer = res.coverVertexBuffer!!)
                    setPipeline(
                        aaStencilCoverBitmapShaderPipelineFor(
                            d.mode, d.fillType, CoverageSide.Inside,
                        ),
                    )
                    draw((d.coverVerts.size / 2).toUInt())
                    setPipeline(
                        aaStencilCoverBitmapShaderPipelineFor(
                            d.mode, d.fillType, CoverageSide.Outside,
                        ),
                    )
                    draw((d.coverVerts.size / 2).toUInt())
                    end()
                }
                return@forEachIndexed
            }
            if (d is StencilCoverAaSweepGradientDraw) {
                // G4.3.2 -- mirror of the [StencilCoverAaGradientDraw] /
                // [StencilCoverAaRadialGradientDraw] dispatches above.
                // Same stencil-write sub-pass, but the two cover sub-draws
                // bind the sweep-gradient pipeline.
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = colorView,
                                loadOp = loadOp,
                                clearValue = background,
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                        depthStencilAttachment = RenderPassDepthStencilAttachment(
                            view = depthStencilView,
                            stencilClearValue = 0u,
                            stencilLoadOp = GPULoadOp.Clear,
                            stencilStoreOp = GPUStoreOp.Discard,
                            stencilReadOnly = false,
                            depthReadOnly = true,
                        ),
                    ),
                ) {
                    setBindGroup(0u, res.bindGroup)
                    setScissorRect(
                        x = d.scissor[0].toUInt(),
                        y = d.scissor[1].toUInt(),
                        width = d.scissor[2].toUInt(),
                        height = d.scissor[3].toUInt(),
                    )
                    setPipeline(stencilWritePipeline)
                    setVertexBuffer(slot = 0u, buffer = res.vertexBuffer!!)
                    draw((d.stencilVerts.size / 2).toUInt())
                    setStencilReference(0u)
                    setVertexBuffer(slot = 0u, buffer = res.coverVertexBuffer!!)
                    setPipeline(
                        aaStencilCoverSweepGradientPipelineFor(
                            d.mode, d.fillType, d.tileMode, CoverageSide.Inside,
                        ),
                    )
                    draw((d.coverVerts.size / 2).toUInt())
                    setPipeline(
                        aaStencilCoverSweepGradientPipelineFor(
                            d.mode, d.fillType, d.tileMode, CoverageSide.Outside,
                        ),
                    )
                    draw((d.coverVerts.size / 2).toUInt())
                    end()
                }
                return@forEachIndexed
            }
            if (d is BlurredShadedPathDraw) {
                // Phase MaskFilter-blur-shaded -- two render passes,
                // mirrors the solid-paint variant below but :
                //   - the H pass samples the SHADED layer (RGBA premul)
                //     instead of a white-tinted alpha-only shape mask,
                //   - the V pass combines the blurred RGBA B with the
                //     original shaded layer A per SkBlurStyle and
                //     blends onto the parent. No paint-colour fold (A
                //     already carries the final shader output).
                val hView = res.scratchHView!!
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = hView,
                                loadOp = GPULoadOp.Clear,
                                clearValue = Color(0.0, 0.0, 0.0, 0.0),
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                    ),
                ) {
                    setPipeline(blurShadedHorizontalPipeline)
                    setBindGroup(0u, res.bindGroup)
                    setScissorRect(
                        x = 0u, y = 0u,
                        width = d.srcWidth.toUInt(),
                        height = d.srcHeight.toUInt(),
                    )
                    draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    end()
                }
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = colorView,
                                loadOp = loadOp,
                                clearValue = background,
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                    ),
                ) {
                    setPipeline(blurShadedVerticalPipelineFor(d.mode))
                    setBindGroup(0u, res.secondaryBindGroup!!)
                    setScissorRect(
                        x = d.scissor[0].toUInt(),
                        y = d.scissor[1].toUInt(),
                        width = d.scissor[2].toUInt(),
                        height = d.scissor[3].toUInt(),
                    )
                    draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    end()
                }
                return@forEachIndexed
            }
            if (d is BlurredPathDraw) {
                // Phase MaskFilter-blur -- single-stage (sigma <=
                // ~10) takes the historical two-pass path :
                //   1. H pass : sample shape mask, write to scratchH
                //      (cleared). No blend.
                //   2. V pass + composite : sample scratchH, modulate
                //      by paint colour, blend onto the parent
                //      intermediate via the pipeline's blend state.
                //
                // Phase MaskFilter-blur-cascade -- multi-stage (sigma
                // above ~10) :
                //   1. N downsample passes : shapeMask -> down1 ->
                //      down2 -> ... -> downN (each 2x bilinear).
                //   2. H pass at the smallest level : downN ->
                //      scratchH (sized like downN).
                //   3. Inner V pass : scratchH -> cascade.innerV
                //      (same size). Pure Gaussian blur, no style or
                //      paint fold.
                //   4. N upsample passes : innerV -> up_{n-1} -> ...
                //      -> up_0 (full resolution).
                //   5. Final composite : sample up_0 (full-res blurred
                //      mask) + the sharp shape mask, apply style +
                //      paint, blend onto the parent intermediate.
                //
                // All scratch textures are freshly allocated per draw
                // (see [drawPathWithBlurMaskFilterIfApplicable] /
                // [buildBlurCascade]) so each pass starts with Clear
                // loadOp. The colour-attachment loadOp on the final
                // composite matches the rest of [flush] (Clear for
                // the first draw, Load otherwise) so the composite
                // stacks with prior draws.
                if (d.cascade != null) {
                    val cascade = d.cascade
                    // 1. Downsample chain. Each pass scissor is its
                    //    destination level's full extent.
                    for (i in cascade.downLevels.indices) {
                        val dst = cascade.downLevels[i]
                        encoder.beginRenderPass(
                            RenderPassDescriptor(
                                colorAttachments = listOf(
                                    RenderPassColorAttachment(
                                        view = dst.view,
                                        loadOp = GPULoadOp.Clear,
                                        clearValue = Color(0.0, 0.0, 0.0, 0.0),
                                        storeOp = GPUStoreOp.Store,
                                    ),
                                ),
                            ),
                        ) {
                            setPipeline(blurDownsamplePipeline)
                            setBindGroup(0u, res.cascadeDownsampleBindGroups[i])
                            setScissorRect(
                                x = 0u, y = 0u,
                                width = dst.width.toUInt(),
                                height = dst.height.toUInt(),
                            )
                            draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                            end()
                        }
                    }
                    // 2. H pass at the smallest level (scratchH).
                    val hView = res.scratchHView!!
                    val innermost = cascade.downLevels.last()
                    encoder.beginRenderPass(
                        RenderPassDescriptor(
                            colorAttachments = listOf(
                                RenderPassColorAttachment(
                                    view = hView,
                                    loadOp = GPULoadOp.Clear,
                                    clearValue = Color(0.0, 0.0, 0.0, 0.0),
                                    storeOp = GPUStoreOp.Store,
                                ),
                            ),
                        ),
                    ) {
                        setPipeline(blurHorizontalPipeline)
                        setBindGroup(0u, res.bindGroup)
                        setScissorRect(
                            x = 0u, y = 0u,
                            width = innermost.width.toUInt(),
                            height = innermost.height.toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                        end()
                    }
                    // 3. Inner V pass : scratchH -> cascade.innerV.
                    encoder.beginRenderPass(
                        RenderPassDescriptor(
                            colorAttachments = listOf(
                                RenderPassColorAttachment(
                                    view = cascade.innerVView,
                                    loadOp = GPULoadOp.Clear,
                                    clearValue = Color(0.0, 0.0, 0.0, 0.0),
                                    storeOp = GPUStoreOp.Store,
                                ),
                            ),
                        ),
                    ) {
                        setPipeline(blurCascadeInnerVerticalPipeline)
                        setBindGroup(0u, res.cascadeInnerVBindGroup!!)
                        setScissorRect(
                            x = 0u, y = 0u,
                            width = innermost.width.toUInt(),
                            height = innermost.height.toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                        end()
                    }
                    // 4. Upsample chain. The last upsample lands at
                    //    full resolution (maskW x maskH).
                    for (i in cascade.upLevels.indices) {
                        val dst = cascade.upLevels[i]
                        encoder.beginRenderPass(
                            RenderPassDescriptor(
                                colorAttachments = listOf(
                                    RenderPassColorAttachment(
                                        view = dst.view,
                                        loadOp = GPULoadOp.Clear,
                                        clearValue = Color(0.0, 0.0, 0.0, 0.0),
                                        storeOp = GPUStoreOp.Store,
                                    ),
                                ),
                            ),
                        ) {
                            setPipeline(blurUpsamplePipeline)
                            setBindGroup(0u, res.cascadeUpsampleBindGroups[i])
                            setScissorRect(
                                x = 0u, y = 0u,
                                width = dst.width.toUInt(),
                                height = dst.height.toUInt(),
                            )
                            draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                            end()
                        }
                    }
                    // 5. Final composite onto the parent intermediate.
                    encoder.beginRenderPass(
                        RenderPassDescriptor(
                            colorAttachments = listOf(
                                RenderPassColorAttachment(
                                    view = colorView,
                                    loadOp = loadOp,
                                    clearValue = background,
                                    storeOp = GPUStoreOp.Store,
                                ),
                            ),
                        ),
                    ) {
                        setPipeline(blurCascadeCompositePipelineFor(d.mode))
                        setBindGroup(0u, res.cascadeCompositeBindGroup!!)
                        setScissorRect(
                            x = d.scissor[0].toUInt(),
                            y = d.scissor[1].toUInt(),
                            width = d.scissor[2].toUInt(),
                            height = d.scissor[3].toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                        end()
                    }
                    return@forEachIndexed
                }
                // Single-stage path.
                val hView = res.scratchHView!!
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = hView,
                                loadOp = GPULoadOp.Clear,
                                clearValue = Color(0.0, 0.0, 0.0, 0.0),
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                    ),
                ) {
                    setPipeline(blurHorizontalPipeline)
                    setBindGroup(0u, res.bindGroup)
                    // H pass scissor : the full scratch extent. The
                    // shader's own bounds guard handles any leakage.
                    setScissorRect(
                        x = 0u, y = 0u,
                        width = d.srcWidth.toUInt(),
                        height = d.srcHeight.toUInt(),
                    )
                    draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    end()
                }
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = colorView,
                                loadOp = loadOp,
                                clearValue = background,
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                    ),
                ) {
                    setPipeline(blurVerticalPipelineFor(d.mode))
                    setBindGroup(0u, res.secondaryBindGroup!!)
                    setScissorRect(
                        x = d.scissor[0].toUInt(),
                        y = d.scissor[1].toUInt(),
                        width = d.scissor[2].toUInt(),
                        height = d.scissor[3].toUInt(),
                    )
                    draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    end()
                }
                return@forEachIndexed
            }
            if (d is NonNativeBlendLayerCompositeDraw) {
                // Phase G-saveLayer-blend -- two (or three) render passes :
                //   0. (When i == 0) Pre-clear the parent intermediate to
                //      the background colour. The snapshot pass below
                //      samples the parent intermediate ; if no prior
                //      draws have populated it, the snapshot would carry
                //      uninitialised pixels. The fast `LayerCompositeDraw`
                //      path piggybacks the clear onto its own render
                //      pass (via `loadOp = Clear`), but our snapshot
                //      pass targets the scratch, not the parent, so we
                //      must clear separately.
                //   1. Snapshot : sample the parent's intermediate (via
                //      `layer_composite.wgsl` with kSrc blend, identity
                //      paintColor, identity colour filter), write to the
                //      per-composite snapshot scratch. The snapshot is
                //      `(width, height)` of the parent and the shader's
                //      dst-pixel-to-layer-pixel mapping with origin (0, 0)
                //      reduces to a straight `textureLoad` copy.
                //   2. Blend composite : sample the layer texture (source)
                //      + snapshot (destination), evaluate the SkBlendMode
                //      in the fragment stage via
                //      `layer_composite_blend.wgsl`, write to the parent
                //      intermediate with `BlendState = kSrc`. The
                //      `loadOp` is `Load` here -- we already cleared (or
                //      a prior draw populated the intermediate) and we
                //      need to preserve pixels outside the scissor.
                if (i == 0) {
                    encoder.beginRenderPass(
                        RenderPassDescriptor(
                            colorAttachments = listOf(
                                RenderPassColorAttachment(
                                    view = colorView,
                                    loadOp = GPULoadOp.Clear,
                                    clearValue = background,
                                    storeOp = GPUStoreOp.Store,
                                ),
                            ),
                        ),
                    ) {
                        end()
                    }
                }
                val snapView = res.scratchVView!!
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = snapView,
                                loadOp = GPULoadOp.Clear,
                                clearValue = Color(0.0, 0.0, 0.0, 0.0),
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                    ),
                ) {
                    // Snapshot pass : reuse the kSrc layer composite
                    // pipeline. Scissor covers the parent's full extent
                    // so the snapshot's RGBA matches the parent texel-
                    // for-texel under the dst rect.
                    setPipeline(layerCompositePipelineFor(SkBlendMode.kSrc))
                    setBindGroup(0u, res.bindGroup)
                    setScissorRect(
                        x = 0u, y = 0u,
                        width = width.toUInt(),
                        height = height.toUInt(),
                    )
                    draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    end()
                }
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = colorView,
                                // Always Load -- we either cleared above
                                // (i == 0) or a prior draw populated the
                                // parent. Clearing again here would wipe
                                // those pixels.
                                loadOp = GPULoadOp.Load,
                                clearValue = background,
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                    ),
                ) {
                    setPipeline(layerCompositeBlendPipeline)
                    setBindGroup(0u, res.secondaryBindGroup!!)
                    setScissorRect(
                        x = d.scissor[0].toUInt(),
                        y = d.scissor[1].toUInt(),
                        width = d.scissor[2].toUInt(),
                        height = d.scissor[3].toUInt(),
                    )
                    draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    end()
                }
                return@forEachIndexed
            }
            if (d is BlurredLayerCompositeDraw) {
                // Phase G-saveLayer-imageFilter-blur -- three render
                // passes :
                //   1. H pass : sample layer texture (or pre-CF scratch
                //      when a pre-blur CF is present, see below), write
                //      to scratchH (cleared). No blend.
                //   2. V pass : sample scratchH, write to scratchV
                //      (cleared). No blend. Output is blurred premul
                //      RGBA, no paint-colour fold.
                //   3. Composite : sample scratchV, modulate by
                //      paintColor, apply colorFilter, blend onto the
                //      parent intermediate via the layer composite
                //      pipeline (same code path as the no-filter
                //      saveLayer).
                //
                // Phase G-saveLayer-imageFilter-compose -- when a pre-
                // blur ColorFilter is present (from a Compose chain),
                // an extra pass runs *before* the H pass : sample the
                // layer texture, apply the colour filter via
                // `layer_composite.wgsl` with kSrc blend, write to the
                // pre-CF scratch. The H pass then reads from the
                // pre-CF scratch (its bind group's binding 1 was wired
                // by [buildBlurredLayerCompositeDrawResources]).
                if (res.scratchPreCfView != null && res.quaternaryBindGroup != null) {
                    val preCfView = res.scratchPreCfView
                    encoder.beginRenderPass(
                        RenderPassDescriptor(
                            colorAttachments = listOf(
                                RenderPassColorAttachment(
                                    view = preCfView,
                                    loadOp = GPULoadOp.Clear,
                                    clearValue = Color(0.0, 0.0, 0.0, 0.0),
                                    storeOp = GPUStoreOp.Store,
                                ),
                            ),
                        ),
                    ) {
                        setPipeline(layerCompositePipelineFor(SkBlendMode.kSrc))
                        setBindGroup(0u, res.quaternaryBindGroup)
                        setScissorRect(
                            x = 0u, y = 0u,
                            width = d.layerWidth.toUInt(),
                            height = d.layerHeight.toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                        end()
                    }
                }
                val hView = res.scratchHView!!
                val vView = res.scratchVView!!
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = hView,
                                loadOp = GPULoadOp.Clear,
                                clearValue = Color(0.0, 0.0, 0.0, 0.0),
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                    ),
                ) {
                    setPipeline(blurImageFilterHorizontalPipeline)
                    setBindGroup(0u, res.bindGroup)
                    setScissorRect(
                        x = 0u, y = 0u,
                        width = d.layerWidth.toUInt(),
                        height = d.layerHeight.toUInt(),
                    )
                    draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    end()
                }
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = vView,
                                loadOp = GPULoadOp.Clear,
                                clearValue = Color(0.0, 0.0, 0.0, 0.0),
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                    ),
                ) {
                    setPipeline(blurImageFilterVerticalPipeline)
                    setBindGroup(0u, res.secondaryBindGroup!!)
                    setScissorRect(
                        x = 0u, y = 0u,
                        width = d.layerWidth.toUInt(),
                        height = d.layerHeight.toUInt(),
                    )
                    draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    end()
                }
                // N1 -- chain-of-passes : when materialising, the
                // composite pass writes into the layer-sized scratch
                // instead of the parent's `colorView`. The scratch
                // starts blank (loadOp = Clear) and the blend mode is
                // forced to `kSrc` (the materialised pixels are the
                // only contribution). Non-materialise path keeps the
                // existing parent composite shape.
                val blurredOutView = d.materializeTargetView ?: colorView
                val blurredLoadOp =
                    if (d.materializeTargetView != null) GPULoadOp.Clear
                    else loadOp
                val blurredMode =
                    if (d.materializeTargetView != null) SkBlendMode.kSrc
                    else d.mode
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = blurredOutView,
                                loadOp = blurredLoadOp,
                                clearValue = background,
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                    ),
                ) {
                    setPipeline(layerCompositePipelineFor(blurredMode))
                    setBindGroup(0u, res.tertiaryBindGroup!!)
                    setScissorRect(
                        x = d.scissor[0].toUInt(),
                        y = d.scissor[1].toUInt(),
                        width = d.scissor[2].toUInt(),
                        height = d.scissor[3].toUInt(),
                    )
                    draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    end()
                }
                return@forEachIndexed
            }
            if (d is DropShadowLayerCompositeDraw) {
                // Phase G-saveLayer-imageFilter-dropshadow -- four render
                // passes :
                //   1. H pass : sample layer texture, write to scratchH
                //      (cleared). No blend. Same shader as the plain
                //      blur ImageFilter -- the colorize-to-shadow step
                //      runs at pass 3 via the colour-filter slot.
                //   2. V pass : sample scratchH, write to scratchV
                //      (cleared). No blend. Output is the layer's
                //      premul RGBA blurred along both axes.
                //   3. Composite (shadow) : sample scratchV, run the
                //      packed `Blend(shadowColor, kSrcIn)` colour
                //      filter (kind = 1, mode = 5) which masks the
                //      blurred RGB out and keeps the alpha * shadowColor
                //      product, then blend onto the parent intermediate
                //      via the layer-composite pipeline at the offset
                //      origin.
                //   4. Composite (original) : sample the layer texture
                //      directly, modulate by paintColor, apply the
                //      paint's regular colour filter, blend onto the
                //      parent intermediate at the original origin.
                //      Lands the layer content ON TOP of the shadow.
                val hView = res.scratchHView!!
                val vView = res.scratchVView!!
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = hView,
                                loadOp = GPULoadOp.Clear,
                                clearValue = Color(0.0, 0.0, 0.0, 0.0),
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                    ),
                ) {
                    setPipeline(blurImageFilterHorizontalPipeline)
                    setBindGroup(0u, res.bindGroup)
                    setScissorRect(
                        x = 0u, y = 0u,
                        width = d.layerWidth.toUInt(),
                        height = d.layerHeight.toUInt(),
                    )
                    draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    end()
                }
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = vView,
                                loadOp = GPULoadOp.Clear,
                                clearValue = Color(0.0, 0.0, 0.0, 0.0),
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                    ),
                ) {
                    setPipeline(blurImageFilterVerticalPipeline)
                    setBindGroup(0u, res.secondaryBindGroup!!)
                    setScissorRect(
                        x = 0u, y = 0u,
                        width = d.layerWidth.toUInt(),
                        height = d.layerHeight.toUInt(),
                    )
                    draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    end()
                }
                // L1a -- when materialising, both sub-passes target the
                // scratch texture instead of the parent's `colorView`. The
                // first sub-pass uses `loadOp = Clear` to wipe the scratch
                // (replaces the parent's `loadOp` which would carry the
                // intermediate-initialised state). The second sub-pass uses
                // `loadOp = Load` to compose on top. The blend mode for the
                // shadow sub-pass is forced to `kSrc` (the scratch starts
                // blank, the shadow IS the first contribution) ; the
                // original sub-pass keeps `kSrcOver` (lands on top of the
                // shadow). When NOT materialising, the existing flow runs
                // unchanged : both sub-passes target the parent's
                // `colorView` with `d.mode` (= kSrcOver, gated at the
                // dispatch site).
                val dropShadowOutView = d.materializeTargetView ?: colorView
                val dropShadowFirstLoadOp =
                    if (d.materializeTargetView != null) GPULoadOp.Clear
                    else loadOp
                val dropShadowShadowMode =
                    if (d.materializeTargetView != null) SkBlendMode.kSrc
                    else d.mode
                // Shadow composite : skip when the scissor is empty
                // (shadow clipped entirely outside parent bounds).
                if (d.shadowScissor[2] > 0 && d.shadowScissor[3] > 0) {
                    encoder.beginRenderPass(
                        RenderPassDescriptor(
                            colorAttachments = listOf(
                                RenderPassColorAttachment(
                                    view = dropShadowOutView,
                                    loadOp = dropShadowFirstLoadOp,
                                    clearValue = background,
                                    storeOp = GPUStoreOp.Store,
                                ),
                            ),
                        ),
                    ) {
                        setPipeline(layerCompositePipelineFor(dropShadowShadowMode))
                        setBindGroup(0u, res.tertiaryBindGroup!!)
                        setScissorRect(
                            x = d.shadowScissor[0].toUInt(),
                            y = d.shadowScissor[1].toUInt(),
                            width = d.shadowScissor[2].toUInt(),
                            height = d.shadowScissor[3].toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                        end()
                    }
                }
                // Original composite : the second composite pass lands
                // the layer content on top of the shadow. The shadow
                // pass above may have cleared the first attachment with
                // a Clear loadOp on the first draw -- the dispatch loop
                // forces Load on subsequent passes anyway, but if the
                // shadow pass was skipped we still need to honour the
                // outer loadOp here, so we pick the right one based on
                // whether the shadow ran.
                val originalLoadOp = when {
                    d.materializeTargetView != null && d.shadowScissor[2] > 0 && d.shadowScissor[3] > 0 ->
                        GPULoadOp.Load
                    d.materializeTargetView != null ->
                        // Materialise + shadow skipped : Clear the scratch
                        // so the original pass starts from a transparent
                        // background (the shadow pass would have done it
                        // otherwise).
                        GPULoadOp.Clear
                    d.shadowScissor[2] > 0 && d.shadowScissor[3] > 0 ->
                        GPULoadOp.Load
                    else ->
                        loadOp
                }
                // L1a -- when materialising, the original sub-pass uses
                // kSrcOver (always lands on TOP of the shadow). The non-
                // materialise path keeps `d.mode` (gated to kSrcOver at the
                // dispatch site, so this is bit-iso).
                val originalMode =
                    if (d.materializeTargetView != null) SkBlendMode.kSrcOver
                    else d.mode
                if (d.originalScissor[2] > 0 && d.originalScissor[3] > 0) {
                    encoder.beginRenderPass(
                        RenderPassDescriptor(
                            colorAttachments = listOf(
                                RenderPassColorAttachment(
                                    view = dropShadowOutView,
                                    loadOp = originalLoadOp,
                                    clearValue = background,
                                    storeOp = GPUStoreOp.Store,
                                ),
                            ),
                        ),
                    ) {
                        setPipeline(layerCompositePipelineFor(originalMode))
                        setBindGroup(0u, res.quaternaryBindGroup!!)
                        setScissorRect(
                            x = d.originalScissor[0].toUInt(),
                            y = d.originalScissor[1].toUInt(),
                            width = d.originalScissor[2].toUInt(),
                            height = d.originalScissor[3].toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                        end()
                    }
                }
                return@forEachIndexed
            }
            if (d is LayerCompositeDraw && d.materializeTargetView != null) {
                // L1b -- MatrixTransform-inside-Compose materialise pass.
                // Single render pass that writes the matrix-transformed
                // image into the layer-sized scratch (the
                // [LayerCompositeDraw.materializeTargetView]) with
                // `loadOp = Clear` and `mode = kSrc`. The downstream
                // Blur / ColorFilter / LayerComposite draws then sample
                // the scratch as if it were the raw layer source.
                encoder.beginRenderPass(
                    RenderPassDescriptor(
                        colorAttachments = listOf(
                            RenderPassColorAttachment(
                                view = d.materializeTargetView,
                                loadOp = GPULoadOp.Clear,
                                clearValue = Color(0.0, 0.0, 0.0, 0.0),
                                storeOp = GPUStoreOp.Store,
                            ),
                        ),
                    ),
                ) {
                    // Zero-area scissor (out-of-layer matrix footprint) :
                    // the Clear loadOp above already wipes the scratch to
                    // transparent, which is the correct semantic for the
                    // CPU MatrixTransform on a fully-out-of-bounds map.
                    // Skip the draw call so wgpu doesn't reject the
                    // zero-size scissor rect.
                    if (d.scissor[2] > 0 && d.scissor[3] > 0) {
                        setPipeline(layerCompositePipelineFor(SkBlendMode.kSrc))
                        setBindGroup(0u, res.bindGroup)
                        setScissorRect(
                            x = d.scissor[0].toUInt(),
                            y = d.scissor[1].toUInt(),
                            width = d.scissor[2].toUInt(),
                            height = d.scissor[3].toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    }
                    end()
                }
                return@forEachIndexed
            }
            encoder.beginRenderPass(
                RenderPassDescriptor(
                    colorAttachments = listOf(
                        RenderPassColorAttachment(
                            view = colorView,
                            loadOp = loadOp,
                            clearValue = background,
                            storeOp = GPUStoreOp.Store,
                        ),
                    ),
                ),
            ) {
                when (d) {
                    is RectDraw -> {
                        setPipeline(rectPipelineFor(d.mode, useGenerated = shouldUseGeneratedSolidRectPath(d)))
                        setBindGroup(0u, res.bindGroup)
                        setScissorRect(
                            x = d.x.toUInt(),
                            y = d.y.toUInt(),
                            width = d.w.toUInt(),
                            height = d.h.toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    }
                    is RuntimeEffectRectDraw -> {
                        setPipeline(runtimeEffectPipelineFor(d.wgslImplementationId, d.mode))
                        setBindGroup(0u, res.bindGroup)
                        setScissorRect(
                            x = d.scissor[0].toUInt(),
                            y = d.scissor[1].toUInt(),
                            width = d.scissor[2].toUInt(),
                            height = d.scissor[3].toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    }
                    is PolygonDraw -> {
                        setPipeline(polygonPipelineFor(d.mode))
                        setBindGroup(0u, res.bindGroup)
                        setScissorRect(
                            x = d.scissor[0].toUInt(),
                            y = d.scissor[1].toUInt(),
                            width = d.scissor[2].toUInt(),
                            height = d.scissor[3].toUInt(),
                        )
                        setVertexBuffer(slot = 0u, buffer = res.vertexBuffer!!)
                        draw((d.verts.size / 2).toUInt())
                    }
                    is AaPolygonDraw -> {
                        setPipeline(aaPolygonPipelineFor(d.mode))
                        setBindGroup(0u, res.bindGroup)
                        setScissorRect(
                            x = d.scissor[0].toUInt(),
                            y = d.scissor[1].toUInt(),
                            width = d.scissor[2].toUInt(),
                            height = d.scissor[3].toUInt(),
                        )
                        setVertexBuffer(slot = 0u, buffer = res.vertexBuffer!!)
                        draw((d.verts.size / 2).toUInt())
                    }
                    is LinearGradientRectDraw -> {
                        setPipeline(
                            linearGradientPipelineFor(
                                d.mode,
                                d.tileMode,
                                useGenerated = shouldUseGeneratedLinearGradientPath(d),
                            ),
                        )
                        setBindGroup(0u, res.bindGroup)
                        setScissorRect(
                            x = d.scissor[0].toUInt(),
                            y = d.scissor[1].toUInt(),
                            width = d.scissor[2].toUInt(),
                            height = d.scissor[3].toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    }
                    is RadialGradientRectDraw -> {
                        setPipeline(radialGradientPipelineFor(d.mode, d.tileMode))
                        setBindGroup(0u, res.bindGroup)
                        setScissorRect(
                            x = d.scissor[0].toUInt(),
                            y = d.scissor[1].toUInt(),
                            width = d.scissor[2].toUInt(),
                            height = d.scissor[3].toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    }
                    is SweepGradientRectDraw -> {
                        setPipeline(sweepGradientPipelineFor(d.mode, d.tileMode))
                        setBindGroup(0u, res.bindGroup)
                        setScissorRect(
                            x = d.scissor[0].toUInt(),
                            y = d.scissor[1].toUInt(),
                            width = d.scissor[2].toUInt(),
                            height = d.scissor[3].toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    }
                    is ConicalGradientRectDraw -> {
                        setPipeline(conicalGradientPipelineFor(d.mode, d.tileMode))
                        setBindGroup(0u, res.bindGroup)
                        setScissorRect(
                            x = d.scissor[0].toUInt(),
                            y = d.scissor[1].toUInt(),
                            width = d.scissor[2].toUInt(),
                            height = d.scissor[3].toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    }
                    is ImageRectDraw -> {
                        // G5.1.1 -- pipeline keyed on (blend, filter, tile).
                        // The blend axis switches the blend state ; filter
                        // and tile both affect the *sampler* (built into
                        // the bind group, not the pipeline) -- the pipeline
                        // entry is identical across them so the cache is
                        // technically over-keyed. Keeping the cache shape
                        // matches the gradient pipelines and leaves room
                        // for shader-side filter / tile branches later.
                        setPipeline(bitmapPipelineFor(d.mode, d.filter))
                        setBindGroup(0u, res.bindGroup)
                        setScissorRect(
                            x = d.scissor[0].toUInt(),
                            y = d.scissor[1].toUInt(),
                            width = d.scissor[2].toUInt(),
                            height = d.scissor[3].toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    }
                    is ConicalFocalGradientRectDraw -> {
                        setPipeline(conicalFocalGradientPipelineFor(d.mode, d.tileMode))
                        setBindGroup(0u, res.bindGroup)
                        setScissorRect(
                            x = d.scissor[0].toUInt(),
                            y = d.scissor[1].toUInt(),
                            width = d.scissor[2].toUInt(),
                            height = d.scissor[3].toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    }
                    is ConicalStripGradientRectDraw -> {
                        setPipeline(conicalStripGradientPipelineFor(d.mode, d.tileMode))
                        setBindGroup(0u, res.bindGroup)
                        setScissorRect(
                            x = d.scissor[0].toUInt(),
                            y = d.scissor[1].toUInt(),
                            width = d.scissor[2].toUInt(),
                            height = d.scissor[3].toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    }
                    is LayerCompositeDraw -> {
                        // Phase G-saveLayer-fast -- direct GPU-to-GPU
                        // composite : fullscreen-quad render pass that
                        // samples the child device's intermediate via
                        // `textureLoad` and writes onto our intermediate.
                        // Blend mode honoured by the pipeline's blend
                        // state ; alpha + colour modulation fold into
                        // the per-draw `paintColor` uniform.
                        setPipeline(layerCompositePipelineFor(d.mode))
                        setBindGroup(0u, res.bindGroup)
                        setScissorRect(
                            x = d.scissor[0].toUInt(),
                            y = d.scissor[1].toUInt(),
                            width = d.scissor[2].toUInt(),
                            height = d.scissor[3].toUInt(),
                        )
                        draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
                    }
                    is StencilCoverPolygonDraw -> { /* handled above */ }
                    is StencilCoverAaPolygonDraw -> { /* handled above */ }
                    is StencilCoverAaGradientDraw -> { /* handled above */ }
                    is StencilCoverAaRadialGradientDraw -> { /* handled above */ }
                    is StencilCoverAaSweepGradientDraw -> { /* handled above */ }
                    is StencilCoverAaConicalGradientDraw -> { /* handled above */ }
                    is StencilCoverAaConicalFocalGradientDraw -> { /* handled above */ }
                    is StencilCoverAaBitmapShaderDraw -> { /* handled above */ }
                    is BlurredPathDraw -> { /* handled above */ }
                    is BlurredShadedPathDraw -> { /* handled above */ }
                    is BlurredLayerCompositeDraw -> { /* handled above */ }
                    is DropShadowLayerCompositeDraw -> { /* handled above */ }
                    is NonNativeBlendLayerCompositeDraw -> { /* handled above */ }
                }
                end()
            }
        }

        return perDrawResources
    }

    /**
     * Phase G-saveLayer-fast -- close out per-draw GPU resources after
     * the command buffer they were bound into has been submitted.
     * Shared by [flush] and [flushDrawsOnly].
     */
    private fun closeDrawResources(perDrawResources: List<DrawResources>) {
        perDrawResources.forEach {
            it.uniform.close()
            it.vertexBuffer?.close()
            it.coverVertexBuffer?.close()
            it.secondaryUniform?.close()
            // Phase MaskFilter-blur -- release the H-pass scratch
            // texture + view, then the child layer device that rendered
            // the shape mask. The view must close before the texture ;
            // the layer device's close() releases its intermediate
            // texture, depth-stencil, pipeline caches, etc.
            it.scratchHView?.close()
            it.scratchHTexture?.close()
            it.layerDevice?.close()
            // Phase G-saveLayer-imageFilter-blur -- release the V-pass
            // scratch and the composite-pass uniform. The layer device
            // for this path is owned by SkCanvas, not by this draw, so
            // we do *not* close it here.
            it.tertiaryUniform?.close()
            it.scratchVView?.close()
            it.scratchVTexture?.close()
            // Phase G-saveLayer-imageFilter-dropshadow / -compose --
            // release the fourth-pass uniform (DropShadow's original-pass
            // composite OR Compose's pre-blur CF pass uniform ; the two
            // never coexist on the same draw) and, when present, the
            // pre-blur CF scratch texture + view (Compose only).
            it.quaternaryUniform?.close()
            it.scratchPreCfView?.close()
            it.scratchPreCfTexture?.close()
            // Phase MaskFilter-blur-cascade -- per-stage uniforms and
            // textures for the multi-stage sigma cascade. Empty lists
            // on the single-stage fast path are a no-op.
            it.cascadeDownsampleUniforms.forEach { u -> u.close() }
            it.cascadeUpsampleUniforms.forEach { u -> u.close() }
            it.cascadeInnerVUniform?.close()
            it.cascadeCompositeUniform?.close()
            it.cascadeViews.forEach { v -> v.close() }
            it.cascadeTextures.forEach { t -> t.close() }
            // L1a -- materialise target texture (DropShadow inside Compose).
            // The view goes before the texture, mirroring scratchH/V cleanup.
            it.materializeTargetView?.close()
            it.materializeTargetTexture?.close()
            it.m60F16FragmentLaneDiagnosticStaging?.close()
            it.m60F16FragmentLaneDiagnosticStorage?.close()
            it.m60F16AaStencilCoverPostPassReadbackStaging?.close()
            it.m60F16AaStencilCoverPostPassReadbackStorage?.close()
            it.m60F16AaStencilCoverPredrawDstReadbackStaging?.close()
            it.m60F16AaStencilCoverPredrawDstReadbackStorage?.close()
            it.m60F16StencilRenderPassSplitBoundaryStaging?.close()
            it.m60F16StencilRenderPassSplitBoundaryStorage?.close()
            it.m60F16AaStencilCoverIsolatedColorTargetStaging?.close()
            it.m60F16AaStencilCoverIsolatedColorTargetStorage?.close()
            it.m60F16AaStencilCoverIsolatedColorTargetScratchView?.close()
            it.m60F16AaStencilCoverIsolatedColorTargetScratchTexture?.close()
            it.m60F16AaStencilCoverIsolatedColorTargetDepthStencilView?.close()
            it.m60F16AaStencilCoverIsolatedColorTargetDepthStencilTexture?.close()
            it.m60F16AaStencilCoverStorageColorTargetComparisonColorStaging?.close()
            it.m60F16AaStencilCoverStorageColorTargetComparisonColorStorage?.close()
            it.m60F16AaStencilCoverStorageColorTargetComparisonShaderStaging?.close()
            it.m60F16AaStencilCoverStorageColorTargetComparisonShaderStorage?.close()
            it.m60F16AaStencilCoverStorageColorTargetComparisonScratchView?.close()
            it.m60F16AaStencilCoverStorageColorTargetComparisonScratchTexture?.close()
            it.m60F16AaStencilCoverStorageColorTargetComparisonDepthStencilView?.close()
            it.m60F16AaStencilCoverStorageColorTargetComparisonDepthStencilTexture?.close()
        }
    }

    /**
     * Submit the pending draws, read the colour texture back, and return
     * its raw bytes. Layout: row-major RGBA, `width * height * 4` bytes,
     * de-padded from WebGPU's 256-byte row alignment. Clears [pending]
     * for the next frame.
     */
    public fun flush(): ByteArray = runBlocking {
        val encoder = context.device.createCommandEncoder()
        // G6.1 — draws target the *intermediate* texture ; the final
        // present pass below samples it, applies the sRGB → Rec.2020
        // transform, and writes to `target.colorTexture` for readback.
        val perDrawResources = encodePendingDrawsToIntermediate(encoder)
        val for258ShaderSideProbeReadback = encodeFor258ShaderSideProbe(encoder)

        // G6.1 present pass : transform sRGB intermediate to Rec.2020
        // final, in a fragment shader (textureLoad + transform + write).
        // Replaces the G6.0 CPU loop in WebGpuSink. Targets
        // `target.colorTexture` so the existing readback machinery picks
        // up the colorspace-converted pixels unchanged.
        val finalView = target.colorTexture.createView()
        encoder.beginRenderPass(
            RenderPassDescriptor(
                colorAttachments = listOf(
                    RenderPassColorAttachment(
                        view = finalView,
                        loadOp = GPULoadOp.Clear,
                        clearValue = Color(0.0, 0.0, 0.0, 0.0),
                        storeOp = GPUStoreOp.Store,
                    ),
                ),
            ),
        ) {
            setPipeline(presentPipeline)
            setBindGroup(0u, presentBindGroup)
            draw(FULL_SCREEN_TRIANGLE_VERTEX_COUNT)
            end()
        }

        target.encodeCopyToStaging(encoder)
        context.queue.submit(listOf(encoder.finish()))

        recordFor258ShaderSideProbe(for258ShaderSideProbeReadback)
        recordM60F16FragmentLaneDiagnostics(perDrawResources)
        recordM60F16AaStencilCoverPredrawDstReadbacks()
        recordM60F16StencilRenderPassSplitBoundaryReadbacks()
        recordM60F16AaStencilCoverPostPassReadbacks()
        recordM60F16AaStencilCoverIsolatedColorTargetReadbacks()
        recordM60F16AaStencilCoverStorageColorTargetComparisonReadbacks()
        recordM60F16LowLevelExactMaskProbeFor443Readbacks()
        recordM60F16RuntimeIntegerLaneMaskProbeFor445Readbacks()
        val pixels = target.readPixels()
        recordOutputReadbackBoundary(pixels)

        closeDrawResources(perDrawResources)
        pending.clear()
        // Phase G-saveLayer-backdrop -- the intermediate is now fully
        // populated. A subsequent `flush()` (rare -- the host usually
        // closes the device after the first flush) would `loadOp =
        // Load` and preserve the pixels, matching the
        // [flushDrawsOnly] convention.
        intermediateInitialized = true
        pixels
    }

    /**
     * Phase G-saveLayer-fast -- drain pending draws onto
     * [intermediateTexture] and submit, **without** the present pass or
     * readback round-trip. Used by [compositeFrom] to flush a child
     * layer device before its texture is sampled by the parent's
     * subsequent composite render pass.
     *
     * After this call, the device's [intermediateTexture] holds the
     * fully-blended content of all pending draws (sRGB-coded premul,
     * matching the present-pass identity-copy output) and `pending` is
     * empty. The intermediate is readable as a sampled texture in any
     * subsequent command buffer queued onto [context]'s shared queue.
     */
    internal fun flushDrawsOnly() {
        val encoder = context.device.createCommandEncoder()
        val perDrawResources = encodePendingDrawsToIntermediate(encoder)
        context.queue.submit(listOf(encoder.finish()))
        closeDrawResources(perDrawResources)
        pending.clear()
        // Phase G-saveLayer-backdrop -- mark the intermediate as
        // populated so a subsequent [encodePendingDrawsToIntermediate]
        // (from a later flushDrawsOnly or the final flush) uses
        // `loadOp = Load` and preserves the parent pixels we just
        // committed.
        intermediateInitialized = true
    }

    /**
     * Per-draw GPU resources lifetime-managed by [flush] : the uniform
     * buffer + its bind group, plus optional vertex buffers (polygon
     * draws use [vertexBuffer] ; stencil-and-cover draws additionally
     * use [coverVertexBuffer] for the cover-pass bbox quad).
     *
     * Phase MaskFilter-blur adds [secondaryUniform] / [secondaryBindGroup]
     * for the V pass of the separable Gaussian blur. The H pass uses
     * the primary [uniform] / [bindGroup] (binding the shape mask) ; the
     * V pass uses the secondaries (binding the H-pass scratch texture
     * and a different per-axis uniform). The secondary slots also carry
     * the per-draw child layer device + scratch H texture so [close]
     * can release them after the command buffer submission.
     */
    private data class DrawResources(
        val uniform: GPUBuffer,
        val bindGroup: io.ygdrasil.webgpu.GPUBindGroup,
        val vertexBuffer: GPUBuffer? = null,
        val coverVertexBuffer: GPUBuffer? = null,
        val secondaryUniform: GPUBuffer? = null,
        val secondaryBindGroup: io.ygdrasil.webgpu.GPUBindGroup? = null,
        // Phase MaskFilter-blur -- transient GPU objects to release
        // after the command buffer that consumed them has been
        // submitted. [scratchHTexture] is the H-pass scratch ;
        // [layerDevice] is the child SkWebGpuDevice that rendered the
        // shape mask. Both are owned by this DrawResources, not by the
        // PendingDraw (which holds *views*).
        val scratchHTexture: GPUTexture? = null,
        val scratchHView: GPUTextureView? = null,
        val layerDevice: SkWebGpuDevice? = null,
        // Phase G-saveLayer-imageFilter-blur -- a third uniform + bind
        // group for the final composite pass (consumed by
        // `layer_composite.wgsl`) plus the V-pass scratch texture that
        // the composite samples. The composite pass reads scratchV, so
        // both scratches need to outlive the command buffer ; we close
        // them after submit.
        val tertiaryUniform: GPUBuffer? = null,
        val tertiaryBindGroup: io.ygdrasil.webgpu.GPUBindGroup? = null,
        val scratchVTexture: GPUTexture? = null,
        val scratchVView: GPUTextureView? = null,
        // A fourth uniform + bind group, shared between two paths that
        // never coexist on the same draw :
        //  - Phase G-saveLayer-imageFilter-dropshadow : the original-pass
        //    composite (layer content drawn ON TOP of the shadow). Same
        //    byte layout as the tertiary (the shadow-pass composite) but
        //    different colour-filter + dst-origin payload, so we need a
        //    distinct GPU buffer.
        //  - Phase G-saveLayer-imageFilter-compose : the pre-blur
        //    ColorFilter pass. Bound by
        //    [buildBlurredLayerCompositeDrawResources] when the
        //    BlurredLayerCompositeDraw carries a pre-blur CF, else left
        //    null and the blur H pass reads from the raw layer view.
        val quaternaryUniform: GPUBuffer? = null,
        val quaternaryBindGroup: io.ygdrasil.webgpu.GPUBindGroup? = null,
        // Phase G-saveLayer-imageFilter-compose -- pre-blur CF scratch
        // texture + view. The blur H pass reads from this scratch when
        // present (instead of from the raw layer view). Released in
        // [closeDrawResources] alongside the other scratch textures.
        val scratchPreCfTexture: GPUTexture? = null,
        val scratchPreCfView: GPUTextureView? = null,
        // Phase MaskFilter-blur-cascade -- per-stage uniform buffers
        // and bind groups for the multi-stage sigma cascade. Indexed
        // by pass order :
        //   - cascadeDownsampleUniforms[i] / cascadeDownsampleBindGroups[i]
        //     drives the i-th downsample pass (i = 0..N-1).
        //   - cascadeUpsampleUniforms[i] / cascadeUpsampleBindGroups[i]
        //     drives the i-th upsample pass (i = 0..N-1).
        //   - cascadeInnerVUniform / cascadeInnerVBindGroup drives the
        //     inner V-blur pass (the H pass uses `uniform` / `bindGroup`
        //     above, repurposed to point at the smallest cascade level).
        //   - cascadeCompositeUniform / cascadeCompositeBindGroup drives
        //     the final upsample-composite pass (replaces
        //     `secondaryUniform` / `secondaryBindGroup` for the cascade
        //     path).
        // All null on the single-stage fast path.
        val cascadeDownsampleUniforms: List<GPUBuffer> = emptyList(),
        val cascadeDownsampleBindGroups: List<io.ygdrasil.webgpu.GPUBindGroup> = emptyList(),
        val cascadeUpsampleUniforms: List<GPUBuffer> = emptyList(),
        val cascadeUpsampleBindGroups: List<io.ygdrasil.webgpu.GPUBindGroup> = emptyList(),
        val cascadeInnerVUniform: GPUBuffer? = null,
        val cascadeInnerVBindGroup: io.ygdrasil.webgpu.GPUBindGroup? = null,
        val cascadeCompositeUniform: GPUBuffer? = null,
        val cascadeCompositeBindGroup: io.ygdrasil.webgpu.GPUBindGroup? = null,
        // Owned cascade textures + views to close after submit.
        val cascadeTextures: List<GPUTexture> = emptyList(),
        val cascadeViews: List<GPUTextureView> = emptyList(),
        // FOR-396 diagnostic-only fragment side-channel for the bounded
        // M60 F16 AA stencil-cover lane predicate. These buffers are
        // allocated only when the explicit opt-in guard is active and the
        // FOR-394 metadata transport recognized the draw.
        val m60F16FragmentLaneDiagnosticStorage: GPUBuffer? = null,
        val m60F16FragmentLaneDiagnosticStaging: GPUBuffer? = null,
        val m60F16FragmentLaneDiagnosticBindGroup: io.ygdrasil.webgpu.GPUBindGroup? = null,
        val m60F16FragmentLaneDiagnosticBufferSize: ULong = M60_F16_FRAGMENT_LANE_DIAGNOSTIC_BUFFER_SIZE,
        val m60F16RuntimeIntegerLaneMaskProbeFor445Storage: GPUBuffer? = null,
        val m60F16RuntimeIntegerLaneMaskProbeFor445Staging: GPUBuffer? = null,
        val m60F16RuntimeIntegerLaneMaskProbeFor445BufferSize: ULong =
            M60_F16_RUNTIME_INTEGER_LANE_MASK_PROBE_FOR445_BUFFER_SIZE,
        val m60F16AaStencilCoverPostPassReadbackStorage: GPUBuffer? = null,
        val m60F16AaStencilCoverPostPassReadbackStaging: GPUBuffer? = null,
        val m60F16AaStencilCoverPostPassReadbackBindGroup: io.ygdrasil.webgpu.GPUBindGroup? = null,
        val m60F16AaStencilCoverPostPassReadbackBufferSize: ULong =
            M60_F16_AA_STENCIL_COVER_POST_PASS_READBACK_BUFFER_SIZE,
        val m60F16AaStencilCoverPredrawDstReadbackStorage: GPUBuffer? = null,
        val m60F16AaStencilCoverPredrawDstReadbackStaging: GPUBuffer? = null,
        val m60F16AaStencilCoverPredrawDstReadbackBindGroup: io.ygdrasil.webgpu.GPUBindGroup? = null,
        val m60F16AaStencilCoverPredrawDstReadbackBufferSize: ULong =
            M60_F16_AA_STENCIL_COVER_POST_PASS_READBACK_BUFFER_SIZE,
        val m60F16StencilRenderPassSplitBoundaryStorage: GPUBuffer? = null,
        val m60F16StencilRenderPassSplitBoundaryStaging: GPUBuffer? = null,
        val m60F16StencilRenderPassSplitBoundaryBindGroup: io.ygdrasil.webgpu.GPUBindGroup? = null,
        val m60F16StencilRenderPassSplitBoundaryBufferSize: ULong =
            M60_F16_AA_STENCIL_COVER_POST_PASS_READBACK_BUFFER_SIZE,
        val m60F16AaStencilCoverIsolatedColorTargetScratchTexture: GPUTexture? = null,
        val m60F16AaStencilCoverIsolatedColorTargetScratchView: GPUTextureView? = null,
        val m60F16AaStencilCoverIsolatedColorTargetDepthStencilTexture: GPUTexture? = null,
        val m60F16AaStencilCoverIsolatedColorTargetDepthStencilView: GPUTextureView? = null,
        val m60F16AaStencilCoverIsolatedColorTargetStorage: GPUBuffer? = null,
        val m60F16AaStencilCoverIsolatedColorTargetStaging: GPUBuffer? = null,
        val m60F16AaStencilCoverIsolatedColorTargetBindGroup: io.ygdrasil.webgpu.GPUBindGroup? = null,
        val m60F16AaStencilCoverIsolatedColorTargetBufferSize: ULong =
            M60_F16_AA_STENCIL_COVER_POST_PASS_READBACK_BUFFER_SIZE,
        val m60F16AaStencilCoverStorageColorTargetComparisonScratchTexture: GPUTexture? = null,
        val m60F16AaStencilCoverStorageColorTargetComparisonScratchView: GPUTextureView? = null,
        val m60F16AaStencilCoverStorageColorTargetComparisonDepthStencilTexture: GPUTexture? = null,
        val m60F16AaStencilCoverStorageColorTargetComparisonDepthStencilView: GPUTextureView? = null,
        val m60F16AaStencilCoverStorageColorTargetComparisonShaderStorage: GPUBuffer? = null,
        val m60F16AaStencilCoverStorageColorTargetComparisonShaderStaging: GPUBuffer? = null,
        val m60F16AaStencilCoverStorageColorTargetComparisonShaderBindGroup:
            io.ygdrasil.webgpu.GPUBindGroup? = null,
        val m60F16AaStencilCoverStorageColorTargetComparisonShaderBufferSize: ULong =
            M60_F16_AA_STENCIL_COVER_CONTRIBUTION_ISOLATION_BUFFER_SIZE,
        val m60F16AaStencilCoverStorageColorTargetComparisonColorStorage: GPUBuffer? = null,
        val m60F16AaStencilCoverStorageColorTargetComparisonColorStaging: GPUBuffer? = null,
        val m60F16AaStencilCoverStorageColorTargetComparisonColorBindGroup:
            io.ygdrasil.webgpu.GPUBindGroup? = null,
        val m60F16LowLevelExactMaskProbeFor443Storage: GPUBuffer? = null,
        val m60F16LowLevelExactMaskProbeFor443Staging: GPUBuffer? = null,
        val m60F16LowLevelExactMaskProbeFor443BindGroup:
            io.ygdrasil.webgpu.GPUBindGroup? = null,
        val m60F16LowLevelExactMaskProbeFor443BufferSize: ULong =
            M60_F16_LOW_LEVEL_EXACT_MASK_PROBE_FOR443_BUFFER_SIZE,
        val m60F16AaStencilCoverDiagnosticMetadata: M60F16AaStencilCoverPostPassReadbackMetadata? = null,
        // L1a -- DropShadow-inside-Compose materialise target texture +
        // view. Allocated by [enqueueMaterializeDropShadowToScratch] and
        // owned by this DrawResources ; closed in [closeDrawResources]
        // after the command buffer that consumed it has been submitted.
        // The texture's view is referenced by the [DropShadowLayerCompositeDraw]
        // dispatch as `materializeTargetView` AND by the downstream Blur /
        // ColorFilter / LayerComposite draws as their `layerView` -- those
        // views (re-derived from the same texture) outlive the materialise
        // draw because each draw owns its own per-draw resources, but the
        // underlying texture must remain alive until the LAST consumer's
        // command buffer is submitted. All these draws live in the same
        // [pending] batch and share a single `flush` cycle, so closing
        // here (at end-of-flush) is correct.
        val materializeTargetTexture: GPUTexture? = null,
        val materializeTargetView: GPUTextureView? = null,
    )

    private data class For258ShaderSideProbeReadback(
        val storage: GPUBuffer,
        val staging: GPUBuffer,
    )

    private data class M60F16FragmentLaneDiagnosticReadback(
        val drawIndex: Int,
        val metadata: M60F16AaStencilCoverPostPassReadbackMetadata?,
        val staging: GPUBuffer,
        val bufferSize: ULong,
    )

    private data class M60F16AaStencilCoverPostPassReadbackMetadata(
        val drawIndex: Int,
        val fillType: String,
        val blendMode: String,
        val scissor: IntArray,
        val edgeCount: Int,
        val coverVertexCount: Int,
    )

    private data class M60F16AaStencilCoverPostPassReadback(
        val metadata: M60F16AaStencilCoverPostPassReadbackMetadata,
        val staging: GPUBuffer,
        val bufferSize: ULong,
    )

    private data class M60F16AaStencilCoverPredrawDstReadback(
        val metadata: M60F16AaStencilCoverPostPassReadbackMetadata,
        val staging: GPUBuffer,
        val bufferSize: ULong,
    )

    private data class M60F16AaStencilCoverIsolatedColorTargetReadback(
        val metadata: M60F16AaStencilCoverPostPassReadbackMetadata,
        val staging: GPUBuffer,
        val bufferSize: ULong,
    )

    private data class M60F16AaStencilCoverStorageColorTargetComparisonReadback(
        val metadata: M60F16AaStencilCoverPostPassReadbackMetadata,
        val shaderStaging: GPUBuffer,
        val shaderBufferSize: ULong,
        val colorStaging: GPUBuffer,
        val colorBufferSize: ULong,
    )

    private data class M60F16LowLevelExactMaskProbeFor443Readback(
        val metadata: M60F16AaStencilCoverPostPassReadbackMetadata,
        val storage: GPUBuffer,
        val staging: GPUBuffer,
        val bufferSize: ULong,
    )

    private data class M60F16RuntimeIntegerLaneMaskProbeFor445Readback(
        val metadata: M60F16AaStencilCoverPostPassReadbackMetadata,
        val storage: GPUBuffer,
        val staging: GPUBuffer,
        val bufferSize: ULong,
    )

    private fun buildRectDrawResources(d: RectDraw): DrawResources {
        val buf = context.device.createBuffer(
            BufferDescriptor(
                size = RECT_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.rectDraw",
            ),
        )
        // Layout : color (4) + outerBounds (4) + innerBounds (4) +
        //          clipShapeBounds (4) + clipShapeRadiiKind (4) +
        //          colorFilterKindMode (4) + colorFilterParam0..3 (4*4) +
        //          colorFilterBias (4) = 44 floats = 176 bytes.
        // Matches `Uniforms { color, outerBounds, innerBounds,
        // clipShapeBounds, clipShapeRadiiKind, colorFilterKindMode,
        // colorFilterParam0..3, colorFilterBias }` in solid_color.wgsl.
        // For draws without an analytical clip shape, `clipKind = 0`
        // skips the modulation step in the shader. For draws without a
        // colour filter, the trailing 6 vec4f are all zeros and the
        // shader's `colorFilterKindMode.x == 0` branch is a no-op.
        val packed = FloatArray(44)
        packed[0] = d.r; packed[1] = d.g; packed[2] = d.b; packed[3] = d.a
        packed[4] = d.ol; packed[5] = d.ot; packed[6] = d.or; packed[7] = d.ob
        packed[8] = d.il; packed[9] = d.it; packed[10] = d.ir; packed[11] = d.ib
        packed[12] = d.clipShapeBounds[0]; packed[13] = d.clipShapeBounds[1]
        packed[14] = d.clipShapeBounds[2]; packed[15] = d.clipShapeBounds[3]
        packed[16] = d.clipShapeRx; packed[17] = d.clipShapeRy
        packed[18] = d.clipKind; packed[19] = 0f
        // Phase G-direct-colorFilter -- 6 contiguous vec4f starting at
        // vec4f index 5 (offset 80 bytes = float index 20). When the
        // paint had no colour filter, [colorFilterPacked] is the shared
        // [ZERO_COLOR_FILTER_24] sentinel, so the trailing 24 floats
        // are zero and the shader's fast path stays warm.
        System.arraycopy(d.colorFilterPacked, 0, packed, 20, 24)
        packed[22] = targetColorSpaceBlendFlag()
        recordRawRectUniformColorWrite(d, packed)
        context.queue.writeBuffer(buf, 0uL, ArrayBuffer.of(packed))
        val bindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = rectBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = buf)),
                ),
            ),
        )
        return DrawResources(uniform = buf, bindGroup = bindGroup)
    }

    private fun buildPolygonDrawResources(d: PolygonDraw): DrawResources {
        val uniform = context.device.createBuffer(
            BufferDescriptor(
                size = POLYGON_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.polygonDraw",
            ),
        )
        // Layout : color (4 floats) + viewport (vec4 padded ; only x,y used)
        // + clipShapeBounds (vec4) + clipShapeRadiiKind (vec4) +
        // colorFilter* (6 * vec4 = 24 floats). Matches the `Uniforms`
        // struct in solid_polygon.wgsl (40 floats = 160 bytes total).
        // Phase G-direct-colorFilter -- the trailing 24 floats stay zero
        // when the paint has no colour filter, so the shader's kind == 0
        // fast path runs and the output is byte-identical.
        val packed = FloatArray(40)
        packed[0] = d.r; packed[1] = d.g; packed[2] = d.b; packed[3] = d.a
        packed[4] = width.toFloat(); packed[5] = height.toFloat()
        packed[6] = 0f; packed[7] = 0f
        writeClipShape(packed, 8, d.clipShape)
        // 6 contiguous vec4f starting at vec4f index 4 (offset 64 bytes
        // = float index 16). When the paint had no colour filter,
        // [colorFilterPacked] is the shared [ZERO_COLOR_FILTER_24]
        // sentinel, keeping the trailing 24 floats at zero.
        System.arraycopy(d.colorFilterPacked, 0, packed, 16, 24)
        context.queue.writeBuffer(uniform, 0uL, ArrayBuffer.of(packed))
        val bindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = polygonBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = uniform)),
                ),
            ),
        )
        val vertexSize = (d.verts.size * Float.SIZE_BYTES).toULong()
        val vertexBuffer = context.device.createBuffer(
            BufferDescriptor(
                size = vertexSize,
                usage = GPUBufferUsage.Vertex or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.polygonVerts",
            ),
        )
        context.queue.writeBuffer(vertexBuffer, 0uL, ArrayBuffer.of(d.verts))
        return DrawResources(uniform = uniform, bindGroup = bindGroup, vertexBuffer = vertexBuffer)
    }

    private fun buildRuntimeEffectRectDrawResources(d: RuntimeEffectRectDraw): DrawResources {
        val uniformByteSize = (d.uniformFloats.size * Float.SIZE_BYTES).toULong()
        val uniform = context.device.createBuffer(
            BufferDescriptor(
                size = uniformByteSize,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.runtimeEffectRectDraw",
            ),
        )
        context.queue.writeBuffer(uniform, 0uL, ArrayBuffer.of(d.uniformFloats))
        val bindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = rectBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = uniform)),
                ),
            ),
        )
        return DrawResources(uniform = uniform, bindGroup = bindGroup)
    }

    private fun buildStencilCoverDrawResources(d: StencilCoverPolygonDraw): DrawResources {
        val uniform = context.device.createBuffer(
            BufferDescriptor(
                size = POLYGON_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.stencilCoverDraw",
            ),
        )
        // Same layout as buildPolygonDrawResources -- shared with
        // solid_polygon.wgsl. The stencil-write sub-pass discards its
        // fragment output (writeMask = None) so the trailing clip-shape
        // + colour-filter slots only matter to the cover sub-pass.
        val packed = FloatArray(40)
        packed[0] = d.r; packed[1] = d.g; packed[2] = d.b; packed[3] = d.a
        packed[4] = width.toFloat(); packed[5] = height.toFloat()
        packed[6] = 0f; packed[7] = 0f
        writeClipShape(packed, 8, d.clipShape)
        // Phase G-direct-colorFilter -- 24 trailing floats packed
        // identically to [buildPolygonDrawResources].
        System.arraycopy(d.colorFilterPacked, 0, packed, 16, 24)
        context.queue.writeBuffer(uniform, 0uL, ArrayBuffer.of(packed))
        val bindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = polygonBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = uniform)),
                ),
            ),
        )
        val stencilVB = context.device.createBuffer(
            BufferDescriptor(
                size = (d.stencilVerts.size * Float.SIZE_BYTES).toULong(),
                usage = GPUBufferUsage.Vertex or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.stencilVerts",
            ),
        )
        context.queue.writeBuffer(stencilVB, 0uL, ArrayBuffer.of(d.stencilVerts))
        val coverVB = context.device.createBuffer(
            BufferDescriptor(
                size = (d.coverVerts.size * Float.SIZE_BYTES).toULong(),
                usage = GPUBufferUsage.Vertex or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.coverVerts",
            ),
        )
        context.queue.writeBuffer(coverVB, 0uL, ArrayBuffer.of(d.coverVerts))
        return DrawResources(
            uniform = uniform,
            bindGroup = bindGroup,
            vertexBuffer = stencilVB,
            coverVertexBuffer = coverVB,
        )
    }

    private fun buildAaPolygonDrawResources(d: AaPolygonDraw): DrawResources {
        val uniform = context.device.createBuffer(
            BufferDescriptor(
                size = AA_POLYGON_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.aaPolygonDraw",
            ),
        )
        // Layout matches `aa_polygon.wgsl` :
        //   offset    0 : color    (4 floats)
        //   offset   16 : viewport (4 floats, only x/y used)
        //   offset   32 : edgeCount (u32) + 3 u32 padding
        //   offset   48 : edges[MAX_AA_EDGES] (vec4 each)
        //   offset 4144 : clipShapeBounds (vec4) ; G2.x (closing slice)
        //   offset 4160 : clipShapeRadiiKind (vec4) ; G2.x (closing slice)
        //   offset 4176 : colorFilter* (6 * vec4 = 24 floats) ; Phase
        //                 G-direct-colorFilter (polygon closing slice)
        // Pack the whole thing in one FloatArray ; reinterpret edgeCount's
        // bits as a float so `floatArrayOf` lays it out at the right
        // byte offset.
        val packed = FloatArray(12 + MAX_AA_EDGES * 4 + 8 + 24)
        // color
        packed[0] = d.r; packed[1] = d.g; packed[2] = d.b; packed[3] = d.a
        // viewport
        packed[4] = width.toFloat(); packed[5] = height.toFloat()
        packed[6] = 0f; packed[7] = 0f
        // edgeCount as bit-reinterpreted float (so the byte pattern matches
        // a u32 in WGSL).
        packed[8] = Float.fromBits(d.edgeCount)
        packed[9] = 0f; packed[10] = 0f; packed[11] = 0f
        // edges
        System.arraycopy(d.edges, 0, packed, 12, d.edges.size)
        // G2.x (closing slice) -- clip-shape payload at offset 4144.
        writeClipShape(packed, 12 + MAX_AA_EDGES * 4, d.clipShape)
        // Phase G-direct-colorFilter -- colour-filter payload at offset
        // 4176 (= float index 12 + MAX_AA_EDGES * 4 + 8).
        System.arraycopy(d.colorFilterPacked, 0, packed, 12 + MAX_AA_EDGES * 4 + 8, 24)

        context.queue.writeBuffer(uniform, 0uL, ArrayBuffer.of(packed))
        val bindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = aaPolygonBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = uniform)),
                ),
            ),
        )
        val vertexSize = (d.verts.size * Float.SIZE_BYTES).toULong()
        val vertexBuffer = context.device.createBuffer(
            BufferDescriptor(
                size = vertexSize,
                usage = GPUBufferUsage.Vertex or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.aaPolygonVerts",
            ),
        )
        context.queue.writeBuffer(vertexBuffer, 0uL, ArrayBuffer.of(d.verts))
        return DrawResources(uniform = uniform, bindGroup = bindGroup, vertexBuffer = vertexBuffer)
    }

    /**
     * G2.x -- write the analytical clip-shape (8 floats : `clipShapeBounds`
     * followed by `clipShapeRadiiKind`) at offset [base] in [out]. Mirrors
     * [packClipShape] : `null` and [SkClipShape.Rect] produce the
     * `clipKind = 0` sentinel (no shape clip ; the shader skips the
     * `rrect_cov` modulation), [SkClipShape.Circle] / [SkClipShape.Oval]
     * / [SkClipShape.RRect] all collapse to the rrect parameterisation
     * (bounds + uniform `(rx, ry)`).
     */
    private fun writeClipShape(out: FloatArray, base: Int, shape: SkClipShape?) {
        val (kind, bounds, rx, ry) = packClipShape(shape)
        out[base]     = bounds[0]
        out[base + 1] = bounds[1]
        out[base + 2] = bounds[2]
        out[base + 3] = bounds[3]
        out[base + 4] = rx
        out[base + 5] = ry
        out[base + 6] = kind
        out[base + 7] = 0f
    }

    private fun buildLinearGradientRectDrawResources(d: LinearGradientRectDraw): DrawResources {
        val uniform = context.device.createBuffer(
            BufferDescriptor(
                size = LINEAR_GRADIENT_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.linearGradientRectDraw",
            ),
        )
        // Layout matches `linear_gradient.wgsl` :
        //   offset   0 : startEnd  (vec4f -- start.xy, end.xy)
        //   offset  16 : viewport  (vec4f, only x/y used)
        //   offset  32 : countPad  (u32 in .x as bit-reinterpreted float)
        //   offset  48 : positions[MAX_GRADIENT_STOPS] (vec4 each, .x = pos)
        //   offset 304 : colors   [MAX_GRADIENT_STOPS] (vec4 each, premul rgba)
        //   offset 560 : clipShapeBounds (vec4f -- l, t, r, b) ; G2.x
        //   offset 576 : clipShapeRadiiKind (vec4f -- rx, ry, clipKind, _) ; G2.x
        //   offset 592 : colorFilter* (6 vec4f) ; Phase G-direct-colorFilter-gradient
        val packed = FloatArray(12 + MAX_GRADIENT_STOPS * 8 + 8 + 24)
        packed[0] = d.startX; packed[1] = d.startY
        packed[2] = d.endX;   packed[3] = d.endY
        packed[4] = width.toFloat(); packed[5] = height.toFloat()
        packed[6] = 0f; packed[7] = 0f
        packed[8] = Float.fromBits(d.stopCount)
        packed[9] = 0f; packed[10] = 0f; packed[11] = 0f
        System.arraycopy(d.stopPositions, 0, packed, 12, MAX_GRADIENT_STOPS * 4)
        System.arraycopy(d.stopColors, 0, packed, 12 + MAX_GRADIENT_STOPS * 4, MAX_GRADIENT_STOPS * 4)
        // G2.x -- clip-shape payload appended at offset 560.
        val clipBase = 12 + MAX_GRADIENT_STOPS * 8
        writeClipShape(packed, clipBase, d.clipShape)
        // Phase G-direct-colorFilter-gradient -- colour filter payload at offset 592.
        System.arraycopy(d.colorFilterPacked, 0, packed, clipBase + 8, 24)

        context.queue.writeBuffer(uniform, 0uL, ArrayBuffer.of(packed))
        val bindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = linearGradientBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = uniform)),
                ),
            ),
        )
        return DrawResources(uniform = uniform, bindGroup = bindGroup)
    }

    private fun buildRadialGradientRectDrawResources(d: RadialGradientRectDraw): DrawResources {
        val uniform = context.device.createBuffer(
            BufferDescriptor(
                size = RADIAL_GRADIENT_UNIFORM_SIZE,
