    private fun buildImageRectDrawResources(d: ImageRectDraw): DrawResources {
        val uniform = context.device.createBuffer(
            BufferDescriptor(
                size = IMAGE_RECT_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.imageRectDraw",
            ),
        )
        // Layout matches `bitmap_shader.wgsl` :
        //   offset   0 : srcRect             (vec4f -- l, t, r, b in image-pixel coords)
        //   offset  16 : dstRect             (vec4f -- l, t, r, b in device-pixel coords)
        //   offset  32 : imageSize           (vec4f -- w, h, tileX (bit-reinterp u32), tileY (bit-reinterp u32))
        //   offset  48 : paintColor          (vec4f -- premul tint, default (1, 1, 1, 1))
        //   offset  64 : csFlags             (vec4f -- .x = csMode bit-reinterp u32 ; G5.3)
        //   offset  80 : csMatrix            (mat3x3<f32>, std140 padded 3 * vec4 = 48 bytes ; G5.3)
        //   offset 128 : csTfParams0         (vec4f -- (g, a, b, c) parametric TF ; G5.3.x)
        //   offset 144 : csTfParams1         (vec4f -- (d, e, f, _) parametric TF ; G5.3.x)
        //   offset 160 : clipShapeBounds     (vec4f -- l, t, r, b device-px ; G2.x)
        //   offset 176 : clipShapeRadiiKind  (vec4f -- rx, ry, clipKind, strict mode ; G2.x/GRA-95)
        //   offset 192 : devToImageRow0      (vec4f -- (sx, kx, tx, _) ; G5.2.2)
        //   offset 208 : devToImageRow1      (vec4f -- (ky, sy, ty, _) ; G5.2.2)
        //   offset 224 : colorFilterKindMode (vec4f -- (kind, mode, _, _) ; Phase H2)
        //   offset 240 : colorFilterParam0   (vec4f -- premul colour OR matrix row 0)
        //   offset 256 : colorFilterParam1   (vec4f -- matrix row 1)
        //   offset 272 : colorFilterParam2   (vec4f -- matrix row 2)
        //   offset 288 : colorFilterParam3   (vec4f -- matrix row 3)
        //   offset 304 : colorFilterBias     (vec4f -- per-row bias)
        // Total = 320 bytes.
        //
        // G5.1.1 -- `imageSize.z` carries the tile-mode ordinal as a
        // bit-reinterpreted f32 (same trick the gradient shaders use for
        // `stopCount` / `edgeCount`). The shader does `bitcast<u32>(.z)`
        // and only branches on kDecal ; the other 3 tile modes are
        // resolved by the sampler's addressMode.
        //
        // G5.2 -- per-axis tile mode : `.z = tileX`, `.w = tileY`. The
        // shader's decal check is now per-axis (covers TinyBitmapGM's
        // `kRepeat`/`kMirror` mix as a no-op, only `kDecal` on either
        // axis triggers the kill).
        //
        // G5.3 -- `csFlags.x` carries the colorspace transform mode
        // (`0 = identity` / `1 = sRGB-TF + matrix` / `2 = parametric
        // sRGBish TF + matrix`, G5.3.x) bit-reinterpreted ; the
        // shader's `bitcast<u32>` gates the transform branch.
        // `csMatrix` is column-major source-linear -> sRGB-linear ;
        // WGSL std140 inserts 4 bytes of padding after each 3-float
        // column, so we pack 3 columns of `(x, y, z, 0)` here.
        //
        // G5.3.x -- `csTfParams0/1` carry the 7-float parametric TF
        // coefficients (`(g, a, b, c, d, e, f)`, mirroring
        // `SkcmsTransferFunction`) used by the shader's mode = 2
        // branch. Modes 0 and 1 still ship `(1, 1, 0, 0, 0, 0, 0)`
        // (linear identity TF) as a stable byte payload so the std140
        // alignment is deterministic across draws.
        //
        // G2.x slice 2 -- `clipShapeBounds` + `clipShapeRadiiKind`
        // mirror the rect pipeline. `clipKind == 0` => no shape clip
        // (the slots are ignored) ; `clipKind == 1` => rrect coverage
        // multiplied into the fragment output. The two slots sit after
        // the G5.3 colorspace block to keep that block contiguous.
        //
        // G5.2.2 -- `devToImageRow0` / `devToImageRow1` carry the 2x3
        // device-to-image affine that drives the per-fragment image-
        // coord lookup. Axis-aligned callers (drawImageRect) build it
        // from the rect ratio ; SkBitmapShader callers ship the
        // inverse of `ctm * localMatrix` directly so rotated / skewed
        // shaders route through the same shader path.
        //
        // Phase H2 paint-colorFilter -- 6 trailing vec4f starting at
        // float index 56 (byte offset 224). When the paint had no
        // colour filter, [colorFilterPacked] is the shared
        // [ZERO_COLOR_FILTER_24] sentinel, so the trailing 24 floats
        // are zero and the shader's `kind == 0` fast path keeps the
        // output bit-iso.
        val m = d.csMatrix
        val tf = d.csTfParams
        val cb = d.clipShapeBounds
        val r0 = d.devToImageRow0
        val r1 = d.devToImageRow1
        val packed = FloatArray(80) // 320 bytes / 4 bytes per float.
        packed[0] = d.srcL; packed[1] = d.srcT; packed[2] = d.srcR; packed[3] = d.srcB
        packed[4] = d.dstL; packed[5] = d.dstT; packed[6] = d.dstR; packed[7] = d.dstB
        packed[8] = d.imageWidth.toFloat(); packed[9] = d.imageHeight.toFloat()
        packed[10] = Float.fromBits(d.tileX.ordinal); packed[11] = Float.fromBits(d.tileY.ordinal)
        packed[12] = d.paintR; packed[13] = d.paintG; packed[14] = d.paintB; packed[15] = d.paintA
        packed[16] = Float.fromBits(d.csMode); packed[17] = 0f; packed[18] = 0f; packed[19] = 0f
        packed[20] = m[0]; packed[21] = m[1]; packed[22] = m[2]; packed[23] = 0f
        packed[24] = m[3]; packed[25] = m[4]; packed[26] = m[5]; packed[27] = 0f
        packed[28] = m[6]; packed[29] = m[7]; packed[30] = m[8]; packed[31] = 0f
        packed[32] = tf[0]; packed[33] = tf[1]; packed[34] = tf[2]; packed[35] = tf[3]
        packed[36] = tf[4]; packed[37] = tf[5]; packed[38] = tf[6]; packed[39] = 0f
        packed[40] = cb[0]; packed[41] = cb[1]; packed[42] = cb[2]; packed[43] = cb[3]
        packed[44] = d.clipShapeRx; packed[45] = d.clipShapeRy
        packed[46] = d.clipKind; packed[47] = d.strictConstraint
        packed[48] = r0[0]; packed[49] = r0[1]; packed[50] = r0[2]; packed[51] = 0f
        packed[52] = r1[0]; packed[53] = r1[1]; packed[54] = r1[2]; packed[55] = 0f
        // Phase H2 paint-colorFilter -- 6 contiguous vec4f starting at
        // float index 56 (offset 224 bytes).
        System.arraycopy(d.colorFilterPacked, 0, packed, 56, 24)
        context.queue.writeBuffer(uniform, 0uL, ArrayBuffer.of(packed))
        val view = d.texture.createView()
        val sampler = bitmapSamplerFor(d.filter, d.tileX, d.tileY)
        val bindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = bitmapBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = uniform)),
                    BindGroupEntry(binding = 1u, resource = view),
                    BindGroupEntry(binding = 2u, resource = sampler),
                ),
            ),
        )
        return DrawResources(uniform = uniform, bindGroup = bindGroup)
    }

    /**
     * Phase G-saveLayer-fast -- build per-draw resources for a
     * [LayerCompositeDraw]. The uniform carries the dst origin + layer
     * size + paint colour ; the bind group also captures the child's
     * intermediate texture view (already populated by
     * [flushDrawsOnly]).
     */
    private fun buildLayerCompositeDrawResources(d: LayerCompositeDraw): DrawResources {
        val uniform = context.device.createBuffer(
            BufferDescriptor(
                size = LAYER_COMPOSITE_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.layerCompositeDraw",
            ),
        )
        // Layout matches `layer_composite.wgsl` :
        //   offset   0 : dstOriginSize       (vec4f -- x, y, layerW, layerH)
        //   offset  16 : paintColor          (vec4f -- premul rgba modulation)
        //   offset  32 : colorFilterKindMode (vec4f -- kind, mode, 0, 0)
        //   offset  48 : colorFilterParam0   (vec4f -- premul colour OR matrix row 0)
        //   offset  64 : colorFilterParam1   (vec4f -- matrix row 1)
        //   offset  80 : colorFilterParam2   (vec4f -- matrix row 2)
        //   offset  96 : colorFilterParam3   (vec4f -- matrix row 3)
        //   offset 112 : colorFilterBias     (vec4f -- per-row bias)
        //   offset 128 : devToLayerRow0      (vec4f -- inv 2x3 row 0)
        //   offset 144 : devToLayerRow1      (vec4f -- inv 2x3 row 1)
        //   offset 160 : samplingMode        (vec4f -- mode, 0, 0, 0)
        //   offset 176 : imageFilterKindMode (vec4f -- kind, tile, zoom, inset)
        //   offset 192 : imageFilterRectA    (vec4f -- rect or lens or dst)
        //   offset 208 : imageFilterRectB    (vec4f -- Tile src ; else zeroed)
        // Total = 224 bytes. The colourFilter / matrix / image-filter
        // payloads are sentinel-zeroed when the layer paint has neither
        // colour filter nor image filter -- the shader's `kind == 0`
        // and `samplingMode == 0` and `imageFilterKind == 0` branches
        // are all no-ops, so the fast path stays bit-iso.
        val packed = FloatArray(LAYER_COMPOSITE_UNIFORM_FLOATS) // 14 vec4f * 4 floats each.
        packed[0] = d.dstOriginX.toFloat()
        packed[1] = d.dstOriginY.toFloat()
        packed[2] = d.layerWidth.toFloat()
        packed[3] = d.layerHeight.toFloat()
        packed[4] = d.paintR; packed[5] = d.paintG
        packed[6] = d.paintB; packed[7] = d.paintA
        // colorFilterPacked is laid out as 6 contiguous vec4f starting
        // at vec4f index 2 (offset 32 bytes).
        System.arraycopy(d.colorFilterPacked, 0, packed, 8, 24)
        // matrixPacked is 3 vec4f (devToLayerRow0, devToLayerRow1,
        // samplingMode) starting at vec4f index 8 (offset 128 bytes).
        System.arraycopy(d.matrixPacked, 0, packed, 32, 12)
        // imageFilterPacked is 3 contiguous vec4f starting at vec4f
        // index 11 (offset 176 bytes). Zeroed array for the no-IF fast
        // path keeps the shader's `imageFilterKind == 0` branch warm.
        System.arraycopy(d.imageFilterPacked, 0, packed, 44, 12)
        context.queue.writeBuffer(
            uniform, 0uL,
            ArrayBuffer.of(packed),
        )
        val bindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = layerCompositeBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = uniform)),
                    BindGroupEntry(binding = 1u, resource = d.layerView),
                ),
            ),
        )
        return DrawResources(
            uniform = uniform,
            bindGroup = bindGroup,
            // L1b -- transfer ownership of the materialise scratch
            // (allocated by [enqueueMaterializeMatrixTransformToScratch])
            // from the PendingDraw to the DrawResources so it's cleaned
            // up in [closeDrawResources] after the command buffer that
            // sampled it (the downstream Blur / ColorFilter /
            // LayerComposite draws) has been submitted. `null` on every
            // non-materialise draw so the fast path is bit-iso.
            materializeTargetTexture = d.materializeTargetTexture,
            materializeTargetView = d.materializeTargetView,
        )
    }

    /**
     * Phase G-saveLayer-blend -- build per-draw resources for a
     * [NonNativeBlendLayerCompositeDraw]. Allocates a snapshot texture
     * (W x H of the parent's intermediate) and builds two uniform
     * buffers + bind groups :
     *  - Snapshot pass : reuses `layer_composite.wgsl` with kSrc blend
     *    and `dstOriginSize = (0, 0, parentW, parentH)`. Source =
     *    parent's intermediate ; target = snapshot.
     *  - Blend composite : `layer_composite_blend.wgsl` with kSrc blend.
     *    Source = child's intermediate (layer) + snapshot (dst). Target
     *    = parent's intermediate. The uniform's `colorFilterKindMode.z`
     *    carries the user's blendMode ordinal so the shader's branch
     *    ladder evaluates the canonical formula in premul space.
     */
    private fun buildNonNativeBlendLayerCompositeDrawResources(
        d: NonNativeBlendLayerCompositeDraw,
    ): DrawResources {
        // Allocate the snapshot texture (same dims + format as the
        // parent's intermediate). Released by [closeDrawResources] via
        // the scratchPreCfTexture / scratchPreCfView slots (reused as a
        // generic "extra scratch" channel -- the draw never carries a
        // pre-blur CF in this path, so the slot is free).
        val snapshot = context.device.createTexture(
            TextureDescriptor(
                size = Extent3D(width = width.toUInt(), height = height.toUInt()),
                format = intermediateFormat,
                usage = GPUTextureUsage.RenderAttachment or GPUTextureUsage.TextureBinding,
                label = "SkWebGpuDevice.nonNativeBlendSnapshot",
            ),
        )
        val snapshotView = snapshot.createView()

        // Snapshot-pass uniform : layer_composite.wgsl with
        // dstOriginSize = (0, 0, parentW, parentH), paintColor = (1,1,1,1),
        // colorFilter/imageFilter/sampling kind = 0 (identity), so the
        // shader's output equals the loaded texel verbatim.
        val snapUniform = context.device.createBuffer(
            BufferDescriptor(
                size = LAYER_COMPOSITE_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.nonNativeBlendSnapshotUniform",
            ),
        )
        val snapPacked = FloatArray(LAYER_COMPOSITE_UNIFORM_FLOATS)
        snapPacked[0] = 0f; snapPacked[1] = 0f
        snapPacked[2] = width.toFloat(); snapPacked[3] = height.toFloat()
        snapPacked[4] = 1f; snapPacked[5] = 1f; snapPacked[6] = 1f; snapPacked[7] = 1f
        // Remaining layout slots stay zero; the shader's identity fast
        // paths run for color filters, matrix sampling and image filters.
        context.queue.writeBuffer(snapUniform, 0uL, ArrayBuffer.of(snapPacked))

        val snapBindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = layerCompositeBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = snapUniform)),
                    BindGroupEntry(binding = 1u, resource = intermediateView),
                ),
            ),
        )

        // Blend-composite uniform : layer_composite_blend.wgsl. Same
        // 128-byte layout as layer_composite ; the user's blendMode
        // ordinal goes into colorFilterKindMode.z so the shader can
        // dispatch on it without expanding the uniform.
        val blendUniform = context.device.createBuffer(
            BufferDescriptor(
                size = LAYER_COMPOSITE_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.nonNativeBlendComposite",
            ),
        )
        val blendPacked = FloatArray(LAYER_COMPOSITE_UNIFORM_FLOATS)
        blendPacked[0] = d.dstOriginX.toFloat()
        blendPacked[1] = d.dstOriginY.toFloat()
        blendPacked[2] = d.layerWidth.toFloat()
        blendPacked[3] = d.layerHeight.toFloat()
        blendPacked[4] = d.paintR; blendPacked[5] = d.paintG
        blendPacked[6] = d.paintB; blendPacked[7] = d.paintA
        // colorFilterPacked occupies vec4f indices 2..7 (24 floats from
        // float index 8). We then overwrite the third float of the first
        // vec4f (colorFilterKindMode.z) with the layer paint's blendMode
        // ordinal -- the source-side colour-filter payload only consumes
        // .x (kind) and .y (mode) so .z is free.
        System.arraycopy(d.colorFilterPacked, 0, blendPacked, 8, 24)
        blendPacked[10] = d.mode.ordinal.toFloat()
        context.queue.writeBuffer(blendUniform, 0uL, ArrayBuffer.of(blendPacked))

        val blendBindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = layerCompositeBlendBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = blendUniform)),
                    BindGroupEntry(binding = 1u, resource = d.layerView),
                    BindGroupEntry(binding = 2u, resource = snapshotView),
                ),
            ),
        )

        return DrawResources(
            uniform = snapUniform,
            bindGroup = snapBindGroup,
            secondaryUniform = blendUniform,
            secondaryBindGroup = blendBindGroup,
            // Park the snapshot lifetime on the V-pass scratch slots so
            // [closeDrawResources] releases it after submit -- the
            // semantics match (both are "scratch textures consumed by a
            // later pass within the same encoder").
            scratchVTexture = snapshot,
            scratchVView = snapshotView,
        )
    }

    /**
     * Phase MaskFilter-blur -- build the GPU resources for a
     * [BlurredPathDraw]. Two uniform buffers + two bind groups :
     *   - Primary (H pass) : axisRadius.x = 1, .y = 0, source binding
     *     is the child layer device's shape-mask view.
     *   - Secondary (V pass) : axisRadius.x = 0, .y = 1, source binding
     *     is the host-allocated H-pass scratch view.
     * Both uniforms share the same byte layout
     * ([BLUR_UNIFORM_SIZE]) ; only `axisRadius` and (for the V pass)
     * `paintColor` differ. The H uniform's `paintColor` is unused but
     * shipped as zeros for deterministic bytes.
     *
     * The kernel half-array (1 + radius floats) is packed into the
     * `weights` slot starting at offset 48 ; trailing slots are zeroed
     * so the uniform's WGSL `array<vec4f, 9>` is fully initialised.
     */
    private fun buildBlurredPathDrawResources(d: BlurredPathDraw): DrawResources {
        // For the single-stage path, the H pass reads the shape mask
        // directly. For the cascade path, the H pass reads the
        // SMALLEST cascade level (the final downsample output).
        val hSourceView =
            if (d.cascade != null) d.cascade.downLevels.last().view
            else d.shapeMaskView
        // For both paths the H scratch shares the H source's
        // dimensions. In the single-stage path that's (srcW, srcH) ;
        // in the cascade path that's the smallest level's dims.
        val hScratchW =
            if (d.cascade != null) d.cascade.downLevels.last().width
            else d.srcWidth
        val hScratchH =
            if (d.cascade != null) d.cascade.downLevels.last().height
            else d.srcHeight

        // ── H pass uniform : axisRadius = (1, 0, radius, 0). paintColor
        //    is irrelevant for the H pass (the V pass owns the colour
        //    fold) ; we ship zeros for deterministic bytes.
        val hUniform = context.device.createBuffer(
            BufferDescriptor(
                size = BLUR_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.blurHorizontalDraw",
            ),
        )
        val hPacked = FloatArray(BLUR_UNIFORM_FLOATS)
        // dstOriginSize : H pass writes to a scratch sized to (hScratchW, hScratchH)
        // with origin (0, 0) -- the shader treats dst pixel coords as
        // the source pixel coords directly.
        hPacked[0] = 0f; hPacked[1] = 0f
        hPacked[2] = hScratchW.toFloat(); hPacked[3] = hScratchH.toFloat()
        // paintColor : zero in the H pass (ignored by fs_horizontal).
        hPacked[4] = 0f; hPacked[5] = 0f; hPacked[6] = 0f; hPacked[7] = 0f
        // axisRadius : (1, 0, radius, 0). Style is irrelevant for the
        // H pass (the H entry doesn't read the shape mask) ; we ship 0
        // for deterministic bytes.
        hPacked[8] = 1f; hPacked[9] = 0f; hPacked[10] = d.radius.toFloat(); hPacked[11] = 0f
        // weights[0..radius] -> flat indices starting at packed[12].
        for (k in 0..d.radius) {
            hPacked[12 + k] = d.kernel[k]
        }
        context.queue.writeBuffer(hUniform, 0uL, ArrayBuffer.of(hPacked))
        // Binding 2 (shape mask) is unused by the H entry but the
        // shared layout requires it ; bind the H-source view so a
        // valid texture sits in the slot.
        val hBindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = blurBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = hUniform)),
                    BindGroupEntry(binding = 1u, resource = hSourceView),
                    BindGroupEntry(binding = 2u, resource = hSourceView),
                ),
            ),
        )

        // Single-stage path : build the V uniform + bind group that
        // does the V Gaussian convolution AND the style/paint composite
        // onto the parent. The cascade path takes a different shape
        // below (inner V is blur-only, final composite is a separate
        // pass).
        if (d.cascade == null) {
            // ── V pass uniform : axisRadius = (0, 1, radius, style).
            val vUniform = context.device.createBuffer(
                BufferDescriptor(
                    size = BLUR_UNIFORM_SIZE,
                    usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                    label = "SkWebGpuDevice.blurVerticalDraw",
                ),
            )
            val vPacked = FloatArray(BLUR_UNIFORM_FLOATS)
            vPacked[0] = d.dstOriginX.toFloat(); vPacked[1] = d.dstOriginY.toFloat()
            vPacked[2] = d.srcWidth.toFloat(); vPacked[3] = d.srcHeight.toFloat()
            vPacked[4] = d.paintR; vPacked[5] = d.paintG
            vPacked[6] = d.paintB; vPacked[7] = d.paintA
            vPacked[8] = 0f
            vPacked[9] = 1f
            vPacked[10] = d.radius.toFloat()
            vPacked[11] = d.blurStyleOrdinal.toFloat()
            for (k in 0..d.radius) {
                vPacked[12 + k] = d.kernel[k]
            }
            writeBlurClipShape(vPacked, d)
            context.queue.writeBuffer(vUniform, 0uL, ArrayBuffer.of(vPacked))
            val vBindGroup = context.device.createBindGroup(
                BindGroupDescriptor(
                    layout = blurBindGroupLayout,
                    entries = listOf(
                        BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = vUniform)),
                        BindGroupEntry(binding = 1u, resource = d.scratchHView),
                        BindGroupEntry(binding = 2u, resource = d.shapeMaskView),
                    ),
                ),
            )
            return DrawResources(
                uniform = hUniform,
                bindGroup = hBindGroup,
                secondaryUniform = vUniform,
                secondaryBindGroup = vBindGroup,
                scratchHTexture = d.scratchHTexture,
                scratchHView = d.scratchHView,
                layerDevice = d.shapeMaskDevice,
            )
        }

        // Cascade path -- build the per-stage resources for the
        // downsample chain, the inner V-blur pass, the upsample chain,
        // and the final composite pass.
        val cascade = d.cascade
        val n = cascade.downLevels.size

        // Downsample uniforms + bind groups. The i-th pass reads from
        // its source view (shapeMask for i = 0, downLevels[i - 1].view
        // otherwise) and writes to downLevels[i].
        val downsampleUniforms = ArrayList<GPUBuffer>(n)
        val downsampleBindGroups =
            ArrayList<io.ygdrasil.webgpu.GPUBindGroup>(n)
        for (i in 0 until n) {
            val src = if (i == 0) d.shapeMaskView else cascade.downLevels[i - 1].view
            val srcLevelW = if (i == 0) d.srcWidth else cascade.downLevels[i - 1].width
            val srcLevelH = if (i == 0) d.srcHeight else cascade.downLevels[i - 1].height
            val dst = cascade.downLevels[i]
            val u = context.device.createBuffer(
                BufferDescriptor(
                    size = BLUR_RESAMPLE_UNIFORM_SIZE,
                    usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                    label = "SkWebGpuDevice.blurDownsample$i",
                ),
            )
            val packed = FloatArray(4)
            packed[0] = dst.width.toFloat(); packed[1] = dst.height.toFloat()
            packed[2] = srcLevelW.toFloat(); packed[3] = srcLevelH.toFloat()
            context.queue.writeBuffer(u, 0uL, ArrayBuffer.of(packed))
            val bg = context.device.createBindGroup(
                BindGroupDescriptor(
                    layout = blurResampleBindGroupLayout,
                    entries = listOf(
                        BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = u)),
                        BindGroupEntry(binding = 1u, resource = src),
                        BindGroupEntry(binding = 2u, resource = blurResampleSampler),
                    ),
                ),
            )
            downsampleUniforms += u
            downsampleBindGroups += bg
        }

        // Inner V uniform : axisRadius = (0, 1, radius, 0). Style /
        // paint are unused (the final composite handles them).
        val innerVUniform = context.device.createBuffer(
            BufferDescriptor(
                size = BLUR_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.blurCascadeInnerV",
            ),
        )
        val innerVPacked = FloatArray(BLUR_UNIFORM_FLOATS)
        innerVPacked[0] = 0f; innerVPacked[1] = 0f
        innerVPacked[2] = hScratchW.toFloat(); innerVPacked[3] = hScratchH.toFloat()
        innerVPacked[4] = 0f; innerVPacked[5] = 0f
        innerVPacked[6] = 0f; innerVPacked[7] = 0f
        innerVPacked[8] = 0f
        innerVPacked[9] = 1f
        innerVPacked[10] = d.radius.toFloat()
        innerVPacked[11] = 0f
        for (k in 0..d.radius) {
            innerVPacked[12 + k] = d.kernel[k]
        }
        context.queue.writeBuffer(innerVUniform, 0uL, ArrayBuffer.of(innerVPacked))
        val innerVBindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = blurBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = innerVUniform)),
                    BindGroupEntry(binding = 1u, resource = d.scratchHView),
                    BindGroupEntry(binding = 2u, resource = d.scratchHView),
                ),
            ),
        )

        // Upsample uniforms + bind groups. The i-th pass samples from
        // (i == 0 ? innerV : upLevels[i - 1]) and writes to upLevels[i].
        val upsampleUniforms = ArrayList<GPUBuffer>(n)
        val upsampleBindGroups = ArrayList<io.ygdrasil.webgpu.GPUBindGroup>(n)
        for (i in 0 until n) {
            val src: GPUTextureView
            val srcLevelW: Int
            val srcLevelH: Int
            if (i == 0) {
                src = cascade.innerVView
                // Inner V dims match the smallest downsample level.
                srcLevelW = cascade.downLevels.last().width
                srcLevelH = cascade.downLevels.last().height
            } else {
                src = cascade.upLevels[i - 1].view
                srcLevelW = cascade.upLevels[i - 1].width
                srcLevelH = cascade.upLevels[i - 1].height
            }
            val dst = cascade.upLevels[i]
            val u = context.device.createBuffer(
                BufferDescriptor(
                    size = BLUR_RESAMPLE_UNIFORM_SIZE,
                    usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                    label = "SkWebGpuDevice.blurUpsample$i",
                ),
            )
            val packed = FloatArray(4)
            packed[0] = dst.width.toFloat(); packed[1] = dst.height.toFloat()
            packed[2] = srcLevelW.toFloat(); packed[3] = srcLevelH.toFloat()
            context.queue.writeBuffer(u, 0uL, ArrayBuffer.of(packed))
            val bg = context.device.createBindGroup(
                BindGroupDescriptor(
                    layout = blurResampleBindGroupLayout,
                    entries = listOf(
                        BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = u)),
                        BindGroupEntry(binding = 1u, resource = src),
                        BindGroupEntry(binding = 2u, resource = blurResampleSampler),
                    ),
                ),
            )
            upsampleUniforms += u
            upsampleBindGroups += bg
        }

        // Final composite uniform : axisRadius.x/.y/.z are unused by
        // `fs_composite_upsampled` (no convolution) ; only .w (style)
        // matters. Pack the paint colour and the origin so the shader
        // can map fragment dst -> upsampled-mask sample.
        val compositeUniform = context.device.createBuffer(
            BufferDescriptor(
                size = BLUR_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.blurCascadeComposite",
            ),
        )
        val cPacked = FloatArray(BLUR_UNIFORM_FLOATS)
        cPacked[0] = d.dstOriginX.toFloat(); cPacked[1] = d.dstOriginY.toFloat()
        cPacked[2] = d.srcWidth.toFloat(); cPacked[3] = d.srcHeight.toFloat()
        cPacked[4] = d.paintR; cPacked[5] = d.paintG
        cPacked[6] = d.paintB; cPacked[7] = d.paintA
        cPacked[8] = 0f; cPacked[9] = 0f
        cPacked[10] = 0f; cPacked[11] = d.blurStyleOrdinal.toFloat()
        writeBlurClipShape(cPacked, d)
        context.queue.writeBuffer(compositeUniform, 0uL, ArrayBuffer.of(cPacked))
        val compositeBindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = blurBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = compositeUniform)),
                    BindGroupEntry(binding = 1u, resource = cascade.upLevels.last().view),
                    BindGroupEntry(binding = 2u, resource = d.shapeMaskView),
                ),
            ),
        )

        // Collect the owned cascade textures + views for cleanup.
        val cascadeTextures = ArrayList<GPUTexture>(2 * n + 1)
        val cascadeViews = ArrayList<GPUTextureView>(2 * n + 1)
        cascade.downLevels.forEach {
            cascadeTextures += it.texture
            cascadeViews += it.view
        }
        cascadeTextures += cascade.innerVTexture
        cascadeViews += cascade.innerVView
        cascade.upLevels.forEach {
            cascadeTextures += it.texture
            cascadeViews += it.view
        }

        return DrawResources(
            uniform = hUniform,
            bindGroup = hBindGroup,
            scratchHTexture = d.scratchHTexture,
            scratchHView = d.scratchHView,
            layerDevice = d.shapeMaskDevice,
            cascadeDownsampleUniforms = downsampleUniforms,
            cascadeDownsampleBindGroups = downsampleBindGroups,
            cascadeUpsampleUniforms = upsampleUniforms,
            cascadeUpsampleBindGroups = upsampleBindGroups,
            cascadeInnerVUniform = innerVUniform,
            cascadeInnerVBindGroup = innerVBindGroup,
            cascadeCompositeUniform = compositeUniform,
            cascadeCompositeBindGroup = compositeBindGroup,
            cascadeTextures = cascadeTextures,
            cascadeViews = cascadeViews,
        )
    }

    private fun writeBlurClipShape(packed: FloatArray, d: BlurredPathDraw) {
        val cb = d.clipShapeBounds
        packed[48] = cb[0]; packed[49] = cb[1]; packed[50] = cb[2]; packed[51] = cb[3]
        packed[52] = d.clipShapeRx; packed[53] = d.clipShapeRy
        packed[54] = d.clipKind; packed[55] = 0f
    }

    /**
     * Phase MaskFilter-blur-shaded -- build the GPU resources for a
     * [BlurredShadedPathDraw]. Shape mirrors
     * [buildBlurredPathDrawResources] (two uniform buffers + two bind
     * groups against the shared [blurBindGroupLayout]) but :
     *   - Primary (H pass) binding 1 + 2 are both the shaded layer view
     *     (the H pass only reads binding 1 ; binding 2 is kept for
     *     layout parity).
     *   - Secondary (V pass) binding 1 is the H-pass scratch, binding
     *     2 is the shaded layer (consumed by the kSolid / kOuter /
     *     kInner style combine).
     * Both uniforms share the [BLUR_UNIFORM_SIZE] byte layout ; the
     * `paintColor` slot ships as zeros (the shaded layer already
     * carries the final colours, no paint-colour fold in the shader).
     */
    private fun buildBlurredShadedPathDrawResources(d: BlurredShadedPathDraw): DrawResources {
        // ── H pass uniform : axisRadius = (1, 0, radius, 0). paintColor
        //    is zero (the shaded layer carries the final colours).
        val hUniform = context.device.createBuffer(
            BufferDescriptor(
                size = BLUR_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.shadedBlurHorizontalDraw",
            ),
        )
        val hPacked = FloatArray(BLUR_UNIFORM_FLOATS)
        hPacked[0] = 0f; hPacked[1] = 0f
        hPacked[2] = d.srcWidth.toFloat(); hPacked[3] = d.srcHeight.toFloat()
        // paintColor : unused for the shaded variant ; ship zeros for
        // deterministic bytes.
        hPacked[4] = 0f; hPacked[5] = 0f; hPacked[6] = 0f; hPacked[7] = 0f
        hPacked[8] = 1f; hPacked[9] = 0f; hPacked[10] = d.radius.toFloat(); hPacked[11] = 0f
        for (k in 0..d.radius) {
            hPacked[12 + k] = d.kernel[k]
        }
        context.queue.writeBuffer(hUniform, 0uL, ArrayBuffer.of(hPacked))
        val hBindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = blurBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = hUniform)),
                    BindGroupEntry(binding = 1u, resource = d.shadedLayerView),
                    BindGroupEntry(binding = 2u, resource = d.shadedLayerView),
                ),
            ),
        )

        // ── V pass uniform : axisRadius = (0, 1, radius, blurStyle).
        val vUniform = context.device.createBuffer(
            BufferDescriptor(
                size = BLUR_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.shadedBlurVerticalDraw",
            ),
        )
        val vPacked = FloatArray(BLUR_UNIFORM_FLOATS)
        vPacked[0] = d.dstOriginX.toFloat(); vPacked[1] = d.dstOriginY.toFloat()
        vPacked[2] = d.srcWidth.toFloat(); vPacked[3] = d.srcHeight.toFloat()
        // PR #612 K2-GPU -- paintColor.x carries the "sharp shader RGB
        // modulated by blurred shape alpha" flag (see
        // blur_mask_filter_shaded.wgsl). Set to 1.0 when the dispatcher
        // detected the K2 SkBitmapShader+kDecal+rect routing ; the V
        // pass then takes the new branch on style == kNormal. All other
        // shaded paints (gradients / non-decal bitmaps) keep paintColor
        // as zero and fall back to the legacy `out = B` semantics.
        vPacked[4] = if (d.sharpRgbMode) 1f else 0f
        vPacked[5] = 0f; vPacked[6] = 0f; vPacked[7] = 0f
        vPacked[8] = 0f
        vPacked[9] = 1f
        vPacked[10] = d.radius.toFloat()
        vPacked[11] = d.blurStyleOrdinal.toFloat()
        for (k in 0..d.radius) {
            vPacked[12 + k] = d.kernel[k]
        }
        context.queue.writeBuffer(vUniform, 0uL, ArrayBuffer.of(vPacked))
        val vBindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = blurBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = vUniform)),
                    BindGroupEntry(binding = 1u, resource = d.scratchHView),
                    BindGroupEntry(binding = 2u, resource = d.shadedLayerView),
                ),
            ),
        )
        return DrawResources(
            uniform = hUniform,
            bindGroup = hBindGroup,
            secondaryUniform = vUniform,
            secondaryBindGroup = vBindGroup,
            scratchHTexture = d.scratchHTexture,
            scratchHView = d.scratchHView,
            layerDevice = d.shadedLayerDevice,
        )
    }

    /**
     * Phase G-saveLayer-imageFilter-blur -- build the GPU resources for
     * a [BlurredLayerCompositeDraw]. Three uniform buffers + three bind
     * groups :
     *   - Primary   (H pass)    : `axisTileRadius.x = 1, .y = 0`, source
     *                              binding is the layer texture view.
     *                              Kernel + radius are per-X.
     *   - Secondary (V pass)    : `axisTileRadius.x = 0, .y = 1`, source
     *                              binding is the H-pass scratch view.
     *                              Kernel + radius are per-Y.
     *   - Tertiary  (composite) : layout matches `layer_composite.wgsl`
     *                              (128-byte uniform : dstOriginSize,
     *                              paintColor, colorFilter*). Source
     *                              binding is the V-pass scratch view.
     *
     * The H and V uniforms share the [BLUR_IMAGE_FILTER_UNIFORM_SIZE]
     * byte layout ; only the per-axis flags + the kernel data differ.
     * The composite uniform is the same byte layout as the
     * no-imageFilter [LayerCompositeDraw], so the pixel result for
     * the colour-filter-applied step is bit-iso with the plain
     * saveLayer composite for the same paint payload.
     */
    private fun buildBlurredLayerCompositeDrawResources(
        d: BlurredLayerCompositeDraw,
    ): DrawResources {
        // ── Phase G-saveLayer-imageFilter-compose -- optional pre-blur
        //    CF pass. Allocated only when the draw carries a pre-blur
        //    CF (i.e. a Compose chain landed with a CF inner of a Blur
        //    outer). Reuses the layer_composite.wgsl shader / bind
        //    group layout with kSrc blend so the scratch is overwritten
        //    rather than blended with prior content.
        val preCfPacked = d.preBlurColorFilterPacked
        val preCfView = d.scratchPreCfView
        var preCfUniform: GPUBuffer? = null
        var preCfBindGroup: io.ygdrasil.webgpu.GPUBindGroup? = null
        // The blur H pass reads from preCfView when the pre-CF pass
        // produced one ; otherwise it reads from the raw layer view.
        val hPassSourceView: GPUTextureView = preCfView ?: d.layerView
        if (preCfPacked != null && preCfView != null) {
            preCfUniform = context.device.createBuffer(
                BufferDescriptor(
                    size = LAYER_COMPOSITE_UNIFORM_SIZE,
                    usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                    label = "SkWebGpuDevice.blurImageFilterPreCfDraw",
                ),
            )
            // layer_composite.wgsl uniform layout : 11 vec4f.
            //   dstOriginSize : (0, 0, w, h)  -> identity mapping
            //   paintColor    : (1, 1, 1, 1)  -> no scale
            //   colorFilter*  : packed CF (6 vec4f, 24 floats)
            //   matrix slots  : identity / off (3 vec4f, 12 floats) --
            //                   pre-blur CF doesn't carry a transform.
            val packed = FloatArray(LAYER_COMPOSITE_UNIFORM_FLOATS)
            packed[0] = 0f; packed[1] = 0f
            packed[2] = d.layerWidth.toFloat(); packed[3] = d.layerHeight.toFloat()
            packed[4] = 1f; packed[5] = 1f; packed[6] = 1f; packed[7] = 1f
            System.arraycopy(preCfPacked, 0, packed, 8, 24)
            System.arraycopy(IDENTITY_LAYER_MATRIX_12, 0, packed, 32, 12)
            context.queue.writeBuffer(preCfUniform, 0uL, ArrayBuffer.of(packed))
            preCfBindGroup = context.device.createBindGroup(
                BindGroupDescriptor(
                    layout = layerCompositeBindGroupLayout,
                    entries = listOf(
                        BindGroupEntry(
                            binding = 0u,
                            resource = BufferBinding(buffer = preCfUniform),
                        ),
                        BindGroupEntry(binding = 1u, resource = d.layerView),
                    ),
                ),
            )
        }

        // ── H pass uniform : axisTileRadius = (1, 0, tileMode, radiusX).
        val hUniform = context.device.createBuffer(
            BufferDescriptor(
                size = BLUR_IMAGE_FILTER_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.blurImageFilterHorizontalDraw",
            ),
        )
        val hPacked = FloatArray(BLUR_IMAGE_FILTER_UNIFORM_FLOATS)
        // dstOriginSize.xy unused (layer-space sampling), .zw = (w, h).
        hPacked[0] = 0f; hPacked[1] = 0f
        hPacked[2] = d.layerWidth.toFloat(); hPacked[3] = d.layerHeight.toFloat()
        // axisTileRadius = (1, 0, tileMode, radiusX).
        hPacked[4] = 1f; hPacked[5] = 0f
        hPacked[6] = d.tileModeOrdinal.toFloat()
        hPacked[7] = d.radiusX.toFloat()
        // weights[0..radiusX] -> flat indices starting at packed[8].
        for (k in 0..d.radiusX) {
            hPacked[8 + k] = d.kernelX[k]
        }
        context.queue.writeBuffer(hUniform, 0uL, ArrayBuffer.of(hPacked))
        val hBindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = blurImageFilterBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = hUniform)),
                    BindGroupEntry(binding = 1u, resource = hPassSourceView),
                ),
            ),
        )

        // ── V pass uniform : axisTileRadius = (0, 1, tileMode, radiusY).
        val vUniform = context.device.createBuffer(
            BufferDescriptor(
                size = BLUR_IMAGE_FILTER_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.blurImageFilterVerticalDraw",
            ),
        )
        val vPacked = FloatArray(BLUR_IMAGE_FILTER_UNIFORM_FLOATS)
        vPacked[0] = 0f; vPacked[1] = 0f
        vPacked[2] = d.layerWidth.toFloat(); vPacked[3] = d.layerHeight.toFloat()
        vPacked[4] = 0f; vPacked[5] = 1f
        vPacked[6] = d.tileModeOrdinal.toFloat()
        vPacked[7] = d.radiusY.toFloat()
        for (k in 0..d.radiusY) {
            vPacked[8 + k] = d.kernelY[k]
        }
        context.queue.writeBuffer(vUniform, 0uL, ArrayBuffer.of(vPacked))
        val vBindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = blurImageFilterBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = vUniform)),
                    BindGroupEntry(binding = 1u, resource = d.scratchHView),
                ),
            ),
        )

        // ── Composite pass uniform : matches `layer_composite.wgsl`'s
        //    176-byte layout. dstOriginSize : (originX, originY,
        //    layerW, layerH) -- the composite shader subtracts this
        //    origin to map the parent-pixel fragment to a layer-pixel
        //    sample. paintColor + colorFilter + matrix payload mirror
        //    the plain [LayerCompositeDraw] packing ; the matrix slots
        //    ship the identity / off sentinel because the blur image
        //    filter pipeline doesn't compose with MatrixTransform yet.
        val compUniform = context.device.createBuffer(
            BufferDescriptor(
                size = LAYER_COMPOSITE_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.blurImageFilterCompositeDraw",
            ),
        )
        val compPacked = FloatArray(LAYER_COMPOSITE_UNIFORM_FLOATS) // 11 vec4f * 4 floats each.
        compPacked[0] = d.dstOriginX.toFloat()
        compPacked[1] = d.dstOriginY.toFloat()
        compPacked[2] = d.layerWidth.toFloat()
        compPacked[3] = d.layerHeight.toFloat()
        compPacked[4] = d.paintR; compPacked[5] = d.paintG
        compPacked[6] = d.paintB; compPacked[7] = d.paintA
        System.arraycopy(d.colorFilterPacked, 0, compPacked, 8, 24)
        // Phase G-saveLayer-imageFilter-matrixTransform -- the blur
        // composite doesn't carry a MatrixTransform (the affine + blur
        // combination is deferred to a Compose-chain follow-up). Ship
        // the identity / off payload so the shader's integer-grid fast
        // path stays bit-iso with the pre-MatrixTransform behaviour.
        System.arraycopy(IDENTITY_LAYER_MATRIX_12, 0, compPacked, 32, 12)
        context.queue.writeBuffer(compUniform, 0uL, ArrayBuffer.of(compPacked))
        val compBindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = layerCompositeBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = compUniform)),
                    BindGroupEntry(binding = 1u, resource = d.scratchVView),
                ),
            ),
        )

        return DrawResources(
            uniform = hUniform,
            bindGroup = hBindGroup,
            secondaryUniform = vUniform,
            secondaryBindGroup = vBindGroup,
            tertiaryUniform = compUniform,
            tertiaryBindGroup = compBindGroup,
            scratchHTexture = d.scratchHTexture,
            scratchHView = d.scratchHView,
            scratchVTexture = d.scratchVTexture,
            scratchVView = d.scratchVView,
            // Phase G-saveLayer-imageFilter-compose -- pre-blur CF
            // pass resources (only populated when the draw carried a
            // pre-blur CF, else left null and the dispatch skips the
            // pre-CF render pass).
            quaternaryUniform = preCfUniform,
            quaternaryBindGroup = preCfBindGroup,
            scratchPreCfTexture = d.scratchPreCfTexture,
            scratchPreCfView = d.scratchPreCfView,
            // N1 -- chain-of-passes : transfer ownership of the
            // materialise scratch (allocated by the BlurCF materialise
            // helper) so it gets cleaned up after the downstream consumer
            // draws have been submitted. Null on the non-materialise
            // (final-composite) path.
            materializeTargetTexture = d.materializeTargetTexture,
            materializeTargetView = d.materializeTargetView,
            // layerDevice intentionally left null -- the layer device
            // is owned by SkCanvas, not by this draw (mirrors
            // [LayerCompositeDraw]).
        )
    }

    /**
     * Phase G-saveLayer-imageFilter-dropshadow -- build the GPU resources
     * for a [DropShadowLayerCompositeDraw]. Four uniform buffers + four
     * bind groups :
     *   - Primary    (H blur)            : same shape as the plain blur
     *                                       ImageFilter's primary -- sources
     *                                       the layer texture, X-axis kernel.
     *   - Secondary  (V blur)            : sources the H scratch, Y-axis
     *                                       kernel.
     *   - Tertiary   (shadow composite)  : sources the V scratch, applies
     *                                       the packed `Blend(shadowColor,
     *                                       kSrcIn)` colour filter, lands
     *                                       at the shifted origin.
     *   - Quaternary (original composite): sources the layer texture
     *                                       directly, applies the paint's
     *                                       regular colour filter, lands
     *                                       at the original origin.
     *
     * The two composite uniforms share the same byte layout
     * ([LAYER_COMPOSITE_UNIFORM_SIZE]) as the no-filter saveLayer ; only
     * their `dstOriginSize.xy` + `colorFilterPacked` payload differ.
     */
    private fun buildDropShadowLayerCompositeDrawResources(
        d: DropShadowLayerCompositeDraw,
    ): DrawResources {
        // ── H blur pass uniform : axisTileRadius = (1, 0, kDecal, radiusX).
        val hUniform = context.device.createBuffer(
            BufferDescriptor(
                size = BLUR_IMAGE_FILTER_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.dropShadowBlurHorizontalDraw",
            ),
        )
        val hPacked = FloatArray(BLUR_IMAGE_FILTER_UNIFORM_FLOATS)
        hPacked[0] = 0f; hPacked[1] = 0f
        hPacked[2] = d.layerWidth.toFloat(); hPacked[3] = d.layerHeight.toFloat()
        hPacked[4] = 1f; hPacked[5] = 0f
        hPacked[6] = d.tileModeOrdinal.toFloat()
        hPacked[7] = d.radiusX.toFloat()
        for (k in 0..d.radiusX) {
            hPacked[8 + k] = d.kernelX[k]
        }
        context.queue.writeBuffer(hUniform, 0uL, ArrayBuffer.of(hPacked))
        val hBindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = blurImageFilterBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = hUniform)),
                    BindGroupEntry(binding = 1u, resource = d.layerView),
                ),
            ),
        )

        // ── V blur pass uniform : axisTileRadius = (0, 1, kDecal, radiusY).
        val vUniform = context.device.createBuffer(
            BufferDescriptor(
                size = BLUR_IMAGE_FILTER_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.dropShadowBlurVerticalDraw",
            ),
        )
        val vPacked = FloatArray(BLUR_IMAGE_FILTER_UNIFORM_FLOATS)
        vPacked[0] = 0f; vPacked[1] = 0f
        vPacked[2] = d.layerWidth.toFloat(); vPacked[3] = d.layerHeight.toFloat()
        vPacked[4] = 0f; vPacked[5] = 1f
        vPacked[6] = d.tileModeOrdinal.toFloat()
        vPacked[7] = d.radiusY.toFloat()
        for (k in 0..d.radiusY) {
            vPacked[8 + k] = d.kernelY[k]
        }
        context.queue.writeBuffer(vUniform, 0uL, ArrayBuffer.of(vPacked))
        val vBindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = blurImageFilterBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = vUniform)),
                    BindGroupEntry(binding = 1u, resource = d.scratchHView),
                ),
            ),
        )

        // ── Shadow composite uniform : dstOriginSize at the shifted
        //    origin, paintColor = (1, 1, 1, 1) (shadow alpha is folded
        //    into the colour-filter's premul colour), colour filter =
        //    Blend(shadowColor, kSrcIn).
        val shadowUniform = context.device.createBuffer(
            BufferDescriptor(
                size = LAYER_COMPOSITE_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.dropShadowShadowCompositeDraw",
            ),
        )
        val shadowPacked = FloatArray(LAYER_COMPOSITE_UNIFORM_FLOATS)
        shadowPacked[0] = d.shadowDstOriginX.toFloat()
        shadowPacked[1] = d.shadowDstOriginY.toFloat()
        shadowPacked[2] = d.layerWidth.toFloat()
        shadowPacked[3] = d.layerHeight.toFloat()
        // paintColor = (1, 1, 1, 1) -- the shadow's alpha + paint alpha
        // modulation is already folded into the colour-filter's premul
        // src colour, so we don't double-multiply here.
        shadowPacked[4] = 1f; shadowPacked[5] = 1f
        shadowPacked[6] = 1f; shadowPacked[7] = 1f
        System.arraycopy(d.shadowColorFilterPacked, 0, shadowPacked, 8, 24)
        // Phase G-saveLayer-imageFilter-matrixTransform -- DropShadow
        // doesn't carry an affine remap, ship the identity / off payload.
        System.arraycopy(IDENTITY_LAYER_MATRIX_12, 0, shadowPacked, 32, 12)
        context.queue.writeBuffer(shadowUniform, 0uL, ArrayBuffer.of(shadowPacked))
        val shadowBindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = layerCompositeBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = shadowUniform)),
                    BindGroupEntry(binding = 1u, resource = d.scratchVView),
                ),
            ),
        )

        // ── Original composite uniform : dstOriginSize at the layer's
        //    original origin, paintColor = (paintA, paintA, paintA,
        //    paintA), colour filter = the paint's original.
        val originalUniform = context.device.createBuffer(
            BufferDescriptor(
                size = LAYER_COMPOSITE_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.dropShadowOriginalCompositeDraw",
            ),
        )
        val originalPacked = FloatArray(LAYER_COMPOSITE_UNIFORM_FLOATS)
        originalPacked[0] = d.dstOriginX.toFloat()
        originalPacked[1] = d.dstOriginY.toFloat()
        originalPacked[2] = d.layerWidth.toFloat()
        originalPacked[3] = d.layerHeight.toFloat()
        originalPacked[4] = d.paintR; originalPacked[5] = d.paintG
        originalPacked[6] = d.paintB; originalPacked[7] = d.paintA
        System.arraycopy(d.originalColorFilterPacked, 0, originalPacked, 8, 24)
        // Phase G-saveLayer-imageFilter-matrixTransform -- ship identity.
        System.arraycopy(IDENTITY_LAYER_MATRIX_12, 0, originalPacked, 32, 12)
        context.queue.writeBuffer(originalUniform, 0uL, ArrayBuffer.of(originalPacked))
        val originalBindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = layerCompositeBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = originalUniform)),
                    BindGroupEntry(binding = 1u, resource = d.layerView),
                ),
            ),
        )

        return DrawResources(
            uniform = hUniform,
            bindGroup = hBindGroup,
            secondaryUniform = vUniform,
            secondaryBindGroup = vBindGroup,
            tertiaryUniform = shadowUniform,
            tertiaryBindGroup = shadowBindGroup,
            scratchHTexture = d.scratchHTexture,
            scratchHView = d.scratchHView,
            scratchVTexture = d.scratchVTexture,
            scratchVView = d.scratchVView,
            quaternaryUniform = originalUniform,
            quaternaryBindGroup = originalBindGroup,
            // layerDevice intentionally left null -- the layer device
            // is owned by SkCanvas, not by this draw (mirrors
            // [BlurredLayerCompositeDraw]).
            // L1a -- transfer ownership of the materialise scratch
            // (allocated by [enqueueMaterializeDropShadowToScratch]) from
            // the PendingDraw to the DrawResources so it gets cleaned up
            // in [closeDrawResources] after the command buffer that
            // sampled it (the downstream Blur / ColorFilter / LayerComposite
            // draws) has been submitted.
            materializeTargetTexture = d.materializeTargetTexture,
            materializeTargetView = d.materializeTargetView,
        )
    }

    private fun buildStencilCoverAaDrawResources(d: StencilCoverAaPolygonDraw): DrawResources {
        val uniform = context.device.createBuffer(
            BufferDescriptor(
                size = AA_POLYGON_UNIFORM_SIZE,
                usage = GPUBufferUsage.Uniform or GPUBufferUsage.CopyDst,
                label = "SkWebGpuDevice.stencilCoverAaDraw",
            ),
        )
        // Base layout shared with `aa_polygon.wgsl` / `aa_stencil_cover.wgsl` ;
        // the final two FOR-394 diagnostic vec4 slots are consumed only by
        // `aa_stencil_cover.wgsl` and remain zero outside the M60 F16 opt-in.
        //   offset    0 : color           (vec4)
        //   offset   16 : viewport        (vec4, only x/y used)
        //   offset   32 : edgeCount + fillType + pad (u32 reinterp)
        //   offset   48 : edges[256]      (vec4 each, here (Ax, Ay, Bx, By))
        //   offset 4144 : clipShapeBounds (vec4) ; G2.x (closing slice)
        //   offset 4160 : clipShapeRadiiKind (vec4) ; G2.x (closing slice)
        //   offset 4176 : colorFilter* (6 * vec4 = 24 floats) ; Phase
        //                 G-direct-colorFilter (polygon closing slice)
        //   offset 4272 : m60F16BandMetadata0 (vec4) ; FOR-394 diagnostic
        //   offset 4288 : m60F16BandMetadata1 (vec4) ; FOR-394 diagnostic
        val packed = FloatArray(12 + MAX_AA_EDGES * 4 + 8 + 24 + 8)
        packed[0] = d.r; packed[1] = d.g; packed[2] = d.b; packed[3] = d.a
        packed[4] = width.toFloat(); packed[5] = height.toFloat()
        packed[6] = 0f; packed[7] = 0f
        packed[8] = Float.fromBits(d.edgeCount)
        packed[9] = Float.fromBits(d.fillType.ordinal)
        packed[10] = 0f; packed[11] = 0f
        System.arraycopy(d.edges, 0, packed, 12, d.edges.size)
        writeClipShape(packed, 12 + MAX_AA_EDGES * 4, d.clipShape)
        // Phase G-direct-colorFilter -- colour-filter payload at offset
        // 4176 (= float index 12 + MAX_AA_EDGES * 4 + 8).
        val colorFilterBase = 12 + MAX_AA_EDGES * 4 + 8
        System.arraycopy(d.colorFilterPacked, 0, packed, colorFilterBase, 24)
        packed[colorFilterBase + 2] = if (d.m60F16SourceColorCorrectionProbe) 0f else targetColorSpaceBlendFlag()
        d.m60F16BandMetadata?.packInto(packed, colorFilterBase + 24)
        context.queue.writeBuffer(uniform, 0uL, ArrayBuffer.of(packed))
        val bindGroup = context.device.createBindGroup(
            BindGroupDescriptor(
                layout = aaPolygonBindGroupLayout,
                entries = listOf(
                    BindGroupEntry(binding = 0u, resource = BufferBinding(buffer = uniform)),
                ),
            ),
        )
        val applicationPointDiagnosticForDraw =
            m60F16BoundedCorrectionApplicationPointDiagnosticsEnabled &&
                d.m60F16BoundedRuntimeCorrectionProbe
        val coverageStencilContributionMapDiagnosticForDraw =
            m60F16CoverageStencilContributionMapDiagnosticsEnabled &&
                d.m60F16BoundedRuntimeCorrectionProbe
        val contributionIsolationDiagnosticForDraw =
            m60F16AaStencilCoverContributionIsolationDiagnosticsEnabled &&
                d.m60F16BandMetadata != null &&
                (
                    d.m60F16BoundedRuntimeCorrectionProbe ||
                        (
                            d.m60F16WidthQuantizedRenderFixFor431 &&
                                m60F16WidthQuantizedColorReconstructionFor432Requested
                            )
                    )
        val shaderReturnDiagnosticForDraw =
            m60F16AaStencilCoverShaderReturnDiagnosticsEnabled &&
                d.m60F16BandMetadata != null &&
                (
                    d.m60F16BoundedRuntimeCorrectionProbe ||
                        (
                            d.m60F16WidthQuantizedRenderFixFor431 &&
                                m60F16WidthQuantizedColorReconstructionFor432Requested
                            )
                    )
        val diagnosticEnabled =
            m60F16AaStencilCoverFragmentLaneDiagnosticsEnabled && d.m60F16BandMetadata != null
        val anyDiagnosticEnabled =
            shaderReturnDiagnosticForDraw ||
                contributionIsolationDiagnosticForDraw ||
                diagnosticEnabled ||
                (applicationPointDiagnosticForDraw && d.m60F16BandMetadata != null) ||
                (coverageStencilContributionMapDiagnosticForDraw && d.m60F16BandMetadata != null)
        val diagnosticBufferSize = when {
            shaderReturnDiagnosticForDraw && m60F16RuntimeExactMaskProbeFor442DiagnosticsEnabled ->
                M60_F16_SUBSAMPLE_MASK_FOR427_BUFFER_SIZE
            shaderReturnDiagnosticForDraw || contributionIsolationDiagnosticForDraw ->
