        const val CONICAL_GRADIENT_UNIFORM_SIZE: ULong = 688uL
        /**
         * G4.4.1 / G2.x -- size of the conical focal-inside per-draw uniform :
         *   viewport (16) + affineRow0 (16) + affineRow1 (16) +
         *   focalScalars (16) + flagsCount (16) +
