            floatArrayOf(1f, 1f, 0f, 0f, 0f, 0f, 0f)
        /**
         * G5.3.y -- peak luminance constant (nits) used by the PQ /
         * HLG shader branches (`csMode == 3` / `csMode == 4`) to tone-
